# ============================================================================
# PUBLICATION EXPORT MIXIN CLASS
# ============================================================================

class PublicationExportMixin:
    '''
    Mixin class that adds publication-ready export functionality to plotting methods.
    Can be used with any plotter class that creates matplotlib figures.
    '''
    
    def export_current_figure(self, base_filename='figure', 
                              export_formats=None,
                              **format_overrides):
        '''
        Export the currently active matplotlib figure in multiple publication-ready formats
        
        Parameters
        ----------
        base_filename : str
            Base name for output files (default: 'figure')
        export_formats : list
            Formats to export. Options: 'word', 'presentation', 'journal', 'poster', 'supplementary'
            If None, exports 'word' and 'journal' formats
        **format_overrides : dict
            Override any format-specific parameters (e.g., dpi=600, figsize=(10,7))
            
        Returns
        -------
        list
            List of exported filenames
            
        Examples
        --------
        >>> # After creating a plot
        >>> plotter.plot_density_profiles()
        >>> plotter.export_current_figure('density', export_formats=['word', 'journal'])
        '''
        
        if export_formats is None:
            export_formats = ['word', 'journal']
        
        format_specs = {
            'word': {
                'dpi': 300,
                'description': 'Word Document (A4/Letter page)',
                'extension': 'png'
            },
            'presentation': {
                'dpi': 150,
                'description': 'Presentation (PowerPoint/Keynote)',
                'extension': 'png'
            },
            'journal': {
                'dpi': 600,
                'description': 'High-Resolution Journal Submission',
                'extension': 'png'
            },
            'journal_tiff': {
                'dpi': 600,
                'description': 'High-Resolution Journal (TIFF format)',
                'extension': 'tiff'
            },
            'poster': {
                'dpi': 300,
                'description': 'Conference Poster (Large Format)',
                'extension': 'png'
            },
            'supplementary': {
                'dpi': 300,
                'description': 'Supplementary Information (Compact)',
                'extension': 'png'
            }
        }
        
        # Add journal_tiff if journal is requested
        if 'journal' in export_formats and 'journal_tiff' not in export_formats:
            export_formats = list(export_formats) + ['journal_tiff']
        
        exported_files = []
        
        print(f"\n{'='*70}")
        print(f"EXPORTING CURRENT FIGURE: {base_filename}")
        print(f"{'='*70}")
        
        for format_name in export_formats:
            if format_name not in format_specs:
                print(f"\n⚠ Warning: Unknown format '{format_name}'. Skipping...")
                continue
            
            specs = format_specs[format_name].copy()
            
            # Apply user overrides
            specs.update(format_overrides)
            
            filename = f"{base_filename}_{format_name}.{specs['extension']}"
            
            print(f"\n📊 Exporting: {specs['description']}")
            print(f"   Format: {format_name}")
            print(f"   DPI: {specs['dpi']}")
            print(f"   File: {filename}")
            
            try:
                plt.savefig(filename, dpi=specs['dpi'], bbox_inches='tight', 
                           facecolor='white', edgecolor='none')
                
                exported_files.append(filename)
                print(f"   ✓ Successfully exported: {filename}")
                
                # Print file size
                import os
                if os.path.exists(filename):
                    file_size = os.path.getsize(filename) / 1024  # KB
                    if file_size > 1024:
                        print(f"   File size: {file_size/1024:.2f} MB")
                    else:
                        print(f"   File size: {file_size:.2f} KB")
            
            except Exception as e:
                print(f"   ✗ Error exporting {format_name}: {e}")
        
        print(f"\n{'='*70}")
        print(f"EXPORT COMPLETE: {len(exported_files)} file(s) created")
        print(f"{'='*70}\n")
        
        return exported_files
    
    
    def publication_export_decorator(self, base_filename='auto', 
                                     export_formats=None,
                                     auto_export=True):
        '''
        Decorator factory that automatically exports plots after creation
        
        Parameters
        ----------
        base_filename : str
            Base filename for exports. 'auto' uses the method name.
        export_formats : list
            Formats to export. If None, uses ['word', 'journal']
        auto_export : bool
            Whether to automatically export. Can be overridden by save_plots parameter.
            
        Examples
        --------
        >>> @plotter.publication_export_decorator(export_formats=['word', 'presentation'])
        >>> def my_plot_function(self):
        >>>     plt.plot([1,2,3], [1,2,3])
        >>>     plt.show()
        '''
        
        def decorator(plot_func):
            @functools.wraps(plot_func)
            def wrapper(*args, **kwargs):
                # Call original plotting function
                result = plot_func(*args, **kwargs)
                
                # Determine if we should export
                should_export = kwargs.get('save_plots', auto_export)
                
                if should_export:
                    # Determine filename
                    if base_filename == 'auto':
                        filename = kwargs.get('filename', plot_func.__name__.replace('plot_', ''))
                        # Remove common extensions if present
                        filename = filename.replace('.png', '').replace('.pdf', '')
                    else:
                        filename = kwargs.get('filename', base_filename)
                    
                    # Export current figure
                    formats = export_formats or ['word', 'journal']
                    self.export_current_figure(filename, export_formats=formats)
                
                return result
            
            return wrapper
        
        return decorator


class ZDirectionalPlotter(PublicationExportMixin):
    '''
    Plotting class for ZDirectionalAnalysis results.
    Includes publication-ready export functionality via PublicationExportMixin.
    '''
    
    def __init__(self, z_analysis=None):
        '''
        Initialize plotter with analysis results.
        
        Parameters
        ----------
        z_analysis : ZDirectionalAnalysis
            The analysis object containing results to plot
        '''
        self.analysis = z_analysis
        
        # Default plotting parameters
        self.default_figsize = (12, 8)
        self.default_dpi = 300
        self.default_colors = ['red', 'blue', 'green', 'orange', 'purple', 'brown', 'pink', 'gray']
      
    
    def set_analysis(self, z_analysis):
        '''Set or update the analysis object'''
        self.analysis = z_analysis
    
    def _validate_analysis(self):
        '''Check if analysis object is set and has results'''
        if self.analysis is None:
            raise ValueError("No analysis object set. Use set_analysis() or provide z_analysis in __init__")
        if not hasattr(self.analysis, 'results'):
            raise ValueError("Analysis object has no results. Run analysis first.")
    
    def plot_density_profiles(self, ion_types=None, save_plots=True, figsize=None,
                             show_counts=True, show_density=True, filename=None):
        '''Plot density profiles and count profiles vs z-position'''
        
        self._validate_analysis()
        
        if not show_counts and not show_density:
            print("Error: At least one of show_counts or show_density must be True")
            return
        
        figsize = figsize or self.default_figsize
        
        # Determine number of subplots needed
        n_plots = 0
        if show_density:
            n_plots += 1
        if show_counts:
            n_plots += 1
        
        fig, axes = plt.subplots(n_plots, 2, figsize=(figsize[0], figsize[1] * n_plots / 2))
        if n_plots == 1:
            axes = axes.reshape(1, -1)
        
        plot_idx = 0
        
        # DENSITY PROFILES
        if show_density:
            # Plot 1: All species density profiles
            ax1 = axes[plot_idx, 0]
            
            ax1.plot(self.analysis.z_centers, self.analysis.results.water_density, 'b-', linewidth=2, label='Water')
            ax1.plot(self.analysis.z_centers, self.analysis.results.cation_density, 'r-', linewidth=2, label='Cations')
            ax1.plot(self.analysis.z_centers, self.analysis.results.anion_density, 'g-', linewidth=2, label='Anions')
            
            ax1.set_xlabel('z (Å)')
            ax1.set_ylabel('Number Density (molecules/Å³)')
            ax1.set_title('Density Profiles vs Z-Position', fontweight='bold')
            ax1.legend()
            ax1.grid(True, alpha=0.3)
            ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Plot 2: Ion-specific density profiles
            ax2 = axes[plot_idx, 1]
            
            color_idx = 0
            for ion_type, density in self.analysis.results.ion_densities_by_type.items():
                if ion_types is None or ion_type in ion_types:
                    color = self.default_colors[color_idx % len(self.default_colors)]
                    linestyle = '-' if ion_type in self.analysis.cation_types else '--'
                    ax2.plot(self.analysis.z_centers, density, color=color, linewidth=2, 
                            label=f'{ion_type}', linestyle=linestyle)
                    color_idx += 1
            
            ax2.set_xlabel('z (Å)')
            ax2.set_ylabel('Number Density (ions/Å³)')
            ax2.set_title('Ion-Specific Density Profiles', fontweight='bold')
            ax2.legend()
            ax2.grid(True, alpha=0.3)
            ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            plot_idx += 1
        
        # COUNT PROFILES
        if show_counts:
            # Plot 3: All species count profiles
            ax3 = axes[plot_idx, 0]
            
            ax3.plot(self.analysis.z_centers, self.analysis.results.water_counts, 'b-', linewidth=2, label='Water')
            ax3.plot(self.analysis.z_centers, self.analysis.results.cation_counts, 'r-', linewidth=2, label='Cations')
            ax3.plot(self.analysis.z_centers, self.analysis.results.anion_counts, 'g-', linewidth=2, label='Anions')
            
            ax3.set_xlabel('z (Å)')
            ax3.set_ylabel('Average Count per Frame')
            ax3.set_title('Count Profiles vs Z-Position', fontweight='bold')
            ax3.legend()
            ax3.grid(True, alpha=0.3)
            ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Plot 4: Ion-specific count profiles
            ax4 = axes[plot_idx, 1]
            
            color_idx = 0
            for ion_type, counts in self.analysis.results.ion_counts_by_type.items():
                if ion_types is None or ion_type in ion_types:
                    color = self.default_colors[color_idx % len(self.default_colors)]
                    linestyle = '-' if ion_type in self.analysis.cation_types else '--'
                    ax4.plot(self.analysis.z_centers, counts, color=color, linewidth=2, 
                            label=f'{ion_type}', linestyle=linestyle)
                    color_idx += 1
            
            ax4.set_xlabel('z (Å)')
            ax4.set_ylabel('Average Count per Frame')
            ax4.set_title('Ion-Specific Count Profiles', fontweight='bold')
            ax4.legend()
            ax4.grid(True, alpha=0.3)
            ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'z_density_and_count_profiles.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Density and count profiles plot saved as: {filename}")
        
        plt.show()
        
        # Print summary statistics
        print(f"\nDensity Profile Summary:")
        print(f"  Water density range: {np.min(self.analysis.results.water_density):.3f} - {np.max(self.analysis.results.water_density):.3f} molecules/Å³")
        print(f"  Water count range: {np.min(self.analysis.results.water_counts):.1f} - {np.max(self.analysis.results.water_counts):.1f} molecules/bin")
        print(f"  Total analyzed frames: {self.analysis.n_frames_analyzed}")

    def plot_clay_interface_boundaries(self, save_plots=True, figsize=None, 
                                    filename='clay_interface_boundaries.png',
                                    show_density_overlay=True,
                                    dpi=300,
                                    title_fontsize=16,
                                    title_text=None,
                                    show_title=True,
                                    label_fontsize=14,
                                    tick_fontsize=12,
                                    legend_fontsize=12,
                                    show_legend=True,
                                    show_grid=True,
                                    grid_alpha=0.3,
                                    upper_clay_avg_color='red',
                                    upper_si_color='orange',
                                    upper_mgo_color='darkred',
                                    lower_clay_avg_color='blue',
                                    lower_si_color='cyan',
                                    lower_mgo_color='darkblue',
                                    upper_clay_avg_linestyle='-',
                                    upper_si_linestyle='--',
                                    upper_mgo_linestyle=':',
                                    lower_clay_avg_linestyle='-',
                                    lower_si_linestyle='--',
                                    lower_mgo_linestyle=':',
                                    boundary_linewidth=2.5,
                                    boundary_alpha=0.8,
                                    show_boundary_lines=True,  # ✅ NEW PARAMETER
                                    water_density_color='blue',
                                    ion_density_color='red',
                                    ion_density_colors=None,
                                    water_linewidth=2,
                                    ion_linewidth=2,
                                    density_overlay_alpha=0.7,
                                    fill_clay_region=True,
                                    clay_fill_alpha=0.1,
                                    clay_fill_color='gray',
                                    fill_density_curves=True,
                                    water_fill_alpha=0.2,
                                    ion_fill_alpha=0.15,
                                    water_fill_color=None,
                                    ion_fill_colors=None,
                                    show_zero_line=True,
                                    zero_line_color='black',
                                    zero_line_style=':',
                                    zero_line_alpha=0.5,
                                    zero_line_width=1.0,
                                    legend_location='upper left',
                                    legend_ncol=2,
                                    legend_frameon=True,
                                    legend_framealpha=0.8,
                                    xlabel_text='z (Å)',
                                    ylabel_text='Water Density (molecules/Å³)',
                                    ylabel_ion_text='Ion Density (ions/Å³)',
                                    show_boundary_values=True,
                                    symmetrize_densities=False,
                                    symmetrize_boundaries=False,
                                    symmetrize_method='average',
                                    show_asymmetry_std=False,
                                    symmetry_center=0.0,
                                    print_summary=True):
        '''
        Plot clay atom positions (Mg/Mgo and Si) and interface boundaries
        
        Parameters
        ----------
        ion_density_colors : dict, optional
        Dictionary mapping ion types to specific colors.
        Example: {'CL': 'red', 'NA': 'black', 'MG': 'blue'}
        If None, uses automatic color cycling.
        If a dict is provided but an ion type is missing, uses default colors.

        show_boundary_lines : bool, default=True
        Whether to show the vertical boundary lines (Si, Mgo, clay average).
        If False, only the filled clay regions will be shown.
        Useful when you want to keep the shaded regions but hide the lines.

        save_plots : bool
            Whether to save the plot
        figsize : tuple
            Figure size (width, height) in inches (default: (10, 7))
        filename : str
            Output filename
        show_density_overlay : bool
            Whether to overlay water density profile for context
        dpi : int
            Resolution for saved figure (default: 300)
        title_fontsize : int
            Font size for plot title (default: 16)
        label_fontsize : int
            Font size for axis labels (default: 14)
        tick_fontsize : int
            Font size for axis tick labels (default: 12)
        legend_fontsize : int
            Font size for legend text (default: 12)
        show_legend : bool
            Whether to show legend (default: True)
        show_grid : bool
            Whether to show grid lines (default: True)
        grid_alpha : float
            Transparency of grid lines (0-1, default: 0.3)
        upper_clay_avg_color : str
            Color for upper clay average boundary (default: 'red')
        upper_si_color : str
            Color for upper Si boundary (default: 'orange')
        upper_mgo_color : str
            Color for upper Mg/Mgo boundary (default: 'darkred')
        lower_clay_avg_color : str
            Color for lower clay average boundary (default: 'blue')
        lower_si_color : str
            Color for lower Si boundary (default: 'cyan')
        lower_mgo_color : str
            Color for lower Mg/Mgo boundary (default: 'darkblue')
        upper_clay_avg_linestyle : str
            Line style for upper clay average (default: '-')
        upper_si_linestyle : str
            Line style for upper Si (default: '--')
        upper_mgo_linestyle : str
            Line style for upper Mg/Mgo (default: ':')
        lower_clay_avg_linestyle : str
            Line style for lower clay average (default: '-')
        lower_si_linestyle : str
            Line style for lower Si (default: '--')
        lower_mgo_linestyle : str
            Line style for lower Mg/Mgo (default: ':')
        boundary_linewidth : float
            Width of boundary lines (default: 2.5)
        boundary_alpha : float
            Transparency of boundary lines (0-1, default: 0.8)
        water_density_color : str
            Color for water density curve (default: 'blue')
        ion_density_color : str
            Color for ion density curves (default: 'red')
        water_linewidth : float
            Width of water density line (default: 2)
        ion_linewidth : float
            Width of ion density lines (default: 2)
        density_overlay_alpha : float
            Transparency of density curves (0-1, default: 0.7)
        fill_clay_region : bool
            Whether to fill clay regions with color (default: True)
        clay_fill_alpha : float
            Transparency of clay region fill (0-1, default: 0.1)
        clay_fill_color : str
            Color for clay region fill (default: 'gray')
        fill_density_curves : bool
            Whether to fill area under density curves (default: True)
        water_fill_alpha : float
            Transparency of water density fill (0-1, default: 0.2)
        ion_fill_alpha : float
            Transparency of ion density fills (0-1, default: 0.15)
        water_fill_color : str, optional
            Color for water density fill. If None, uses water_density_color
        ion_fill_colors : dict, optional
            Dictionary mapping ion types to fill colors. If None, uses line colors
        show_zero_line : bool
            Whether to show z=0 reference line (default: True)
        zero_line_color : str
            Color of z=0 line (default: 'black')
        zero_line_style : str
            Line style for z=0 line (default: ':')
        zero_line_alpha : float
            Transparency of z=0 line (0-1, default: 0.5)
        zero_line_width : float
            Width of z=0 line (default: 1.0)
        legend_location : str
            Legend location (default: 'upper left')
        legend_ncol : int
            Number of columns in legend (default: 2)
        legend_frameon : bool
            Whether to show legend frame (default: True)
        legend_framealpha : float
            Transparency of legend frame (0-1, default: 0.8)
        title_text : str, optional
            Custom title text (default: auto-generated)
        xlabel_text : str
            X-axis label text (default: 'z (Å)')
        ylabel_text : str
            Y-axis label text (default: 'Water Density (molecules/Å³)')
        ylabel_ion_text : str
            Y-axis label for ion density (default: 'Ion Density (ions/Å³)')
        show_boundary_values : bool
            Whether to show boundary values in legend labels (default: True)
        print_summary : bool
            Whether to print boundary position summary (default: True)
        symmetrize_densities : bool, default=False
            If True, symmetrize density profiles
        symmetrize_boundaries : bool, default=False
            If True, symmetrize clay boundary positions
        symmetrize_method : str, default='average'
            Method for symmetrization:
            - 'average': Average positive and negative sides
            - 'fold': Use positive side only, fold to negative
            - 'mirror_positive': Use positive side, mirror to negative
            - 'mirror_negative': Use negative side, mirror to positive
        show_asymmetry_std : bool, default=False
            If True, show standard deviation between sides as error bars/shading
        symmetry_center : float, default=0.0
            Center point for symmetrization        
        '''
        
        print("Plotting clay interface boundaries...")

        if not hasattr(self.analysis.results, 'clay_interface_boundaries'):
            print("No clay interface data available. Running calculation...")
            try:
                self.analysis.calculate_clay_interface_boundaries()
            except Exception as e:
                print(f"Error calculating clay interface boundaries: {e}")
                return
        
        clay_data = self.analysis.results.clay_interface_boundaries
        
        if clay_data is None:
            print("Clay interface calculation returned None.")
            return
        
        # Helper function to symmetrize 1D data
        def _symmetrize_data(z_centers, data, method='average'):
            """Symmetrize 1D data array."""
            positive_mask = z_centers >= symmetry_center
            negative_mask = z_centers < symmetry_center
            
            if method == 'average':
                from scipy.interpolate import interp1d
                
                positive_z = z_centers[positive_mask]
                positive_data = data[positive_mask]
                negative_z = np.abs(z_centers[negative_mask])
                negative_data = data[negative_mask]
                
                common_z = positive_z
                if len(negative_z) > 0 and len(positive_z) > 0:
                    f_neg = interp1d(negative_z, negative_data, kind='linear', 
                                    bounds_error=False, fill_value=np.nan)
                    negative_interp = f_neg(common_z)
                    
                    averaged = np.where(~np.isnan(negative_interp),
                                    (positive_data + negative_interp) / 2,
                                    positive_data)
                    
                    std_dev = np.where(~np.isnan(negative_interp),
                                    np.abs(positive_data - negative_interp) / 2,
                                    np.zeros_like(positive_data))
                    
                    sym_z = np.concatenate([-common_z[::-1], common_z])
                    sym_data = np.concatenate([averaged[::-1], averaged])
                    sym_std = np.concatenate([std_dev[::-1], std_dev]) if show_asymmetry_std else None
                    
                    return sym_z, sym_data, sym_std
                else:
                    return z_centers, data, None
                    
            elif method == 'fold':
                positive_z = z_centers[positive_mask]
                positive_data = data[positive_mask]
                return positive_z, positive_data, None
                
            elif method == 'mirror_positive':
                positive_z = z_centers[positive_mask]
                positive_data = data[positive_mask]
                sym_z = np.concatenate([-positive_z[::-1], positive_z])
                sym_data = np.concatenate([positive_data[::-1], positive_data])
                return sym_z, sym_data, None
                
            elif method == 'mirror_negative':
                negative_z = z_centers[negative_mask]
                negative_data = data[negative_mask]
                sym_z = np.concatenate([negative_z, -negative_z[::-1]])
                sym_data = np.concatenate([negative_data, negative_data[::-1]])
                return sym_z, sym_data, None
            
            return z_centers, data, None
        
        # Symmetrize densities if requested
        z_centers = self.analysis.z_centers.copy()
        water_density = self.analysis.results.water_density.copy()
        
        water_std = None
        ion_densities = {}
        ion_stds = {}
        
        if symmetrize_densities:
            z_centers, water_density, water_std = _symmetrize_data(
                self.analysis.z_centers, self.analysis.results.water_density, symmetrize_method)
            
            for ion_type, density in self.analysis.results.ion_densities_by_type.items():
                _, ion_densities[ion_type], ion_stds[ion_type] = _symmetrize_data(
                    self.analysis.z_centers, density, symmetrize_method)
        else:
            for ion_type, density in self.analysis.results.ion_densities_by_type.items():
                ion_densities[ion_type] = density.copy()
                ion_stds[ion_type] = None
        
        # Symmetrize boundaries if requested - WITH PERIODIC BOUNDARY CORRECTION FOR MG
        sym_boundaries = None
        if symmetrize_boundaries:
            upper_clay_avg = clay_data['clay_average_z_positive']
            lower_clay_avg = clay_data['clay_average_z_negative']
            
            # Handle None values for clay boundaries
            if upper_clay_avg is not None and lower_clay_avg is not None:
                clay_avg = (abs(upper_clay_avg) + abs(lower_clay_avg)) / 2
                clay_std = abs(abs(upper_clay_avg) - abs(lower_clay_avg)) / 2
            elif upper_clay_avg is not None:
                clay_avg = abs(upper_clay_avg)
                clay_std = 0.0
            elif lower_clay_avg is not None:
                clay_avg = abs(lower_clay_avg)
                clay_std = 0.0
            else:
                clay_avg = None
                clay_std = 0.0
            
            # Handle Si boundaries
            upper_si = clay_data['si_average_z_positive']
            lower_si = clay_data['si_average_z_negative']
            
            if upper_si is not None and lower_si is not None:
                si_avg = (abs(upper_si) + abs(lower_si)) / 2
                si_std = abs(abs(upper_si) - abs(lower_si)) / 2
            elif upper_si is not None:
                si_avg = abs(upper_si)
                si_std = 0.0
            elif lower_si is not None:
                si_avg = abs(lower_si)
                si_std = 0.0
            else:
                si_avg = None
                si_std = 0.0
            
            # Handle Mg boundaries - WITH PERIODIC BOUNDARY CORRECTION
            upper_mgo = clay_data['mgo_average_z_positive']
            lower_mgo = clay_data['mgo_average_z_negative']
            
            # Apply periodic boundary correction for Mg atoms only
            if upper_mgo is None and lower_mgo is not None:
                upper_mgo = -lower_mgo  # Use opposite sign
            elif lower_mgo is None and upper_mgo is not None:
                lower_mgo = -upper_mgo  # Use opposite sign
            
            if upper_mgo is not None and lower_mgo is not None:
                mgo_avg = (abs(upper_mgo) + abs(lower_mgo)) / 2
                mgo_std = abs(abs(upper_mgo) - abs(lower_mgo)) / 2
            elif upper_mgo is not None:
                mgo_avg = abs(upper_mgo)
                mgo_std = 0.0
            elif lower_mgo is not None:
                mgo_avg = abs(lower_mgo)
                mgo_std = 0.0
            else:
                mgo_avg = None
                mgo_std = 0.0
            
            sym_boundaries = {
                'clay_avg': clay_avg,
                'si_avg': si_avg,
                'mgo_avg': mgo_avg,
                'clay_std': clay_std,
                'si_std': si_std,
                'mgo_std': mgo_std
            }
        
        # Create figure
        figsize = figsize or (10, 7)
        fig, ax1 = plt.subplots(figsize=figsize)
        
        # Determine fill color for water
        water_fill_col = water_fill_color if water_fill_color is not None else water_density_color
        
        # Plot water density
        ax1.plot(z_centers, water_density, color=water_density_color, 
                linewidth=water_linewidth, alpha=density_overlay_alpha, label='Water density')
        
        if fill_density_curves:
            ax1.fill_between(z_centers, 0, water_density, 
                            color=water_fill_col, alpha=water_fill_alpha, 
                            zorder=0, linewidth=0)
        
        if show_asymmetry_std and water_std is not None:
            ax1.fill_between(z_centers, water_density - water_std, 
                            water_density + water_std,
                            alpha=0.2, color=water_density_color)
        
        ax1.set_ylabel(ylabel_text, color=water_density_color, fontsize=label_fontsize)
        ax1.tick_params(axis='y', labelcolor=water_density_color, labelsize=tick_fontsize)
        ax1.tick_params(axis='x', labelsize=tick_fontsize)
        
        # Add ion densities with custom colors
        if hasattr(self.analysis.results, 'ion_densities_by_type'):
            ax2 = ax1.twinx()
            
            unmapped_ions = []
            
            for ion_idx, ion_type in enumerate(ion_densities.keys()):
                density = ion_densities[ion_type]
                
                if ion_density_colors is not None and ion_type in ion_density_colors:
                    line_color = ion_density_colors[ion_type]
                else:
                    line_color = self.default_colors[ion_idx % len(self.default_colors)]
                    if ion_density_colors is not None:
                        unmapped_ions.append(ion_type)
                
                line = ax2.plot(z_centers, density, color=line_color, linewidth=ion_linewidth, 
                            alpha=density_overlay_alpha, label=ion_type)
                
                if fill_density_curves:
                    if ion_fill_colors is not None and ion_type in ion_fill_colors:
                        fill_col = ion_fill_colors[ion_type]
                    else:
                        fill_col = line_color
                    
                    ax2.fill_between(z_centers, 0, density,
                                    color=fill_col, alpha=ion_fill_alpha,
                                    zorder=0, linewidth=0)
                
                if show_asymmetry_std and ion_stds[ion_type] is not None:
                    ax2.fill_between(z_centers, density - ion_stds[ion_type],
                                    density + ion_stds[ion_type],
                                    alpha=0.15, color=line_color)
            
            if unmapped_ions:
                print(f"⚠ Warning: Ion types not in ion_density_colors dict: {unmapped_ions}")
                print(f"   Using default colors for these ions.")
            
            ax2.set_ylabel(ylabel_ion_text, color=ion_density_color, fontsize=label_fontsize)
            ax2.tick_params(axis='y', labelcolor=ion_density_color, labelsize=tick_fontsize)
            
            if show_legend:
                ax2.legend(loc='upper right', fontsize=legend_fontsize, frameon=legend_frameon, 
                        framealpha=legend_framealpha)
        
        # ✅ Plot boundaries only if show_boundary_lines=True
        if symmetrize_boundaries and sym_boundaries is not None:
            if show_boundary_lines:
                # Clay average lines
                if sym_boundaries['clay_avg'] is not None:
                    ax1.axvline(sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, label=f'Clay Avg ({sym_boundaries["clay_avg"]:.2f} Å)')
                    ax1.axvline(-sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha)
                
                # Si layer lines
                if sym_boundaries['si_avg'] is not None:
                    ax1.axvline(sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, label=f'Si Layer ({sym_boundaries["si_avg"]:.2f} Å)')
                    ax1.axvline(-sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha)
                
                # Mgo layer lines
                if sym_boundaries['mgo_avg'] is not None:
                    ax1.axvline(sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, label=f'Mg/Mgo Layer ({sym_boundaries["mgo_avg"]:.2f} Å)')
                    ax1.axvline(-sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha)
            
            # ✅ Show asymmetry shading if requested (independent of show_boundary_lines)
            if show_asymmetry_std:
                if sym_boundaries['clay_avg'] is not None:
                    ax1.axvspan(sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                            sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                            alpha=0.1, color=upper_clay_avg_color)
                    ax1.axvspan(-sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                            -sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                            alpha=0.1, color=upper_clay_avg_color)
                
                if sym_boundaries['si_avg'] is not None:
                    ax1.axvspan(sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                            sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                            alpha=0.1, color=upper_si_color)
                    ax1.axvspan(-sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                            -sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                            alpha=0.1, color=upper_si_color)
                
                if sym_boundaries['mgo_avg'] is not None:
                    ax1.axvspan(sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                            sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                            alpha=0.1, color=upper_mgo_color)
                    ax1.axvspan(-sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                            -sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                            alpha=0.1, color=upper_mgo_color)
            
            # ✅ Fill clay regions (always shown if fill_clay_region=True)
            if fill_clay_region:
                if sym_boundaries['si_avg'] is not None and sym_boundaries['mgo_avg'] is not None:
                    ax1.axvspan(sym_boundaries['si_avg'], sym_boundaries['mgo_avg'], 
                            alpha=clay_fill_alpha, color=clay_fill_color, zorder=0)
                    ax1.axvspan(-sym_boundaries['mgo_avg'], -sym_boundaries['si_avg'], 
                            alpha=clay_fill_alpha, color=clay_fill_color, zorder=0)
        
        else:
            # ✅ Original boundaries - only show lines if show_boundary_lines=True
            if show_boundary_lines:
                if clay_data['clay_average_z_positive'] is not None:
                    ax1.axvline(clay_data['clay_average_z_positive'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Upper Clay Avg ({clay_data["clay_average_z_positive"]:.2f} Å)')
                
                if clay_data['si_average_z_positive'] is not None:
                    ax1.axvline(clay_data['si_average_z_positive'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Upper Si ({clay_data["si_average_z_positive"]:.2f} Å)')
                
                if clay_data['mgo_average_z_positive'] is not None:
                    ax1.axvline(clay_data['mgo_average_z_positive'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Upper Mg/Mgo ({clay_data["mgo_average_z_positive"]:.2f} Å)')
                
                if clay_data['clay_average_z_negative'] is not None:
                    ax1.axvline(clay_data['clay_average_z_negative'], color=lower_clay_avg_color, 
                            linestyle=lower_clay_avg_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Lower Clay Avg ({clay_data["clay_average_z_negative"]:.2f} Å)')
                
                if clay_data['si_average_z_negative'] is not None:
                    ax1.axvline(clay_data['si_average_z_negative'], color=lower_si_color, 
                            linestyle=lower_si_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Lower Si ({clay_data["si_average_z_negative"]:.2f} Å)')
                
                if clay_data['mgo_average_z_negative'] is not None:
                    ax1.axvline(clay_data['mgo_average_z_negative'], color=lower_mgo_color, 
                            linestyle=lower_mgo_linestyle, linewidth=boundary_linewidth, 
                            alpha=boundary_alpha, 
                            label=f'Lower Mg/Mgo ({clay_data["mgo_average_z_negative"]:.2f} Å)')
            
            # ✅ Fill clay regions (always shown if fill_clay_region=True)
            if fill_clay_region:
                # Apply periodic boundary correction for clay region filling
                upper_si = clay_data['si_average_z_positive']
                upper_mgo = clay_data['mgo_average_z_positive']
                lower_si = clay_data['si_average_z_negative']
                lower_mgo = clay_data['mgo_average_z_negative']
                
                # Apply periodic boundary correction for missing Mg boundaries
                if upper_mgo is None and lower_mgo is not None:
                    upper_mgo = -lower_mgo
                elif lower_mgo is None and upper_mgo is not None:
                    lower_mgo = -upper_mgo
                
                if upper_si is not None and upper_mgo is not None:
                    ax1.axvspan(upper_si, upper_mgo, alpha=clay_fill_alpha, 
                            color=clay_fill_color, zorder=0)
                if lower_si is not None and lower_mgo is not None:
                    ax1.axvspan(lower_mgo, lower_si, alpha=clay_fill_alpha, 
                            color=clay_fill_color, zorder=0)
        
        # Reference line at z=0
        if show_zero_line:
            ax1.axvline(0, color=zero_line_color, linestyle=zero_line_style, 
                    linewidth=zero_line_width, alpha=zero_line_alpha)
        
        # Formatting
        ax1.set_xlabel(xlabel_text, fontsize=label_fontsize)
        
        if show_title:
            if title_text is None:
                title_text = 'Density Profiles with Clay Interfaces'
                if symmetrize_densities or symmetrize_boundaries:
                    title_text += f' (Symmetrized: {symmetrize_method})'
            ax1.set_title(title_text, fontsize=title_fontsize, fontweight='bold')
        
        if show_legend:
            ax1.legend(loc=legend_location, fontsize=legend_fontsize, ncol=legend_ncol,
                    frameon=legend_frameon, framealpha=legend_framealpha)
        
        if show_grid:
            ax1.grid(True, alpha=grid_alpha)
        
        plt.tight_layout()
        
        # Print summary
        if print_summary:
            print("\n=== Clay Interface Boundaries ===")
            
            if not show_boundary_lines:
                print("\n⚠ Note: Boundary lines are HIDDEN (show_boundary_lines=False)")
                print("  Only filled clay regions are visible")
            
            if ion_density_colors is not None:
                print("\nIon color mapping:")
                for ion_type in ion_densities.keys():
                    if ion_type in ion_density_colors:
                        print(f"  {ion_type}: {ion_density_colors[ion_type]}")
                    else:
                        print(f"  {ion_type}: (default color)")
            
            if symmetrize_boundaries and sym_boundaries is not None:
                print(f"\nSymmetrized boundaries (method: {symmetrize_method}):")
                if sym_boundaries['clay_avg'] is not None:
                    print(f"  Clay average: {sym_boundaries['clay_avg']:.2f} Å (± {sym_boundaries['clay_std']:.2f} Å)")
                if sym_boundaries['si_avg'] is not None:
                    print(f"  Si layer:     {sym_boundaries['si_avg']:.2f} Å (± {sym_boundaries['si_std']:.2f} Å)")
                if sym_boundaries['mgo_avg'] is not None:
                    print(f"  Mg/Mgo layer: {sym_boundaries['mgo_avg']:.2f} Å (± {sym_boundaries['mgo_std']:.2f} Å)")
            else:
                print("\nUpper region:")
                if clay_data['clay_average_z_positive'] is not None:
                    print(f"  Overall average: {clay_data['clay_average_z_positive']:.2f} Å")
                if clay_data['si_average_z_positive'] is not None:
                    print(f"  Si layer:        {clay_data['si_average_z_positive']:.2f} Å")
                if clay_data['mgo_average_z_positive'] is not None:
                    print(f"  Mg/Mgo layer:    {clay_data['mgo_average_z_positive']:.2f} Å")
                
                print("\nLower region:")
                if clay_data['clay_average_z_negative'] is not None:
                    print(f"  Overall average: {clay_data['clay_average_z_negative']:.2f} Å")
                if clay_data['si_average_z_negative'] is not None:
                    print(f"  Si layer:        {clay_data['si_average_z_negative']:.2f} Å")
                if clay_data['mgo_average_z_negative'] is not None:
                    print(f"  Mg/Mgo layer:    {clay_data['mgo_average_z_negative']:.2f} Å")
        
        if save_plots:
            suffix = f"_sym_{symmetrize_method}" if (symmetrize_densities or symmetrize_boundaries) else ""
            suffix += "_no_lines" if not show_boundary_lines else ""
            final_filename = filename.replace('.png', f'{suffix}.png')
            plt.savefig(final_filename, dpi=dpi, bbox_inches='tight')
            print(f"✓ Clay interface boundaries plot saved as: {final_filename} (dpi={dpi})")
        
        plt.show()
        return fig, (ax1, ax2 if hasattr(self.analysis.results, 'ion_densities_by_type') else None)


