    def plot_coordination_vs_z(self, ion_types=None, bin_size=2.0, save_plots=True, 
                              figsize=None, filename=None):
        '''Plot coordination numbers vs z-position'''
        
        self._validate_analysis()
        
        if not self.analysis.results.coordination_vs_z:
            print("No coordination data available. Run analysis first.")
            return
        
        figsize = figsize or self.default_figsize
        fig, axes = plt.subplots(1, 2, figsize=figsize)
        
        color_idx = 0
        
        # Plot 1: Raw coordination data (scatter)
        ax1 = axes[0]
        
        for ion_type, data in self.analysis.results.coordination_vs_z.items():
            if (ion_types is None or ion_type in ion_types) and data['z_positions']:
                color = self.default_colors[color_idx % len(self.default_colors)]
                ax1.scatter(data['z_positions'], data['coordination_numbers'], 
                           alpha=0.6, s=20, color=color, label=ion_type)
                color_idx += 1
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Coordination Number')
        ax1.set_title('Ion Coordination vs Z-Position (Raw Data)', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Binned coordination data (smooth curves)
        ax2 = axes[1]
        color_idx = 0
        
        for ion_type, data in self.analysis.results.coordination_vs_z.items():
            if (ion_types is None or ion_type in ion_types) and data['z_positions']:
                z_pos = np.array(data['z_positions'])
                coord_nums = np.array(data['coordination_numbers'])
                
                # Bin the data
                z_bins = np.arange(self.analysis.z_min, self.analysis.z_max + bin_size, bin_size)
                z_bin_centers = (z_bins[:-1] + z_bins[1:]) / 2
                
                binned_coord = []
                for i in range(len(z_bins)-1):
                    mask = (z_pos >= z_bins[i]) & (z_pos < z_bins[i+1])
                    if np.any(mask):
                        binned_coord.append(np.mean(coord_nums[mask]))
                    else:
                        binned_coord.append(0)
                
                color = self.default_colors[color_idx % len(self.default_colors)]
                ax2.plot(z_bin_centers, binned_coord, color=color, linewidth=2, 
                        marker='o', markersize=4, label=ion_type)
                color_idx += 1
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Average Coordination Number')
        ax2.set_title(f'Average Ion Coordination vs Z (bin size: {bin_size} Å)', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'coordination_vs_z.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Coordination vs z plot saved as: {filename}")
        
        plt.show()

    def plot_ion_pairing_results(self, save_plots=True, figsize=None, filename=None):
        '''Plot ion pairing analysis results'''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'ion_pairing'):
            print("No ion pairing data available. Run calculate_ion_pairing_vs_z() first.")
            return
        
        pairing_data = self.analysis.results.ion_pairing
        z_centers = pairing_data['z_centers']
        
        # Count number of ion pairs for subplot arrangement
        n_pairs = len(pairing_data['contact_pair_fraction'])
        
        if n_pairs == 0:
            print("No ion pairs found in the analysis.")
            return
        
        figsize = figsize or (15, 12)
        
        # Create subplots
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        # Plot 1: Contact pair fraction vs z
        ax1 = axes[0, 0]
        
        for i, (pair, fractions) in enumerate(pairing_data['contact_pair_fraction'].items()):
            color = self.default_colors[i % len(self.default_colors)]
            ax1.plot(z_centers, fractions, color=color, linewidth=2, 
                    marker='o', markersize=4, label=pair)
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Contact Pair Fraction')
        ax1.set_title('Ion Contact Pair Fraction vs Z-Position', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Average pair distance vs z
        ax2 = axes[0, 1]
        
        for i, (pair, distances) in enumerate(pairing_data['average_pair_distance'].items()):
            color = self.default_colors[i % len(self.default_colors)]
            ax2.plot(z_centers, distances, color=color, linewidth=2, 
                    marker='s', markersize=4, label=pair)
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Average Pair Distance (Å)')
        ax2.set_title('Average Ion Pair Distance vs Z-Position', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Coordination numbers vs z
        ax3 = axes[1, 0]
        
        for i, (pair, coord_nums) in enumerate(pairing_data['coordination_numbers'].items()):
            color = self.default_colors[i % len(self.default_colors)]
            ax3.plot(z_centers, coord_nums, color=color, linewidth=2, 
                    marker='^', markersize=4, label=pair)
        
        ax3.set_xlabel('z (Å)')
        ax3.set_ylabel('Coordination Number')
        ax3.set_title('Ion Pair Coordination Numbers vs Z-Position', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 4: Combined comparison (contact fraction for all pairs)
        ax4 = axes[1, 1]
        
        # Create a heatmap-style plot if multiple pairs exist
        if len(pairing_data['contact_pair_fraction']) > 1:
            pair_names = list(pairing_data['contact_pair_fraction'].keys())
            contact_matrix = np.array([pairing_data['contact_pair_fraction'][pair] 
                                      for pair in pair_names])
            
            im = ax4.imshow(contact_matrix, aspect='auto', cmap='viridis', 
                           extent=[z_centers.min(), z_centers.max(), -0.5, len(pair_names)-0.5])
            ax4.set_xlabel('z (Å)')
            ax4.set_ylabel('Ion Pairs')
            ax4.set_title('Contact Pair Fraction Heatmap', fontweight='bold')
            ax4.set_yticks(range(len(pair_names)))
            ax4.set_yticklabels(pair_names)
            
            # Add colorbar
            cbar = plt.colorbar(im, ax=ax4)
            cbar.set_label('Contact Pair Fraction')
            
            ax4.axvline(0, color='white', linestyle='--', alpha=0.7)
        else:
            # If only one pair, show detailed comparison
            pair_name = list(pairing_data['contact_pair_fraction'].keys())[0]
            
            ax4_twin = ax4.twinx()
            
            line1 = ax4.plot(z_centers, pairing_data['contact_pair_fraction'][pair_name], 
                            'r-', linewidth=2, label='Contact Fraction')
            line2 = ax4_twin.plot(z_centers, pairing_data['average_pair_distance'][pair_name], 
                                 'b-', linewidth=2, label='Avg Distance')
            
            ax4.set_xlabel('z (Å)')
            ax4.set_ylabel('Contact Pair Fraction', color='r')
            ax4_twin.set_ylabel('Average Distance (Å)', color='b')
            ax4.set_title(f'Detailed Analysis: {pair_name}', fontweight='bold')
            ax4.grid(True, alpha=0.3)
            ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Combined legend
            lines = line1 + line2
            labels = [l.get_label() for l in lines]
            ax4.legend(lines, labels, loc='upper right')
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'ion_pairing_vs_z.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Ion pairing plot saved as: {filename}")
        
        plt.show()
        
        # Print summary statistics
        print(f"\nIon Pairing Analysis Summary:")
        for pair, fractions in pairing_data['contact_pair_fraction'].items():
            avg_fraction = np.mean(fractions[fractions > 0]) if np.any(fractions > 0) else 0
            max_fraction = np.max(fractions)
            print(f"  {pair}:")
            print(f"    Average contact fraction: {avg_fraction:.3f}")
            print(f"    Maximum contact fraction: {max_fraction:.3f}")



    def plot_ion_clustering_vs_z(self, save_plots=True, figsize=None, filename=None):
        '''
        Plot ion clustering analysis results from calculate_ion_clustering_vs_z().
        
        This method reads data from self.analysis.results.ion_clustering which is
        populated by calculate_ion_clustering_vs_z() or loaded from cache.
        
        Parameters
        ----------
        save_plots : bool, optional
            If True, save the plot to file. Default is True
        figsize : tuple, optional
            Figure size (width, height) in inches. Default is (15, 10)
        filename : str, optional
            Output filename. Default is 'ion_clustering_vs_z.png'
        
        Returns
        -------
        None
            Displays and optionally saves the plot
        '''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'ion_clustering'):
            print("No ion clustering data available. Run calculate_ion_clustering_vs_z() first.")
            return
        
        clustering_data = self.analysis.results.ion_clustering
        z_centers = clustering_data['z_centers']
        
        figsize = figsize or (15, 10)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        # Plot 1: Average cluster size vs z
        ax1 = axes[0, 0]
        color_idx = 0
        
        for ion_type, cluster_sizes in clustering_data['average_cluster_size'].items():
            color = self.default_colors[color_idx % len(self.default_colors)]
            ax1.plot(z_centers, cluster_sizes, color=color, linewidth=2, 
                    marker='o', markersize=4, label=ion_type)
            color_idx += 1
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Average Cluster Size')
        ax1.set_title('Average Ion Cluster Size vs Z-Position', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Fraction clustered vs z
        ax2 = axes[0, 1]
        color_idx = 0
        
        for ion_type, fractions in clustering_data['fraction_clustered'].items():
            color = self.default_colors[color_idx % len(self.default_colors)]
            ax2.plot(z_centers, fractions, color=color, linewidth=2, 
                    marker='s', markersize=4, label=ion_type)
            color_idx += 1
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Fraction in Clusters')
        ax2.set_title('Fraction of Ions in Clusters vs Z-Position', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Cluster size vs fraction scatter plot
        ax3 = axes[1, 0]
        color_idx = 0
        
        for ion_type in clustering_data['average_cluster_size'].keys():
            cluster_sizes = clustering_data['average_cluster_size'][ion_type]
            fractions = clustering_data['fraction_clustered'][ion_type]
            color = self.default_colors[color_idx % len(self.default_colors)]
            
            ax3.scatter(cluster_sizes, fractions, color=color, alpha=0.7, 
                       s=60, label=ion_type)
            color_idx += 1
        
        ax3.set_xlabel('Average Cluster Size')
        ax3.set_ylabel('Fraction in Clusters')
        ax3.set_title('Cluster Size vs Clustering Fraction', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        
        # Plot 4: Summary statistics
        ax4 = axes[1, 1]
        
        ion_types = list(clustering_data['average_cluster_size'].keys())
        avg_cluster_sizes = []
        avg_fractions = []
        
        for ion_type in ion_types:
            avg_size = np.mean(clustering_data['average_cluster_size'][ion_type])
            avg_fraction = np.mean(clustering_data['fraction_clustered'][ion_type])
            avg_cluster_sizes.append(avg_size)
            avg_fractions.append(avg_fraction)
        
        x_pos = np.arange(len(ion_types))
        width = 0.35
        
        bars1 = ax4.bar(x_pos - width/2, avg_cluster_sizes, width, 
                        label='Avg Cluster Size', alpha=0.7, color='skyblue')
        
        ax4_twin = ax4.twinx()
        bars2 = ax4_twin.bar(x_pos + width/2, avg_fractions, width, 
                             label='Avg Fraction Clustered', alpha=0.7, color='lightcoral')
        
        ax4.set_xlabel('Ion Type')
        ax4.set_ylabel('Average Cluster Size', color='blue')
        ax4_twin.set_ylabel('Average Fraction Clustered', color='red')
        ax4.set_title('Overall Clustering Statistics', fontweight='bold')
        ax4.set_xticks(x_pos)
        ax4.set_xticklabels(ion_types)
        
        # Combined legend
        lines1, labels1 = ax4.get_legend_handles_labels()
        lines2, labels2 = ax4_twin.get_legend_handles_labels()
        ax4.legend(lines1 + lines2, labels1 + labels2, loc='upper left')
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'ion_clustering_vs_z.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Ion clustering plot saved as: {filename}")
        
        plt.show()
        
        # Print summary
        print(f"\nIon Clustering Analysis Summary:")
        for ion_type in ion_types:
            avg_size = np.mean(clustering_data['average_cluster_size'][ion_type])
            avg_fraction = np.mean(clustering_data['fraction_clustered'][ion_type])
            print(f"  {ion_type}:")
            print(f"    Average cluster size: {avg_size:.2f}")
            print(f"    Average fraction clustered: {avg_fraction:.3f}")

    # Backward compatibility alias
    def plot_ion_clustering_results(self, save_plots=True, figsize=None, filename=None):
        '''Deprecated: Use plot_ion_clustering_vs_z() instead.'''
        import warnings
        warnings.warn("plot_ion_clustering_results() is deprecated. Use plot_ion_clustering_vs_z() instead.", 
                     DeprecationWarning, stacklevel=2)
        return self.plot_ion_clustering_vs_z(save_plots=save_plots, figsize=figsize, filename=filename)

    def plot_ion_clustering_xy_results(self, save_plots=True, figsize=(18, 12), 
                                    filename=None, plot_spatial_grids=True,
                                    z_slice_idx=None, metric='fraction_clustered'):
        '''
        Plot XY-plane ion clustering analysis results.
        
        Automatically detects if spatial gridding was used (xy_grid_size parameter)
        and creates appropriate visualizations:
        - 1D mode: Standard z-profile plots
        - 3D mode: Spatial heatmaps + z-profiles + hotspot analysis
        
        Parameters
        ----------
        save_plots : bool
            Whether to save plots to file
        figsize : tuple
            Figure size (width, height)
        filename : str, optional
            Custom filename for saved plots
        plot_spatial_grids : bool
            If True and spatial gridding data exists, create detailed spatial plots
        z_slice_idx : int, optional
            Z-slice index for spatial heatmaps. If None, uses middle slice.
        metric : str
            Metric to visualize in spatial plots: 'fraction_clustered', 
            'average_cluster_size', 'cluster_density', or 'largest_cluster_size'
        '''
        
        if not hasattr(self.analysis.results, 'ion_clustering_xy'):
            print("No XY-plane clustering data available. Run calculate_ion_clustering_xy_plane() first.")
            return
        
        clustering_data = self.analysis.results.ion_clustering_xy
        z_centers = clustering_data['z_slice_centers']
        ion_types = list(clustering_data['average_cluster_size'].keys())
        
        # Check if spatial gridding was used
        has_spatial_grid = 'xy_grid_spacing' in clustering_data
        
        if has_spatial_grid:
            print(f"Spatial gridding detected: {clustering_data['xy_grid_spacing']:.1f} Å spacing")
            if plot_spatial_grids:
                # Create spatial grid plots for each ion type
                self._plot_spatial_grid_analysis(clustering_data, ion_types, 
                                                z_slice_idx, metric, save_plots, filename)
                return
            else:
                print("Plotting XY-averaged profiles (use plot_spatial_grids=True for spatial maps)")
        
        # Standard 1D z-profile plots (or XY-averaged from 3D data)
        self._plot_1d_clustering_profiles(clustering_data, z_centers, ion_types, 
                                         has_spatial_grid, save_plots, figsize, filename)
        # Standard 1D z-profile plots (or XY-averaged from 3D data)
        self._plot_1d_clustering_profiles(clustering_data, z_centers, ion_types, 
                                         has_spatial_grid, save_plots, figsize, filename)
    
    
    def _plot_1d_clustering_profiles(self, clustering_data, z_centers, ion_types,
                                    has_spatial_grid, save_plots, figsize, filename):
        """
        Plot 1D z-profile clustering results.
        
        If has_spatial_grid is True, averages over XY grid to create 1D profiles.
        """
        
        fig, axes = plt.subplots(2, 3, figsize=figsize)
        
        colors = ['red', 'blue', 'green', 'orange', 'purple', 'brown', 'pink', 'gray']
        
        # Process data: average over XY if spatial grid exists
        if has_spatial_grid:
            # Average 3D arrays (n_slices, nx, ny) -> 1D arrays (n_slices)
            plot_data = {
                'average_cluster_size': {},
                'fraction_clustered': {},
                'cluster_density': {},
                'largest_cluster_size': {}
            }
            for ion_type in ion_types:
                plot_data['average_cluster_size'][ion_type] = np.mean(
                    clustering_data['average_cluster_size'][ion_type], axis=(1, 2))
                plot_data['fraction_clustered'][ion_type] = np.mean(
                    clustering_data['fraction_clustered'][ion_type], axis=(1, 2))
                plot_data['cluster_density'][ion_type] = np.mean(
                    clustering_data['cluster_density'][ion_type], axis=(1, 2))
                plot_data['largest_cluster_size'][ion_type] = np.max(
                    clustering_data['largest_cluster_size'][ion_type], axis=(1, 2))
        else:
            plot_data = clustering_data
        
        # Plot 1: Average cluster size vs z
        ax1 = axes[0, 0]
        for idx, ion_type in enumerate(ion_types):
            color = colors[idx % len(colors)]
            cluster_sizes = plot_data['average_cluster_size'][ion_type]
            ax1.plot(z_centers, cluster_sizes, color=color, linewidth=2, 
                    marker='o', markersize=6, label=ion_type)
        
        ax1.set_xlabel('z (Å)', fontsize=11)
        ylabel = 'Average Cluster Size (XY averaged)' if has_spatial_grid else 'Average Cluster Size (XY plane)'
        ax1.set_ylabel(ylabel, fontsize=11)
        ax1.set_title('XY-Plane Cluster Size vs Z', fontweight='bold')
        ax1.axhline(1, color='gray', linestyle='--', alpha=0.5, label='No clustering')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Fraction clustered vs z
        ax2 = axes[0, 1]
        for idx, ion_type in enumerate(ion_types):
            color = colors[idx % len(colors)]
            fractions = plot_data['fraction_clustered'][ion_type]
            ax2.plot(z_centers, fractions, color=color, linewidth=2,
                    marker='s', markersize=6, label=ion_type)
        
        ax2.set_xlabel('z (Å)', fontsize=11)
        ylabel = 'Fraction in Clusters (XY avg)' if has_spatial_grid else 'Fraction in Clusters (XY)'
        ax2.set_ylabel(ylabel, fontsize=11)
        ax2.set_title('XY-Plane Clustering Fraction', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Cluster density vs z
        ax3 = axes[0, 2]
        for idx, ion_type in enumerate(ion_types):
            color = colors[idx % len(colors)]
            density = plot_data['cluster_density'][ion_type]
            ax3.plot(z_centers, density, color=color, linewidth=2,
                    marker='^', markersize=6, label=ion_type)
        
        ax3.set_xlabel('z (Å)', fontsize=11)
        ylabel = 'Cluster Density (XY avg, clusters/nm²)' if has_spatial_grid else 'Cluster Density (clusters/nm²)'
        ax3.set_ylabel(ylabel, fontsize=11)
        ax3.set_title('XY-Plane Cluster Density', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 4: Largest cluster size vs z
        ax4 = axes[1, 0]
        for idx, ion_type in enumerate(ion_types):
            color = colors[idx % len(colors)]
            max_sizes = plot_data['largest_cluster_size'][ion_type]
            ax4.plot(z_centers, max_sizes, color=color, linewidth=2,
                    marker='d', markersize=6, label=ion_type)
        
        ax4.set_xlabel('z (Å)', fontsize=11)
        ylabel = 'Largest Cluster Size (XY max)' if has_spatial_grid else 'Largest Cluster Size'
        ax4.set_ylabel(ylabel, fontsize=11)
        ax4.set_title('Maximum XY-Plane Cluster', fontweight='bold')
        ax4.legend()
        ax4.grid(True, alpha=0.3)
        ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 5: Heatmap of cluster sizes
        ax5 = axes[1, 1]
        if len(ion_types) > 0:
            cluster_matrix = np.array([plot_data['average_cluster_size'][ion_type] 
                                    for ion_type in ion_types])
            
            im = ax5.imshow(cluster_matrix, aspect='auto', cmap='YlOrRd',
                        extent=[z_centers.min(), z_centers.max(), -0.5, len(ion_types)-0.5])
            ax5.set_xlabel('z (Å)', fontsize=11)
            ax5.set_ylabel('Ion Types', fontsize=11)
            ax5.set_title('XY-Clustering Heatmap', fontweight='bold')
            ax5.set_yticks(range(len(ion_types)))
            ax5.set_yticklabels(ion_types)
            ax5.axvline(0, color='white', linestyle='--', alpha=0.7)
            
            cbar = plt.colorbar(im, ax=ax5)
            cbar.set_label('Average Cluster Size')
        
        # Plot 6: Comparison summary
        ax6 = axes[1, 2]
        
        # Calculate overall statistics
        overall_avg_size = []
        overall_frac_clustered = []
        
        for ion_type in ion_types:
            avg_size = np.mean(plot_data['average_cluster_size'][ion_type])
            avg_frac = np.mean(plot_data['fraction_clustered'][ion_type])
            overall_avg_size.append(avg_size)
            overall_frac_clustered.append(avg_frac)
        
        x_pos = np.arange(len(ion_types))
        width = 0.35
        
        bars1 = ax6.bar(x_pos - width/2, overall_avg_size, width, 
                    label='Avg Size', alpha=0.7, 
                    color=[colors[i % len(colors)] for i in range(len(ion_types))],
                    edgecolor='black')
        
        ax6_twin = ax6.twinx()
        bars2 = ax6_twin.bar(x_pos + width/2, overall_frac_clustered, width,
                            label='Frac Clustered', alpha=0.7,
                            color='lightcoral', edgecolor='black')
        
        ax6.set_xlabel('Ion Type', fontsize=11)
        ax6.set_ylabel('Average Cluster Size', color='blue', fontsize=11)
        ax6_twin.set_ylabel('Fraction Clustered', color='red', fontsize=11)
        ax6.set_title('Overall XY-Clustering Statistics', fontweight='bold')
        ax6.set_xticks(x_pos)
        ax6.set_xticklabels(ion_types, rotation=45, ha='right')
        
        # Combined legend
        lines1, labels1 = ax6.get_legend_handles_labels()
        lines2, labels2 = ax6_twin.get_legend_handles_labels()
        ax6.legend(lines1 + lines2, labels1 + labels2, loc='upper left')
        
        plt.tight_layout()
        
        if save_plots:
            if filename is None:
                filename = 'ion_clustering_xy_analysis.png'
            plt.savefig(filename, dpi=300, bbox_inches='tight')
            print(f"XY-plane clustering analysis plot saved as: {filename}")
        
        plt.show()
    
    
    def _plot_spatial_grid_analysis(self, clustering_data, ion_types, 
                                    z_slice_idx, metric, save_plots, filename):
        """
        Create comprehensive spatial grid visualizations for each ion type.
        
        For each ion type, creates a 3-panel figure showing:
        1. XY spatial heatmap at selected z-slice
        2. Z-profile (XY averaged)
        3. Statistics and hotspot information
        """
        
        z_centers = clustering_data['z_slice_centers']
        
        # Use middle z-slice if not specified
        if z_slice_idx is None:
            z_slice_idx = len(z_centers) // 2
        
        for ion_type in ion_types:
            fig = self._create_hotspot_summary(clustering_data, ion_type, 
                                              z_slice_idx, metric)
            
            if save_plots:
                if filename is None:
                    save_name = f'ion_clustering_spatial_{ion_type}_{metric}.png'
                else:
                    base, ext = os.path.splitext(filename)
                    save_name = f'{base}_{ion_type}_{metric}{ext}'
                
                plt.savefig(save_name, dpi=300, bbox_inches='tight')
                print(f"Spatial clustering plot saved: {save_name}")
            
            plt.show()
    
    
    def _create_hotspot_summary(self, results, ion_type, z_slice_idx, 
                               metric='fraction_clustered'):
        """
        Create 3-panel summary: XY heatmap + Z-profile + statistics.
        """
        
        figsize = (16, 5)
        fig = plt.figure(figsize=figsize)
        gs = fig.add_gridspec(1, 3, width_ratios=[1.2, 1, 1], wspace=0.3)
        
        z_centers = results['z_slice_centers']
        
        # Panel 1: XY heatmap at specific z
        ax1 = fig.add_subplot(gs[0])
        X, Y = np.meshgrid(results['x_edges'], results['y_edges'])
        data_2d = results[metric][ion_type][z_slice_idx, :, :]
        im = ax1.pcolormesh(X, Y, data_2d.T, cmap='viridis', shading='flat')
        ax1.set_xlabel('X (Å)', fontsize=11)
        ax1.set_ylabel('Y (Å)', fontsize=11)
        ax1.set_title(f'XY Heatmap at Z={z_centers[z_slice_idx]:.1f} Å', 
                      fontsize=12, fontweight='bold')
        ax1.set_aspect('equal')
        
        cbar = plt.colorbar(im, ax=ax1, fraction=0.046, pad=0.04)
        
        # Format colorbar label based on metric
        metric_labels = {
            'fraction_clustered': 'Fraction Clustered',
            'cluster_density': 'Cluster Density (clusters/nm²)',
            'average_cluster_size': 'Average Cluster Size (ions)',
            'largest_cluster_size': 'Largest Cluster Size (ions)'
        }
        cbar.set_label(metric_labels.get(metric, metric.replace('_', ' ').title()), 
                      fontsize=10)
        
        # Panel 2: Z-profile (XY averaged)
        ax2 = fig.add_subplot(gs[1])
        data_3d = results[metric][ion_type]
        z_profile = np.mean(data_3d, axis=(1, 2))
        ax2.plot(z_centers, z_profile, 'o-', linewidth=2, markersize=6, color='steelblue')
        ax2.axvline(z_centers[z_slice_idx], color='r', linestyle='--', alpha=0.5, 
                    label=f'Z = {z_centers[z_slice_idx]:.1f} Å')
        ax2.set_xlabel('Z Position (Å)', fontsize=11)
        ax2.set_ylabel(metric_labels.get(metric, metric.replace('_', ' ').title()), 
                      fontsize=11)
        ax2.set_title('Z-Profile (XY Averaged)', fontsize=12, fontweight='bold')
        ax2.legend(fontsize=9)
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.3)
        
        # Panel 3: Statistics
        ax3 = fig.add_subplot(gs[2])
        ax3.axis('off')
        
        # Calculate statistics
        mean_val = np.mean(data_3d)
        std_val = np.std(data_3d)
        min_val = np.min(data_3d)
        max_val = np.max(data_3d)
        
        # Find hotspot (maximum)
        max_idx = np.unravel_index(np.argmax(data_3d), data_3d.shape)
        hotspot_z = z_centers[max_idx[0]]
        hotspot_x = results['x_centers'][max_idx[1]]
        hotspot_y = results['y_centers'][max_idx[2]]
        
        stats_text = f"""
    Statistics for {ion_type}
    {metric_labels.get(metric, metric.replace('_', ' ').title())}
    {'='*30}
    
    Mean: {mean_val:.3f}
    Std Dev: {std_val:.3f}
    Min: {min_val:.3f}
    Max: {max_val:.3f}
    
    Hotspot Location:
      Z = {hotspot_z:.1f} Å
      X = {hotspot_x:.1f} Å
      Y = {hotspot_y:.1f} Å
      Value = {max_val:.3f}
    
    Grid Info:
      Spacing: {results['xy_grid_spacing']:.1f} Å
      X cells: {data_3d.shape[1]}
      Y cells: {data_3d.shape[2]}
      Z slices: {data_3d.shape[0]}
    """
        
        ax3.text(0.1, 0.95, stats_text, transform=ax3.transAxes, 
                 fontsize=10, verticalalignment='top', family='monospace',
                 bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.3))
        
        fig.suptitle(f'{ion_type} Clustering Hotspot Analysis', 
                     fontsize=14, fontweight='bold', y=1.02)
        
        return fig
    
    
    def plot_xy_grid_at_z_slice(self, ion_type, z_slice_idx, 
                                metric='fraction_clustered',
                                save_plots=True, figsize=(12, 10), 
                                cmap='viridis', vmin=None, vmax=None,
                                filename=None):
        """
        Plot spatial distribution of clustering metric in XY plane at a specific z-slice.
        
        Parameters
        ----------
        ion_type : str
            Ion type to plot (e.g., 'NA', 'CL')
        z_slice_idx : int
            Index of z-slice to plot
        metric : str
            Metric to plot: 'average_cluster_size', 'fraction_clustered', 
            'cluster_density', or 'largest_cluster_size'
        save_plots : bool
            Whether to save the plot
        figsize : tuple
            Figure size (width, height)
        cmap : str
            Colormap name
        vmin, vmax : float, optional
            Color scale limits
        filename : str, optional
            Custom filename for saved plot
            
        Returns
        -------
        fig, ax : matplotlib figure and axis objects
        """
        
        if not hasattr(self.analysis.results, 'ion_clustering_xy'):
            print("No XY-plane clustering data available.")
            return None, None
        
        results = self.analysis.results.ion_clustering_xy
        
        # Check if gridding was used
        if 'xy_grid_spacing' not in results:
            print("Spatial grid data not available. Use xy_grid_size parameter in analysis.")
            return None, None
        
        # Get grid information
        x_centers = results['x_centers']
        y_centers = results['y_centers']
        z_center = results['z_slice_centers'][z_slice_idx]
        
        # Get data
        data = results[metric][ion_type][z_slice_idx, :, :]
        
        # Create figure
        fig, ax = plt.subplots(figsize=figsize)
        
        # Create meshgrid for pcolormesh
        X, Y = np.meshgrid(results['x_edges'], results['y_edges'])
        
        # Plot
        if vmin is None:
            vmin = data.min()
        if vmax is None:
            vmax = data.max()
        
        im = ax.pcolormesh(X, Y, data.T, cmap=cmap, vmin=vmin, vmax=vmax, shading='flat')
        
        # Formatting
        ax.set_xlabel('X (Å)', fontsize=12)
        ax.set_ylabel('Y (Å)', fontsize=12)
        ax.set_title(f'{ion_type} {metric.replace("_", " ").title()}\nZ = {z_center:.1f} Å', 
                     fontsize=14, fontweight='bold')
        ax.set_aspect('equal')
        
        # Colorbar
        cbar = plt.colorbar(im, ax=ax, fraction=0.046, pad=0.04)
        
        # Format colorbar label based on metric
        metric_labels = {
            'fraction_clustered': 'Fraction Clustered',
            'cluster_density': 'Cluster Density (clusters/nm²)',
            'average_cluster_size': 'Average Cluster Size (ions)',
            'largest_cluster_size': 'Largest Cluster Size (ions)'
        }
        cbar.set_label(metric_labels.get(metric, metric.replace('_', ' ').title()), 
                      fontsize=11)
        
        # Add grid spacing info
        ax.text(0.02, 0.98, f'Grid: {results["xy_grid_spacing"]:.1f} Å', 
                transform=ax.transAxes, fontsize=10, va='top',
                bbox=dict(boxstyle='round', facecolor='white', alpha=0.8))
        
        plt.tight_layout()
        
        if save_plots:
            if filename is None:
                filename = f'clustering_xy_grid_{ion_type}_{metric}_z{z_slice_idx}.png'
            plt.savefig(filename, dpi=300, bbox_inches='tight')
            print(f"XY grid plot saved: {filename}")
        
        plt.show()
        return fig, ax


