    #     z_indices : str or list
    #         Z-slice indices to plot ('all' or list of indices)
    #     save_plots : bool
    #         Whether to save the plot
    #     cmap : str
    #         Colormap name for ion density (default: 'hot')
    #     figsize : tuple
    #         Figure size (width, height) in inches
    #     vmax, vmin : float, optional
    #         Color scale limits for ion density
    #     show_clay_atoms : bool
    #         Whether to overlay clay atom positions (Si connections)
    #     show_mgo : bool
    #         Whether to show Mgo atoms as markers (default: True)
    #     mgo_marker_size : float
    #         Size of Mgo markers (default: 100)
    #     mgo_atom_alpha : float
    #         Transparency of Mgo markers (0-1, default: 0.9)
    #     clay_z_tolerance : float, optional
    #         Z-distance tolerance for showing Si atoms (Å).
    #         If None, uses half the z_slice_width.
    #     clay_line_alpha : float
    #         Transparency of Si connecting lines (0-1, default: 0.15)
    #     sigma : float, optional
    #         Gaussian smoothing parameter for ion density. If None, no smoothing applied.
    #     dpi : int
    #         Resolution for saved figure (default: 300)
        
