    #     ----------------------------------------
    #     show_clay_spatial : bool, default=False
    #         Whether to calculate and plot clay spatial distribution
    #     clay_plot_mode : str, default='overlay'
    #         How to display clay spatial distribution:
    #         - 'overlay': Overlay on ion density (semi-transparent)
    #         - 'separate': Show as separate subplots  
    #         - 'both': Show both overlay and separate views
    #     mg_vdw_scaling : float, default=2.0
    #         Scaling factor for Mg Van der Waals radius (0.72 Å × scaling)
    #     apply_mg_smoothing : bool, default=True
    #         If True, apply Gaussian smoothing to Mg spatial footprints
    #     mg_smoothing_sigma : float, optional
    #         Gaussian smoothing sigma for Mg atoms. If None, uses scaled_mg_radius / 2
    #     clay_spatial_alpha : float, default=0.7
    #         Transparency for clay spatial overlay (0-1)
    #     clay_spatial_cmap : str, default='Reds'
    #         Colormap for clay spatial distribution
    #     clay_spatial_vmax : float, optional
    #         Maximum value for clay spatial colorbar
    #     show_clay_colorbar : bool, default=True
    #         Whether to show separate colorbar for clay spatial distribution
    #     clay_colorbar_label : str, default='Clay Density'
    #         Label for clay spatial colorbar
    #     step : int, default=1
    #         Frame sampling interval for clay calculation
    #     use_cache : bool, default=True
    #         Whether to use cached clay data if available
    #     cache_filename : str, default='clay_spatial_xy_cache.npz'
    #         Name of cache file for clay data
    #     max_frames : int, optional
    #         Maximum number of frames to analyze for clay calculation
        
