    def plot_pmf_vs_z(self, ion_types=None, save_plots=True, figsize=(15, 10), 
                    show_binding_sites=True, show_barriers=True, show_bulk_reference=True,
                    colors=None, filename='pmf_vs_z.png', dpi=300,
                    title_fontsize=22,
                    label_fontsize=18,
                    tick_fontsize=14,
                    show_grid=True,
                    grid_alpha=0.5,
                    save_individual_figures=False,
                    show_title=True,
                    show_legend=True,
                    legend_frameon=False,
                    legend_fontsize=14,
                    legend_loc='best',
                    linewidth=2.5,
                    marker_size=80,
                    barrier_marker='^',
                    binding_marker='v',
                    marker_edge_width=1.5,
                    marker_edge_color='black',
                    bulk_ref_style='--',
                    bulk_ref_alpha=0.7,
                    zero_line_alpha=0.5,
                    ion_colors=None,
                    line_weight=None,
                    y_max=None,
                    y_min=None,
                    x_max=None,
                    x_min=None,
                    show_clay_boundaries_on_overlay=False,
                    # 🆕 NEW: Clay boundary styling parameters (adapted from plot_clay_interface_boundaries)
                    upper_clay_avg_color='gray',
                    upper_si_color='orange',
                    upper_mgo_color='green',
                    lower_clay_avg_color='gray',
                    lower_si_color='orange',
                    lower_mgo_color='green',
                    upper_clay_avg_linestyle='-',
                    upper_si_linestyle='--',
                    upper_mgo_linestyle='--',
                    lower_clay_avg_linestyle='-',
                    lower_si_linestyle='--',
                    lower_mgo_linestyle='--',
                    # 🆕 NEW: Clay fill styling parameters (adapted from plot_clay_interface_boundaries)
                    clay_fill_color='yellow',
                    clay_fill_alpha=0.15,
                    fill_PMF_curves=False,
                    fill_ion_density_curves=False,
                    ion_fill_alpha=0.15,
                    ion_fill_colors=None,
                    # 🆕 NEW: Symmetrization parameters (adapted from plot_clay_interface_boundaries)
                    symmetrize_boundaries=False,
                    symmetrize_method='average',
                    show_asymmetry_std=False,
                    symmetry_center=0.0):
        """
        Plot Potential of Mean Force profiles with enhanced styling options and clay boundary integration
        
        Parameters:
        -----------
        [... all existing parameters remain the same ...]
            
        🆕 NEW: Clay boundary styling parameters (adapted from plot_clay_interface_boundaries):
        upper_clay_avg_color : str, default='gray'
            Color for upper clay average boundary line
        upper_si_color : str, default='orange'
            Color for upper Si layer boundary line
        upper_mgo_color : str, default='green'
            Color for upper MgO layer boundary line
        lower_clay_avg_color : str, default='gray'
            Color for lower clay average boundary line
        lower_si_color : str, default='orange'
            Color for lower Si layer boundary line
        lower_mgo_color : str, default='green'
            Color for lower MgO layer boundary line
        upper_clay_avg_linestyle : str, default='-'
            Line style for upper clay average boundary
        upper_si_linestyle : str, default='--'
            Line style for upper Si layer boundary
        upper_mgo_linestyle : str, default='--'
            Line style for upper MgO layer boundary
        lower_clay_avg_linestyle : str, default='-'
            Line style for lower clay average boundary
        lower_si_linestyle : str, default='--'
            Line style for lower Si layer boundary
        lower_mgo_linestyle : str, default=':'
            Line style for lower MgO layer boundary
            
        🆕 NEW: Clay fill styling parameters:
        clay_fill_color : str, default='yellow'
            Color for filled clay regions (fills actual Si-MgO boundaries)
        clay_fill_alpha : float, default=0.15
            Transparency for filled clay regions (0-1)
        fill_PMF_curves : bool, default=False
            Fill area under PMF curves
        fill_ion_density_curves : bool, default=False
            Fill area under ion density curves
        ion_fill_alpha : float, default=0.15
            Transparency for ion curve fills (0-1)
        ion_fill_colors : dict, optional
            Dictionary mapping ion types to fill colors. If None, uses line colors.
            
        🆕 NEW: Symmetrization parameters (adapted from plot_clay_interface_boundaries):
        symmetrize_boundaries : bool, default=False
            If True, symmetrize clay boundary positions
        symmetrize_method : str, default='average'
            Method for symmetrization:
            - 'average': Average positive and negative sides
            - 'fold': Use positive side only, fold to negative
            - 'mirror_positive': Use positive side, mirror to negative
            - 'mirror_negative': Use negative side, mirror to positive
        show_asymmetry_std : bool, default=False
            If True, show standard deviation between sides as error bars/shading
        symmetry_center : float, default=0.0
            Center point for symmetrization
        """
        
        # Check if PMF data exists
        if not hasattr(self.analysis.results, 'pmf_vs_z'):
            print("No PMF data available. Run calculate_pmf_vs_z() first.")
            return
        
        pmf_data = self.analysis.results.pmf_vs_z
        
        if ion_types is None:
            ion_types = list(pmf_data.keys())
        
        if not colors:
            colors = ['red', 'blue', 'green', 'orange', 'purple', 'brown', 'pink', 'gray']
        
        # Handle line_weight parameter
        actual_linewidth = line_weight if line_weight is not None else linewidth
        
        print(f"\n🎨 Creating enhanced PMF plots with:")
        print(f"  ✓ Line plots (no dots)")
        print(f"  ✓ Grid: {'ON' if show_grid else 'OFF'} (α={grid_alpha})")
        print(f"  ✓ Legend: {'ON' if show_legend else 'OFF'} (frameon={legend_frameon})")
        print(f"  ✓ Markers: barriers={barrier_marker}, binding={binding_marker}")
        print(f"  ✓ Individual figures: {'ON' if save_individual_figures else 'OFF'}")
        print(f"  ✓ Line weight: {actual_linewidth}")
        print(f"  ✓ PMF + Ion Density Overlay: Clay boundaries {'ON' if show_clay_boundaries_on_overlay else 'OFF'}")
        if ion_colors:
            print(f"  ✓ Ion colors: {ion_colors}")
        if any(param is not None for param in [y_min, y_max, x_min, x_max]):
            print(f"  ✓ Axis limits: x=[{x_min}, {x_max}], y=[{y_min}, {y_max}]")
        if show_clay_boundaries_on_overlay:
            print(f"  ✓ Clay boundary styling: Custom colors and linestyles applied")
            print(f"  ✓ Clay fill: {'ON' if clay_fill_color else 'OFF'} (color={clay_fill_color}, α={clay_fill_alpha})")
            if symmetrize_boundaries:
                print(f"  ✓ Boundary symmetrization: {symmetrize_method} method")
        
        # Create 4 subplots (2x2 grid)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        axes = axes.flatten()
        
        # Get units from first ion type
        units = None
        for ion_type in ion_types:
            if ion_type in pmf_data:
                units = pmf_data[ion_type]['units']
                break
        
        # Plot 1: PMF profiles (LINES ONLY, NO DOTS)
        ax1 = axes[0]
        
        for idx, ion_type in enumerate(ion_types):
            if ion_type not in pmf_data:
                continue
            
            data = pmf_data[ion_type]
            
            # Use ion_colors if provided
            if ion_colors is not None and ion_type in ion_colors:
                color = ion_colors[ion_type]
            else:
                color = colors[idx % len(colors)]
            
            z_centers = data['z_centers']
            pmf = data['pmf']
            
            # Plot PMF as LINES ONLY (no markers) with custom line weight
            valid_mask = np.isfinite(pmf)
            line = ax1.plot(z_centers[valid_mask], pmf[valid_mask], 
                        color=color, linewidth=actual_linewidth, label=ion_type)
            
            # Fill under PMF curves if requested
            if fill_PMF_curves:
                fill_color = ion_fill_colors.get(ion_type, color) if ion_fill_colors else color
                ax1.fill_between(z_centers[valid_mask], 0, pmf[valid_mask], 
                            color=fill_color, alpha=ion_fill_alpha)
            
            # Mark binding sites with customizable markers
            if show_binding_sites and data['binding_sites']['positions']:
                binding_z = np.array(data['binding_sites']['positions'])
                binding_e = np.array(data['binding_sites']['energies'])
                ax1.scatter(binding_z, binding_e, color=color, s=marker_size, 
                        marker=binding_marker, edgecolor=marker_edge_color, 
                        linewidth=marker_edge_width, zorder=5, alpha=0.9)
            
            # Mark barriers with customizable markers
            if show_barriers and data['energy_barriers']['positions']:
                barrier_z = np.array(data['energy_barriers']['positions'])
                barrier_e = np.array(data['energy_barriers']['energies'])
                ax1.scatter(barrier_z, barrier_e, color=color, s=marker_size,
                        marker=barrier_marker, edgecolor=marker_edge_color,
                        linewidth=marker_edge_width, zorder=5, alpha=0.9)
        
        # Bulk reference line with custom styling
        if show_bulk_reference:
            ax1.axhline(0, color='k', linestyle=bulk_ref_style, alpha=bulk_ref_alpha, 
                    linewidth=actual_linewidth*0.8, label='Bulk reference')
        
        # Zero line with custom styling
        ax1.axvline(0, color='k', linestyle=':', alpha=zero_line_alpha, linewidth=1.0)
        
        # Axis formatting
        ax1.set_xlabel('z (Å)', fontsize=label_fontsize)
        ax1.set_ylabel(f'PMF ({units})' if units else 'PMF', fontsize=label_fontsize)
        if show_title:
            ax1.set_title('Potential of Mean Force Profiles', fontsize=title_fontsize, fontweight='bold')
        
        # Apply axis limits if provided
        if x_min is not None or x_max is not None:
            current_xlim = ax1.get_xlim()
            new_xlim = (x_min if x_min is not None else current_xlim[0],
                    x_max if x_max is not None else current_xlim[1])
            ax1.set_xlim(new_xlim)
        
        if y_min is not None or y_max is not None:
            current_ylim = ax1.get_ylim()
            new_ylim = (y_min if y_min is not None else current_ylim[0],
                    y_max if y_max is not None else current_ylim[1])
            ax1.set_ylim(new_ylim)
        
        # Legend and grid control
        if show_legend:
            ax1.legend(fontsize=legend_fontsize, loc=legend_loc, frameon=legend_frameon)
        if show_grid:
            ax1.grid(True, alpha=grid_alpha)
        
        # Tick formatting
        ax1.tick_params(axis='both', which='major', labelsize=tick_fontsize)
        
        # Plot 2: Density profiles (for comparison)
        ax2 = axes[1]
        
        for idx, ion_type in enumerate(ion_types):
            if ion_type not in pmf_data:
                continue
            
            data = pmf_data[ion_type]
            
            # Use ion_colors if provided
            if ion_colors is not None and ion_type in ion_colors:
                color = ion_colors[ion_type]
            else:
                color = colors[idx % len(colors)]
            
            z_centers = data['z_centers']
            density = data['density']
            
            # LINES ONLY for density too with custom line weight
            line = ax2.plot(z_centers, density, color=color, linewidth=actual_linewidth, 
                        label=f'{ion_type}', alpha=0.8)
            
            # Fill under ion density curves if requested
            if fill_ion_density_curves:
                fill_color = ion_fill_colors.get(ion_type, color) if ion_fill_colors else color
                ax2.fill_between(z_centers, 0, density, 
                            color=fill_color, alpha=ion_fill_alpha)
            
            # Show bulk reference
            if show_bulk_reference:
                bulk_density = data['bulk_density']
                ax2.axhline(bulk_density, color=color, linestyle=':', alpha=bulk_ref_alpha*0.8)
        
        ax2.axvline(0, color='k', linestyle=':', alpha=zero_line_alpha, linewidth=1.0)
        ax2.set_xlabel('z (Å)', fontsize=label_fontsize)
        ax2.set_ylabel('Ion Density (ions/Å³)', fontsize=label_fontsize)
        if show_title:
            ax2.set_title('Ion Density Profiles', fontsize=title_fontsize, fontweight='bold')
        
        # Apply axis limits if provided
        if x_min is not None or x_max is not None:
            current_xlim = ax2.get_xlim()
            new_xlim = (x_min if x_min is not None else current_xlim[0],
                    x_max if x_max is not None else current_xlim[1])
            ax2.set_xlim(new_xlim)
        
        if show_legend:
            ax2.legend(fontsize=legend_fontsize, loc=legend_loc, frameon=legend_frameon)
        if show_grid:
            ax2.grid(True, alpha=grid_alpha)
        ax2.tick_params(axis='both', which='major', labelsize=tick_fontsize)
        ax2.set_yscale('log')
        
        # Plot 3: Binding strength and barrier heights
        ax3 = axes[2]
        
        ion_names = []
        binding_strengths = []
        barrier_heights = []
        
        for ion_type in ion_types:
            if ion_type not in pmf_data:
                continue
            
            data = pmf_data[ion_type]
            ion_names.append(ion_type)
            
            # Strongest binding (most negative PMF)
            if data['binding_sites']['energies']:
                strongest_binding = min(data['binding_sites']['energies'])
                binding_strengths.append(-strongest_binding)  # Make positive for binding strength
            else:
                binding_strengths.append(0)
            
            # Highest barrier
            if data['energy_barriers']['energies']:
                highest_barrier = max(data['energy_barriers']['energies'])
                barrier_heights.append(highest_barrier)
            else:
                barrier_heights.append(0)
        
        x_pos = np.arange(len(ion_names))
        width = 0.35
        
        # Better bar styling with custom colors
        bars1 = ax3.bar(x_pos - width/2, binding_strengths, width, 
                    label='Binding Strength', color='forestgreen', alpha=0.8, 
                    edgecolor='darkgreen', linewidth=1.2)
        bars2 = ax3.bar(x_pos + width/2, barrier_heights, width,
                    label='Barrier Height', color='tomato', alpha=0.8, 
                    edgecolor='darkred', linewidth=1.2)
        
        ax3.set_ylabel(f'Energy ({units})' if units else 'Energy', fontsize=label_fontsize)
        if show_title:
            ax3.set_title('Binding Strength vs Energy Barriers', fontsize=title_fontsize, fontweight='bold')
        ax3.set_xticks(x_pos)
        ax3.set_xticklabels(ion_names, rotation=45, ha='right', fontsize=tick_fontsize)
        if show_legend:
            ax3.legend(fontsize=legend_fontsize, loc=legend_loc, frameon=legend_frameon)
        if show_grid:
            ax3.grid(True, alpha=grid_alpha, axis='y')
        ax3.tick_params(axis='y', which='major', labelsize=tick_fontsize)
        
        # Add value labels on bars with better formatting
        for bars in [bars1, bars2]:
            for bar in bars:
                height = bar.get_height()
                if height > 0:
                    ax3.text(bar.get_x() + bar.get_width()/2., height + height*0.02,
                            f'{height:.2f}', ha='center', va='bottom', 
                            fontweight='bold', fontsize=tick_fontsize-2)
        
        # Plot 4: PMF with Ion Density Overlay + Enhanced Clay Boundaries (adapted from plot_clay_interface_boundaries)
        ax4 = axes[3]
        
        # Create twin axis for density
        ax4_twin = ax4.twinx()
        
        # Plot PMF on left axis
        for idx, ion_type in enumerate(ion_types):
            if ion_type not in pmf_data:
                continue
            
            data = pmf_data[ion_type]
            
            # Use ion_colors if provided
            if ion_colors is not None and ion_type in ion_colors:
                color = ion_colors[ion_type]
            else:
                color = colors[idx % len(colors)]
            
            z_centers = data['z_centers']
            pmf = data['pmf']
            density = data['density']
            
            # Plot PMF as solid lines
            valid_mask = np.isfinite(pmf)
            pmf_line = ax4.plot(z_centers[valid_mask], pmf[valid_mask], 
                            color=color, linewidth=actual_linewidth, label=f'{ion_type} PMF')
            
            # Fill under PMF curves if requested
            if fill_PMF_curves:
                fill_color = ion_fill_colors.get(ion_type, color) if ion_fill_colors else color
                ax4.fill_between(z_centers[valid_mask], 0, pmf[valid_mask], 
                            color=fill_color, alpha=ion_fill_alpha)
            
            # Plot density as dashed lines on twin axis
            density_line = ax4_twin.plot(z_centers, density, color=color, linewidth=actual_linewidth*0.8, 
                                    linestyle='--', alpha=0.7, label=f'{ion_type} density')
            
            # Fill under ion density curves if requested
            if fill_ion_density_curves:
                fill_color = ion_fill_colors.get(ion_type, color) if ion_fill_colors else color
                ax4_twin.fill_between(z_centers, 0, density, 
                                    color=fill_color, alpha=ion_fill_alpha)
        
        # 🆕 NEW: Add enhanced clay boundaries with symmetrization (adapted from plot_clay_interface_boundaries)
        if show_clay_boundaries_on_overlay and hasattr(self.analysis.results, 'clay_interface_boundaries'):
            clay_boundaries = self.analysis.results.clay_interface_boundaries
            
            # 🆕 NEW: Apply symmetrization logic (adapted from plot_clay_interface_boundaries)
            sym_boundaries = None
            if symmetrize_boundaries:
                upper_clay_avg = clay_boundaries.get('clay_average_z_positive')
                lower_clay_avg = clay_boundaries.get('clay_average_z_negative')
                
                # Handle None values for clay boundaries
                if upper_clay_avg is not None and lower_clay_avg is not None:
                    clay_avg = (abs(upper_clay_avg) + abs(lower_clay_avg)) / 2
                    clay_std = abs(abs(upper_clay_avg) - abs(lower_clay_avg)) / 2
                elif upper_clay_avg is not None:
                    clay_avg = abs(upper_clay_avg)
                    clay_std = 0.0
                elif lower_clay_avg is not None:
                    clay_avg = abs(lower_clay_avg)
                    clay_std = 0.0
                else:
                    clay_avg = None
                    clay_std = 0.0
                
                # Handle Si boundaries
                upper_si = clay_boundaries.get('si_average_z_positive')
                lower_si = clay_boundaries.get('si_average_z_negative')
                
                if upper_si is not None and lower_si is not None:
                    si_avg = (abs(upper_si) + abs(lower_si)) / 2
                    si_std = abs(abs(upper_si) - abs(lower_si)) / 2
                elif upper_si is not None:
                    si_avg = abs(upper_si)
                    si_std = 0.0
                elif lower_si is not None:
                    si_avg = abs(lower_si)
                    si_std = 0.0
                else:
                    si_avg = None
                    si_std = 0.0
                
                # Handle Mg boundaries - WITH PERIODIC BOUNDARY CORRECTION
                upper_mgo = clay_boundaries.get('mgo_average_z_positive')
                lower_mgo = clay_boundaries.get('mgo_average_z_negative')
                
                # Apply periodic boundary correction for Mg atoms only
                if upper_mgo is None and lower_mgo is not None:
                    upper_mgo = -lower_mgo  # Use opposite sign
                elif lower_mgo is None and upper_mgo is not None:
                    lower_mgo = -upper_mgo  # Use opposite sign
                
                if upper_mgo is not None and lower_mgo is not None:
                    mgo_avg = (abs(upper_mgo) + abs(lower_mgo)) / 2
                    mgo_std = abs(abs(upper_mgo) - abs(lower_mgo)) / 2
                elif upper_mgo is not None:
                    mgo_avg = abs(upper_mgo)
                    mgo_std = 0.0
                elif lower_mgo is not None:
                    mgo_avg = abs(lower_mgo)
                    mgo_std = 0.0
                else:
                    mgo_avg = None
                    mgo_std = 0.0
                
                sym_boundaries = {
                    'clay_avg': clay_avg,
                    'si_avg': si_avg,
                    'mgo_avg': mgo_avg,
                    'clay_std': clay_std,
                    'si_std': si_std,
                    'mgo_std': mgo_std
                }
            
            # Enhanced boundary styles with individual control (adapted from plot_clay_interface_boundaries)
            if symmetrize_boundaries and sym_boundaries is not None:
                # Symmetrized boundaries
                if sym_boundaries['clay_avg'] is not None:
                    ax4.axvline(sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Clay Avg (±{sym_boundaries["clay_avg"]:.2f} Å)')
                    ax4.axvline(-sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                if sym_boundaries['si_avg'] is not None:
                    ax4.axvline(sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Si Layer (±{sym_boundaries["si_avg"]:.2f} Å)')
                    ax4.axvline(-sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                if sym_boundaries['mgo_avg'] is not None:
                    ax4.axvline(sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Mg Layer (±{sym_boundaries["mgo_avg"]:.2f} Å)')
                    ax4.axvline(-sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                # Show asymmetry shading if requested
                if show_asymmetry_std:
                    if sym_boundaries['clay_avg'] is not None:
                        ax4.axvspan(sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                                sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                                alpha=0.1, color=upper_clay_avg_color)
                        ax4.axvspan(-sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                                -sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                                alpha=0.1, color=upper_clay_avg_color)
                    
                    if sym_boundaries['si_avg'] is not None:
                        ax4.axvspan(sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                                sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                                alpha=0.1, color=upper_si_color)
                        ax4.axvspan(-sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                                -sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                                alpha=0.1, color=upper_si_color)
                    
                    if sym_boundaries['mgo_avg'] is not None:
                        ax4.axvspan(sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                                sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                                alpha=0.1, color=upper_mgo_color)
                        ax4.axvspan(-sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                                -sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                                alpha=0.1, color=upper_mgo_color)
                
                # Fill clay regions (symmetrized)
                if clay_fill_color and sym_boundaries['si_avg'] is not None and sym_boundaries['mgo_avg'] is not None:
                    ax4.axvspan(sym_boundaries['si_avg'], sym_boundaries['mgo_avg'], 
                            color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
                    ax4.axvspan(-sym_boundaries['mgo_avg'], -sym_boundaries['si_avg'], 
                            color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
            
            else:
                # Original boundaries with periodic boundary correction
                plot_boundaries = clay_boundaries.copy()
                
                # Apply periodic boundary correction for Mg atoms
