                            original_pmf_grid = surface_info['pmf_grid']
                            
                            # CRITICAL FIX: If PMF and Z have different resolutions, interpolate PMF to match
                            if original_pmf_grid.shape != Z_original.shape:
                                from scipy.interpolate import RegularGridInterpolator
                                y_orig = np.arange(original_pmf_grid.shape[0])
                                x_orig = np.arange(original_pmf_grid.shape[1])
                                interpolator = RegularGridInterpolator(
                                    (y_orig, x_orig), original_pmf_grid,
                                    method='linear', bounds_error=False, fill_value=np.nan
                                )
                                y_new = np.linspace(0, original_pmf_grid.shape[0] - 1, Z_original.shape[0])
                                x_new = np.linspace(0, original_pmf_grid.shape[1] - 1, Z_original.shape[1])
                                Y_new, X_new = np.meshgrid(y_new, x_new, indexing='ij')
                                coords = np.column_stack([Y_new.ravel(), X_new.ravel()])
                                original_pmf_grid = interpolator(coords).reshape(Z_original.shape)
                            
                            # Fill missing PMF data using (now resolution-matched) PMF
                            filled_pmf_grid = _fill_missing_pmf_data(original_pmf_grid)
                            
