                                sm = ScalarMappable(norm=cb_info['norm'], cmap=cb_info['cmap'])
                                sm.set_array([])
                                cb_y = ax_pos.y0 + idx_cb * (colorbar_height + colorbar_spacing)
                                cbar_ax = individual_fig.add_axes([colorbar_x, cb_y, cbar_width_val, colorbar_height])
                                cbar = individual_fig.colorbar(sm, cax=cbar_ax)
                                cbar.ax.tick_params(labelsize=colorbar_tick_fontsize-2)
                                
                                # Format tick labels to consistent decimal places for alignment
