                                cbar.ax.yaxis.set_major_formatter(plt.matplotlib.ticker.FormatStrFormatter('%4.1f'))
                                
                                label_text = f'{shell_name}\n({cb_info["vmin"]:.1f}-{cb_info["vmax"]:.1f})'
                                cbar.set_label(label_text, fontsize=label_fontsize-2, labelpad=colorbar_labelpad)
                                
