                            sm.set_array([])
                            cbar = individual_fig.colorbar(sm, ax=individual_ax, shrink=0.7, aspect=15, pad=colorbar_pad)
                            cbar.ax.tick_params(labelsize=colorbar_tick_fontsize)
                            
                            if colorbar_scaling == 'unified':
                                cbar.set_label(f'{colorbar_label}\n(unified scale)', 
                                             fontsize=label_fontsize, labelpad=colorbar_labelpad)
                            elif colorbar_scaling == 'global':
                                cbar.set_label(f'{colorbar_label}\n({ion_type})', 
                                             fontsize=label_fontsize, labelpad=colorbar_labelpad)
                            else:
                                cbar.set_label(colorbar_label, fontsize=label_fontsize, labelpad=colorbar_labelpad)
                    
