    def plot_pmf_with_bootstrap_uncertainty_bands(self, ion_types=None, 
                                                bootstrap_results=None,
                                                confidence_levels=[0.68, 0.95],
                                                save_plots=True, figsize=(12, 8),
                                                filename='pmf_with_uncertainty_bands.png',
                                                dpi=300,
                                                title_fontsize=16,
                                                label_fontsize=14,
                                                tick_fontsize=12,
                                                legend_fontsize=12,
                                                linewidth=3.0,
                                                ion_colors=None,
                                                fill_alpha=0.3,
                                                line_alpha=0.9,
                                                show_grid=True,
                                                grid_alpha=0.3,
                                                x_min=None, x_max=None,
                                                y_min=None, y_max=None,
                                                use_precomputed_intervals=True,
                                                show_clay_boundaries=False,
                                                upper_clay_avg_color='gray',
                                                upper_si_color='orange',
                                                upper_mgo_color='green',
                                                lower_clay_avg_color='gray',
                                                lower_si_color='orange',
                                                lower_mgo_color='green',
                                                upper_clay_avg_linestyle='-',
                                                upper_si_linestyle='--',
                                                upper_mgo_linestyle='--',
                                                lower_clay_avg_linestyle='-',
                                                lower_si_linestyle='--',
                                                lower_mgo_linestyle='--',
                                                clay_fill_color='yellow',
                                                clay_fill_alpha=0.15,
                                                symmetrize_boundaries=False,
                                                symmetrize_method='average',
                                                show_asymmetry_std=False,
                                                symmetry_center=0.0,
                                                show_legend=True,
                                                show_title=True):
        """
        Plot PMF with bootstrap uncertainty bands using pre-calculated confidence intervals
        
        Parameters
        ----------
        ion_types : list or None
            Ion types to plot. If None, uses all available
        bootstrap_results : dict or None
            Bootstrap results dictionary containing confidence intervals
        confidence_levels : list
            Confidence levels to plot (filters which CIs to show from bootstrap results)
        save_plots : bool
            Whether to save the plot
        figsize : tuple
            Figure size (width, height)
        filename : str
            Output filename
        dpi : int
            Plot resolution
        title_fontsize : int
            Font size for title
        label_fontsize : int
            Font size for axis labels
        tick_fontsize : int
            Font size for tick labels
        legend_fontsize : int
            Font size for legend
        linewidth : float
            Width of PMF lines
        ion_colors : dict
            Colors for different ions
        fill_alpha : float
            Transparency for uncertainty bands
        line_alpha : float
            Transparency for PMF lines
        show_grid : bool
            Whether to show grid
        grid_alpha : float
            Grid transparency
        x_min, x_max : float
            X-axis limits
        y_min, y_max : float
            Y-axis limits
        use_precomputed_intervals : bool
            Whether to use pre-calculated confidence intervals
        show_clay_boundaries : bool
            Whether to show clay boundary lines
        upper_clay_avg_color : str, default='gray'
            Color for upper clay average boundary line
        upper_si_color : str, default='orange'
            Color for upper Si layer boundary line
        upper_mgo_color : str, default='green'
            Color for upper MgO layer boundary line
        lower_clay_avg_color : str, default='gray'
            Color for lower clay average boundary line
        lower_si_color : str, default='orange'
            Color for lower Si layer boundary line
        lower_mgo_color : str, default='green'
            Color for lower MgO layer boundary line
        upper_clay_avg_linestyle : str, default='-'
            Line style for upper clay average boundary
        upper_si_linestyle : str, default='--'
            Line style for upper Si layer boundary
        upper_mgo_linestyle : str, default='--'
            Line style for upper MgO layer boundary
        lower_clay_avg_linestyle : str, default='-'
            Line style for lower clay average boundary
        lower_si_linestyle : str, default='--'
            Line style for lower Si layer boundary
        lower_mgo_linestyle : str, default='--'
            Line style for lower MgO layer boundary
        clay_fill_color : str, default='yellow'
            Color for filled clay regions
        clay_fill_alpha : float, default=0.15
            Transparency for filled clay regions (0-1)
        symmetrize_boundaries : bool, default=False
            Whether to symmetrize clay boundaries
        symmetrize_method : str, default='average'
            Method for symmetrization ('average' or other)
        show_asymmetry_std : bool, default=False
            Whether to show asymmetry standard deviation
        symmetry_center : float, default=0.0
            Center point for symmetrization
        show_legend : bool, default=True
            Whether to display the legend
        show_title : bool, default=True
            Whether to display the plot title
        
        Returns
        -------
        tuple
            (figure, axes)
        """
        
        # Validate inputs
        if bootstrap_results is None:
            bootstrap_results = getattr(self.analysis.results, 'bootstrap_pmf_uncertainty', {})
        
        if not bootstrap_results:
            print("❌ No bootstrap results available")
            return None, None
        
        if ion_types is None:
            ion_types = list(bootstrap_results.keys())
        
        print(f"\n🎨 Creating PMF plots with bootstrap uncertainty bands")
        print(f"Ion types: {ion_types}")
        print(f"Using precomputed intervals: {use_precomputed_intervals}")
        print(f"Requested confidence levels: {confidence_levels}")
        print(f"Show legend: {show_legend}")
        print(f"Show title: {show_title}")
        if show_clay_boundaries:
            print(f"Clay boundaries: ENABLED")
            if symmetrize_boundaries:
                print(f"Boundary symmetrization: {symmetrize_method} method")
            if clay_fill_color:
                print(f"Clay fill: {clay_fill_color} (α={clay_fill_alpha})")
        
        # Create figure
        fig, ax = plt.subplots(figsize=figsize, dpi=dpi)
        
        # Default colors if not provided
        if ion_colors is None:
            ion_colors = {'NA': 'blue', 'CL': 'red', 'MG': 'green', 'CA': 'orange'}
        
        # Track legend entries to avoid duplicates
        legend_entries = []
        
        for idx, ion_type in enumerate(ion_types):
            if ion_type not in bootstrap_results:
                print(f"Warning: No bootstrap data for {ion_type}")
                continue
                
            result = bootstrap_results[ion_type]
            
            # Check if we have the required data
            if 'confidence_intervals' not in result or 'mean_pmf' not in result:
                print(f"Warning: Missing required data for {ion_type}")
                print(f"Available keys: {list(result.keys())}")
                continue
            
            z_centers = result.get('z_centers')
            mean_pmf = result.get('mean_pmf')
            
            if z_centers is None or mean_pmf is None:
                print(f"Warning: Missing z_centers or mean_pmf for {ion_type}")
                continue
            
            # Get color for this ion
            if ion_type in ion_colors:
                color = ion_colors[ion_type]
            else:
                color = f'C{idx}'
            
            ci_data = result['confidence_intervals']
            print(f"Confidence intervals structure for {ion_type}: {list(ci_data.keys())}")
            
            # 🔧 FIXED: Properly filter confidence intervals based on requested levels
            confidence_intervals_plotted = []
            
            # Convert requested confidence levels to both decimal and percentage formats for comparison
            requested_decimals = []
            requested_percentages = []
            for cl in confidence_levels:
                if cl <= 1.0:
                    requested_decimals.append(cl)
                    requested_percentages.append(int(cl * 100))
                else:
                    requested_decimals.append(cl / 100.0)
                    requested_percentages.append(int(cl))
            
            print(f"  Looking for CIs matching: {requested_decimals} (decimal) or {requested_percentages}% (percentage)")
            
            # Check if we have single CI structure (backward compatibility)
            if 'lower' in ci_data and 'upper' in ci_data:
                # Single confidence interval structure
                conf_level_raw = ci_data.get('confidence_level', 95)
                
                # Convert to decimal for comparison
                if conf_level_raw <= 1.0:
                    conf_level_decimal = conf_level_raw
                else:
                    conf_level_decimal = conf_level_raw / 100.0
                
                conf_level_percentage = int(conf_level_decimal * 100)
                
                # 🔧 Check if this CI matches any requested confidence level
                if (conf_level_decimal in requested_decimals or 
                    conf_level_percentage in requested_percentages or
                    any(abs(conf_level_decimal - req_cl) < 0.01 for req_cl in requested_decimals)):
                    
                    lower_bound = ci_data['lower']
                    upper_bound = ci_data['upper']
                    
                    # Plot confidence band FIRST (so it appears behind the line)
                    fill = ax.fill_between(z_centers, lower_bound, upper_bound, 
                                        color=color, alpha=fill_alpha, 
                                        label=f'{ion_type} {conf_level_percentage}% CI', zorder=1)
                    
                    confidence_intervals_plotted.append(f'{ion_type} {conf_level_percentage}% CI')
                    print(f"    ✅ Added confidence band for {ion_type} ({conf_level_percentage}% CI)")
                else:
                    print(f"    ⏭️ Skipped {ion_type} ({conf_level_percentage}% CI) - not in requested levels")
            
            else:
                # Multiple confidence intervals structure - check each one
                for ci_key, ci_value in ci_data.items():
                    if not isinstance(ci_value, dict) or 'lower' not in ci_value or 'upper' not in ci_value:
                        continue
                    
                    # Try to parse confidence level from key
                    try:
                        # Handle different key formats: '95%', '95', '0.95', etc.
                        if isinstance(ci_key, str):
                            if ci_key.endswith('%'):
                                key_percentage = int(ci_key[:-1])
                                key_decimal = key_percentage / 100.0
                            else:
                                key_float = float(ci_key)
                                if key_float <= 1.0:
                                    key_decimal = key_float
                                    key_percentage = int(key_float * 100)
                                else:
                                    key_percentage = int(key_float)
                                    key_decimal = key_float / 100.0
                        else:
                            # Numeric key
                            key_float = float(ci_key)
                            if key_float <= 1.0:
                                key_decimal = key_float
                                key_percentage = int(key_float * 100)
                            else:
                                key_percentage = int(key_float)
                                key_decimal = key_float / 100.0
            
                    except (ValueError, TypeError):
                        print(f"    ⚠️ Could not parse confidence level from key: {ci_key}")
                        continue
                    
                    # 🔧 Check if this CI matches any requested confidence level
                    if (key_decimal in requested_decimals or 
                        key_percentage in requested_percentages or
                        any(abs(key_decimal - req_cl) < 0.01 for req_cl in requested_decimals)):
                        
                        lower_bound = ci_value['lower']
                        upper_bound = ci_value['upper']
                        
                        # Use different alpha for different confidence levels (make higher confidence more transparent)
                        level_alpha = fill_alpha * (0.5 + 0.5 * key_decimal)
                        
                        # Plot confidence band
                        fill = ax.fill_between(z_centers, lower_bound, upper_bound, 
                                            color=color, alpha=level_alpha, 
                                            label=f'{ion_type} {key_percentage}% CI', zorder=1)
                        
                        confidence_intervals_plotted.append(f'{ion_type} {key_percentage}% CI')
                        print(f"    ✅ Added confidence band for {ion_type} ({key_percentage}% CI)")
                    else:
                        print(f"    ⏭️ Skipped {ion_type} ({key_percentage}% CI) - not in requested levels")
            
            # Plot mean PMF line ON TOP (after all confidence bands)
            pmf_line = ax.plot(z_centers, mean_pmf, color=color, linewidth=linewidth, 
                            alpha=line_alpha, label=f'{ion_type} PMF', zorder=3)
            
            # Add to legend tracking
            legend_entries.extend(confidence_intervals_plotted)
            legend_entries.append(f'{ion_type} PMF')
            
            print(f"    ✅ Added PMF line for {ion_type}")
            if confidence_intervals_plotted:
                print(f"    📊 Plotted {len(confidence_intervals_plotted)} confidence intervals")
            else:
                print(f"    ⚠️ No confidence intervals plotted for {ion_type} (none matched requested levels)")
        
        # Add enhanced clay boundaries if requested (adapted from plot_pmf_vs_z)
        if show_clay_boundaries and hasattr(self.analysis.results, 'clay_interface_boundaries'):
            clay_boundaries = self.analysis.results.clay_interface_boundaries
            
            # Apply symmetrization logic (same as plot_clay_interface_boundaries)
            sym_boundaries = None
            if symmetrize_boundaries:
                upper_clay_avg = clay_boundaries.get('clay_average_z_positive')
                lower_clay_avg = clay_boundaries.get('clay_average_z_negative')
                
                # Handle None values for clay boundaries
                if upper_clay_avg is not None and lower_clay_avg is not None:
                    clay_avg = (abs(upper_clay_avg) + abs(lower_clay_avg)) / 2
                    clay_std = abs(abs(upper_clay_avg) - abs(lower_clay_avg)) / 2
                elif upper_clay_avg is not None:
                    clay_avg = abs(upper_clay_avg)
                    clay_std = 0.0
                elif lower_clay_avg is not None:
                    clay_avg = abs(lower_clay_avg)
                    clay_std = 0.0
                else:
                    clay_avg = None
                    clay_std = 0.0
                
                # Handle Si boundaries
                upper_si = clay_boundaries.get('si_average_z_positive')
                lower_si = clay_boundaries.get('si_average_z_negative')
                
                if upper_si is not None and lower_si is not None:
                    si_avg = (abs(upper_si) + abs(lower_si)) / 2
                    si_std = abs(abs(upper_si) - abs(lower_si)) / 2
                elif upper_si is not None:
                    si_avg = abs(upper_si)
                    si_std = 0.0
                elif lower_si is not None:
                    si_avg = abs(lower_si)
                    si_std = 0.0
                else:
                    si_avg = None
                    si_std = 0.0
                
                # Handle Mg boundaries - WITH PERIODIC BOUNDARY CORRECTION
                upper_mgo = clay_boundaries.get('mgo_average_z_positive')
                lower_mgo = clay_boundaries.get('mgo_average_z_negative')
                
                # Apply periodic boundary correction for Mg atoms only
                if upper_mgo is None and lower_mgo is not None:
                    upper_mgo = -lower_mgo  # Use opposite sign
                elif lower_mgo is None and upper_mgo is not None:
                    lower_mgo = -upper_mgo  # Use opposite sign
                
                if upper_mgo is not None and lower_mgo is not None:
                    mgo_avg = (abs(upper_mgo) + abs(lower_mgo)) / 2
                    mgo_std = abs(abs(upper_mgo) - abs(lower_mgo)) / 2
                elif upper_mgo is not None:
                    mgo_avg = abs(upper_mgo)
                    mgo_std = 0.0
                elif lower_mgo is not None:
                    mgo_avg = abs(lower_mgo)
                    mgo_std = 0.0
                else:
                    mgo_avg = None
                    mgo_std = 0.0
                
                sym_boundaries = {
                    'clay_avg': clay_avg,
                    'si_avg': si_avg,
                    'mgo_avg': mgo_avg,
                    'clay_std': clay_std,
                    'si_std': si_std,
                    'mgo_std': mgo_std
                }
            
            # Enhanced boundary styles with individual control (adapted from plot_clay_interface_boundaries)
            if symmetrize_boundaries and sym_boundaries is not None:
                # Symmetrized boundaries
                if sym_boundaries['clay_avg'] is not None:
                    ax.axvline(sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Clay Avg (±{sym_boundaries["clay_avg"]:.2f} Å)')
                    ax.axvline(-sym_boundaries['clay_avg'], color=upper_clay_avg_color, 
                            linestyle=upper_clay_avg_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                if sym_boundaries['si_avg'] is not None:
                    ax.axvline(sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Si Layer (±{sym_boundaries["si_avg"]:.2f} Å)')
                    ax.axvline(-sym_boundaries['si_avg'], color=upper_si_color, 
                            linestyle=upper_si_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                if sym_boundaries['mgo_avg'] is not None:
                    ax.axvline(sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=1.5, 
                            alpha=0.8, label=f'Mg Layer (±{sym_boundaries["mgo_avg"]:.2f} Å)')
                    ax.axvline(-sym_boundaries['mgo_avg'], color=upper_mgo_color, 
                            linestyle=upper_mgo_linestyle, linewidth=1.5, 
                            alpha=0.8)
                
                # Show asymmetry shading if requested
                if show_asymmetry_std:
                    if sym_boundaries['clay_avg'] is not None:
                        ax.axvspan(sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                                sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                                alpha=0.1, color=upper_clay_avg_color)
                        ax.axvspan(-sym_boundaries['clay_avg'] - sym_boundaries['clay_std'], 
                                -sym_boundaries['clay_avg'] + sym_boundaries['clay_std'],
                                alpha=0.1, color=upper_clay_avg_color)
                    
                    if sym_boundaries['si_avg'] is not None:
                        ax.axvspan(sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                                sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                                alpha=0.1, color=upper_si_color)
                        ax.axvspan(-sym_boundaries['si_avg'] - sym_boundaries['si_std'], 
                                -sym_boundaries['si_avg'] + sym_boundaries['si_std'],
                                alpha=0.1, color=upper_si_color)
                    
                    if sym_boundaries['mgo_avg'] is not None:
                        ax.axvspan(sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                                sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                                alpha=0.1, color=upper_mgo_color)
                        ax.axvspan(-sym_boundaries['mgo_avg'] - sym_boundaries['mgo_std'], 
                                -sym_boundaries['mgo_avg'] + sym_boundaries['mgo_std'],
                                alpha=0.1, color=upper_mgo_color)
                
                # Fill clay regions (symmetrized)
                if clay_fill_color and sym_boundaries['si_avg'] is not None and sym_boundaries['mgo_avg'] is not None:
                    ax.axvspan(sym_boundaries['si_avg'], sym_boundaries['mgo_avg'], 
                            color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
                    ax.axvspan(-sym_boundaries['mgo_avg'], -sym_boundaries['si_avg'], 
                            color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
            
            else:
                # Original boundaries with periodic boundary correction
                plot_boundaries = clay_boundaries.copy()
                
                # Apply periodic boundary correction for Mg atoms
                upper_mgo_orig = clay_boundaries.get('mgo_average_z_positive')
                lower_mgo_orig = clay_boundaries.get('mgo_average_z_negative')
                
                if upper_mgo_orig is None and lower_mgo_orig is not None:
                    plot_boundaries['mgo_average_z_positive'] = -lower_mgo_orig
                elif lower_mgo_orig is None and upper_mgo_orig is not None:
                    plot_boundaries['mgo_average_z_negative'] = -upper_mgo_orig
                
                # Enhanced boundary styles
                boundary_styles = {
                    'clay_average_z_positive': (upper_clay_avg_linestyle, upper_clay_avg_color, 0.8, 'Upper Clay Avg'),
                    'si_average_z_positive': (upper_si_linestyle, upper_si_color, 0.8, 'Upper Si'),
                    'mgo_average_z_positive': (upper_mgo_linestyle, upper_mgo_color, 0.8, 'Upper MgO'),
                    'clay_average_z_negative': (lower_clay_avg_linestyle, lower_clay_avg_color, 0.8, 'Lower Clay Avg'),
                    'si_average_z_negative': (lower_si_linestyle, lower_si_color, 0.8, 'Lower Si'),
                    'mgo_average_z_negative': (lower_mgo_linestyle, lower_mgo_color, 0.8, 'Lower MgO')
                }
                
                for boundary_key, (linestyle, color, alpha, label) in boundary_styles.items():
                    if boundary_key in plot_boundaries and plot_boundaries[boundary_key] is not None:
                        boundary_z = plot_boundaries[boundary_key]
                        ax.axvline(boundary_z, color=color, linestyle=linestyle, 
                                alpha=alpha, linewidth=1.5, label=f'{label} ({boundary_z:.2f} Å)')
                
                # Fill clay regions using corrected boundaries
                if clay_fill_color:
                    upper_si = plot_boundaries.get('si_average_z_positive')
                    upper_mgo = plot_boundaries.get('mgo_average_z_positive')
                    lower_si = plot_boundaries.get('si_average_z_negative')
                    lower_mgo = plot_boundaries.get('mgo_average_z_negative')
                    
                    # Fill upper clay region: from Si to MgO
                    if upper_si is not None and upper_mgo is not None:
                        ax.axvspan(upper_si, upper_mgo, 
                                color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
                    
                    # Fill lower clay region: from MgO to Si  
                    if lower_si is not None and lower_mgo is not None:
                        ax.axvspan(lower_mgo, lower_si,
                                color=clay_fill_color, alpha=clay_fill_alpha, zorder=0)
        
        # Formatting
        ax.set_xlabel('z (Å)', fontsize=label_fontsize)
        ax.set_ylabel('PMF (kJ/mol)', fontsize=label_fontsize)
        
        # Add title only if show_title is True
        if show_title:
            ax.set_title('PMF with Bootstrap Uncertainty Bands', fontsize=title_fontsize, fontweight='bold')
        
        # Set axis limits if provided
        if x_min is not None or x_max is not None:
            current_xlim = ax.get_xlim()
            new_xlim = (x_min if x_min is not None else current_xlim[0],
                    x_max if x_max is not None else current_xlim[1])
            ax.set_xlim(new_xlim)
        
        if y_min is not None or y_max is not None:
            current_ylim = ax.get_ylim()
            new_ylim = (y_min if y_min is not None else current_ylim[0],
                    y_max if y_max is not None else current_ylim[1])
            ax.set_ylim(new_ylim)
        
        # Grid
        if show_grid:
            ax.grid(True, alpha=grid_alpha)
        
        # Legend - Only show if show_legend is True AND we have legend entries
        if show_legend and legend_entries:
            ax.legend(fontsize=legend_fontsize, frameon=False, loc='best')
            print(f"    ✅ Legend created with entries: {legend_entries}")
        elif not show_legend:
            print(f"    ⚠️ Legend disabled by show_legend=False")
        else:
            print(f"    ⚠️ No legend entries found")
        
        # Tick formatting
        ax.tick_params(axis='both', which='major', labelsize=tick_fontsize)
        
        # Add zero line for reference
        ax.axhline(0, color='black', linestyle='--', alpha=0.5, linewidth=1)
        ax.axvline(0, color='black', linestyle=':', alpha=0.5, linewidth=1)
        
        plt.tight_layout()
        
        # Save plot
        if save_plots:
            plt.savefig(filename, dpi=dpi, bbox_inches='tight')
            print(f"✅ Plot saved as: {filename}")
        
        plt.show()
        
        # Enhanced summary
        print(f"\n=== PMF Bootstrap Uncertainty Analysis Summary ===")
        print(f"Ion types: {ion_types}")
        print(f"Requested confidence levels: {confidence_levels}")
        print(f"Confidence levels plotted: {[entry for entry in legend_entries if 'CI' in entry]}")
        print(f"Legend displayed: {show_legend and bool(legend_entries)}")
        print(f"Title displayed: {show_title}")
        if show_clay_boundaries:
            print(f"Clay boundaries: ENABLED")
            if symmetrize_boundaries:
                print(f"Boundary symmetrization: {symmetrize_method} method")
                if show_asymmetry_std:
                    print(f"Asymmetry shading: ENABLED")
            if clay_fill_color:
                print(f"Clay fill: {clay_fill_color} (α={clay_fill_alpha}) - Uses actual Si-MgO boundaries")
        
        return fig, ax

        
