    def plot_water_structure_analysis(self, save_plots=True, figsize=None, filename=None, 
                                    z_min=None, z_max=None, show_bulk_references=True,
                                    highlight_interfaces=False, bin_width=None, 
                                    recalculate_if_needed=False):
        '''
        Plot water structure analysis results with optional z-range control and bin width
        
        Parameters
        ----------
        save_plots : bool
            Whether to save the plot
        figsize : tuple
            Figure size (width, height)
        filename : str
            Output filename for saved plot
        z_min : float, optional
            Minimum z-value to display (Å)
        z_max : float, optional
            Maximum z-value to display (Å)
        show_bulk_references : bool
            Whether to show reference lines for bulk water values
        highlight_interfaces : bool
            Whether to highlight detected interface regions
        bin_width : float, optional
            Bin width for z-direction analysis (Å). If provided and different from
            current analysis, will trigger recalculation if recalculate_if_needed=True
        recalculate_if_needed : bool
            Whether to recalculate analysis if bin_width is different
        '''
        
        self._validate_analysis()
        
        # Check if water structure data exists
        if not hasattr(self.analysis.results, 'water_structure') or self.analysis.results.water_structure is None:
            print("No water structure data available. Running calculation...")
            
            # Use provided bin_width or default
            if bin_width is not None:
                self.analysis.bin_width = bin_width
            
            self.analysis.calculate_water_structure_vs_z_detailed()
            
            if not hasattr(self.analysis.results, 'water_structure') or self.analysis.results.water_structure is None:
                print("Failed to calculate water structure data.")
                return
        
        # Check if recalculation is needed due to different bin_width
        elif bin_width is not None and recalculate_if_needed:
            current_bin_width = getattr(self.analysis, 'bin_width', 1.0)  # Default fallback
            if abs(bin_width - current_bin_width) > 0.01:  # Small tolerance for float comparison
                print(f"Recalculating water structure with new bin width: {bin_width:.2f} Å (was {current_bin_width:.2f} Å)")
                self.analysis.bin_width = bin_width
                self.analysis.calculate_water_structure_vs_z_detailed(force_rerun=True)
        
        figsize = figsize or (15, 12)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        struct_data = self.analysis.results.water_structure
        z_centers = struct_data['z_centers']
        
        # Display current bin width info
        current_bin_width = getattr(self.analysis, 'bin_width', 1.0)
        print(f"Using bin width: {current_bin_width:.2f} Å")
        
        # Determine z-range for plotting
        if z_min is None:
            z_min = z_centers.min()
        if z_max is None:
            z_max = z_centers.max()
        
        # Error handling for empty data ranges
        data_in_range = np.any((z_centers >= z_min) & (z_centers <= z_max))
        if not data_in_range:
            print(f"Warning: No data points in the specified z-range ({z_min:.1f} to {z_max:.1f} Å)")
            print(f"Available z-range: {z_centers.min():.1f} to {z_centers.max():.1f} Å")
            return
        
        print(f"Plotting z-range: {z_min:.1f} to {z_max:.1f} Å")
        
        # Plot 1: Tetrahedral order parameter
        ax1 = axes[0, 0]
        tetrahedral_order = struct_data['tetrahedral_order']
        valid_mask = (struct_data['water_counts'] > 0) & (tetrahedral_order > 0)
        
        if np.any(valid_mask):
            ax1.plot(z_centers[valid_mask], tetrahedral_order[valid_mask], 'b-', 
                    linewidth=2, marker='o', markersize=4)
            ax1.set_xlabel('z (Å)')
            ax1.set_ylabel('Tetrahedral Order Parameter')
            ax1.set_title(f'Water Tetrahedral Order vs Z (bin={current_bin_width:.1f}Å)', fontweight='bold')
            ax1.set_xlim(z_min, z_max)
            ax1.grid(True, alpha=0.3)
            ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            if show_bulk_references:
                ax1.axhline(1.0, color='r', linestyle='--', alpha=0.5, label='Perfect tetrahedral')
                ax1.axhline(0.7, color='orange', linestyle=':', alpha=0.7, 
                        label='Typical bulk (~0.7)')
                ax1.legend()
            else:
                ax1.axhline(1.0, color='r', linestyle='--', alpha=0.5, label='Perfect tetrahedral')
                ax1.legend()
        
        # Plot 2: Hydrogen bonds per water
        ax2 = axes[0, 1]
        hbonds = struct_data['hydrogen_bonds_per_water']
        
        if np.any(valid_mask):
            ax2.plot(z_centers[valid_mask], hbonds[valid_mask], 'r-', 
                    linewidth=2, marker='s', markersize=4)
            ax2.set_xlabel('z (Å)')
            ax2.set_ylabel('H-bonds per Water')
            ax2.set_title(f'Hydrogen Bonding vs Z (bin={current_bin_width:.1f}Å)', fontweight='bold')
            ax2.set_xlim(z_min, z_max)
            ax2.grid(True, alpha=0.3)
            ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            if show_bulk_references:
                ax2.axhline(4.0, color='g', linestyle='--', alpha=0.5, label='Ideal bulk (4.0)')
                ax2.axhline(3.8, color='orange', linestyle=':', alpha=0.7, 
                        label='Typical bulk (~3.8)')
                ax2.legend()
            else:
                ax2.axhline(4.0, color='g', linestyle='--', alpha=0.5, label='Ideal bulk (4.0)')
                ax2.legend()
        
        # Plot 3: Water coordination number
        ax3 = axes[1, 0]
        coord_num = struct_data['water_coordination_number']
        
        if np.any(valid_mask):
            ax3.plot(z_centers[valid_mask], coord_num[valid_mask], 'g-', 
                    linewidth=2, marker='^', markersize=4)
            ax3.set_xlabel('z (Å)')
            ax3.set_ylabel('Coordination Number')
            ax3.set_title(f'Water Coordination Number vs Z (bin={current_bin_width:.1f}Å)', fontweight='bold')
            ax3.set_xlim(z_min, z_max)
            ax3.grid(True, alpha=0.3)
            ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            if show_bulk_references:
                ax3.axhline(4.5, color='orange', linestyle=':', alpha=0.7,
                        label='Bulk coordination (~4.5)')
                ax3.legend()
        
        # Plot 4: Water count per layer
        ax4 = axes[1, 1]
        water_counts = struct_data['water_counts']
        
        ax4.plot(z_centers, water_counts, 'purple', linewidth=2, marker='d', markersize=4)
        ax4.set_xlabel('z (Å)')
        ax4.set_ylabel('Water Count')
        ax4.set_title(f'Water Molecules per Layer (bin={current_bin_width:.1f}Å)', fontweight='bold')
        ax4.set_xlim(z_min, z_max)
        ax4.grid(True, alpha=0.3)
        ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Optional: highlight interface regions
        if highlight_interfaces and hasattr(self.analysis.results, 'interfaces'):
            interfaces = self.analysis.results.interfaces
            interface_plotted = False
            for start, end in interfaces['all_interfaces']:
                if start >= z_min and end <= z_max:
                    for ax in axes.flat:
                        ax.axvspan(start, end, alpha=0.2, color='yellow', 
                                label='Interface' if not interface_plotted else "")
                    interface_plotted = True
            
            if interface_plotted:
                axes[0, 0].legend()
        
        plt.tight_layout()
        
        # Save with bin width and z-range info if custom values are used
        if save_plots:
            filename_parts = []
            if filename is None:
                filename_parts.append('water_structure_analysis')
                if bin_width is not None:
                    filename_parts.append(f'bin{bin_width:.1f}A')
                if z_min != z_centers.min() or z_max != z_centers.max():
                    filename_parts.append(f'z{z_min:.0f}to{z_max:.0f}')
                filename = '_'.join(filename_parts) + '.png'
            
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Water structure analysis plot saved as: {filename}")
        
        plt.show()
        
        # Print summary for displayed range
        if np.any(valid_mask):
            range_mask = (z_centers >= z_min) & (z_centers <= z_max) & valid_mask
            if np.any(range_mask):
                print(f"\nWater Structure Analysis Summary (z: {z_min:.1f} to {z_max:.1f} Å, bin: {current_bin_width:.1f} Å):")
                print(f"  Mean tetrahedral order: {np.mean(tetrahedral_order[range_mask]):.3f}")
                print(f"  Mean H-bonds per water: {np.mean(hbonds[range_mask]):.2f}")
                print(f"  Mean coordination number: {np.mean(coord_num[range_mask]):.2f}")
            else:
                print(f"No valid data in the specified z-range: {z_min:.1f} to {z_max:.1f} Å")
        
        # Print summary for displayed range only
        if np.any(valid_mask):
            # Filter data to displayed range
            range_mask = (z_centers >= z_min) & (z_centers <= z_max) & valid_mask
            if np.any(range_mask):
                print(f"\nWater Structure Analysis Summary (z: {z_min:.1f} to {z_max:.1f} Å):")
                print(f"  Mean tetrahedral order: {np.mean(tetrahedral_order[range_mask]):.3f}")
                print(f"  Mean H-bonds per water: {np.mean(hbonds[range_mask]):.2f}")
                print(f"  Mean coordination number: {np.mean(coord_num[range_mask]):.2f}")
                print(f"  Total water molecules in range: {np.sum(water_counts[(z_centers >= z_min) & (z_centers <= z_max)]):.0f}")
                
                # Additional insights
                interface_order = np.mean(tetrahedral_order[(z_centers >= -10) & (z_centers <= 10) & valid_mask])
                bulk_order = np.mean(tetrahedral_order[np.abs(z_centers) > 15][valid_mask[np.abs(z_centers) > 15]])
                
                if not np.isnan(interface_order) and not np.isnan(bulk_order):
                    print(f"  Interface order (±10 Å): {interface_order:.3f}")
                    print(f"  Bulk order (>15 Å): {bulk_order:.3f}")
                    print(f"  Order difference: {interface_order - bulk_order:.3f}")
            else:
                print(f"No valid data in the specified z-range: {z_min:.1f} to {z_max:.1f} Å")

    # Convenience methods for common z-ranges
    def plot_water_structure_interface_region(self, interface_width=15.0, **kwargs):
        '''Plot water structure focusing on interface region'''
        return self.plot_water_structure_analysis(
            z_min=-interface_width, z_max=interface_width, **kwargs)

    def plot_water_structure_bulk_region(self, bulk_start=20.0, **kwargs):
        '''Plot water structure focusing on bulk regions'''
        return self.plot_water_structure_analysis(
            z_min=bulk_start, **kwargs)


    def plot_electrostatic_potential_3d_histograms(self, z_indices='all', plot_mode='3d',
                                                save_plots=True, figsize=(15, 10), dpi=300,
                                                
                                                # Individual figure control
                                                save_individual_figures=False,
                                                show_individual_figures=False,
                                                show_combined_figure=True,
                                                individual_figsize=(8, 7),
                                                
                                                # Publication settings
                                                title_fontsize=14,
                                                show_title=True,
                                                label_fontsize=12,
                                                tick_fontsize=10,
                                                colorbar_label_fontsize=11,
                                                
                                                # 3D histogram parameters
                                                bar_alpha=0.7,
                                                colormap='viridis',
                                                threshold_percentile=1,
                                                
                                                # 🆕 NEW: 3D surface parameters
                                                surface_alpha=0.8,
                                                surface_cmap='RdYlBu_r',
                                                surface_lighting=True,
                                                surface_smoothing=True,
                                                surface_smoothing_sigma=1.0,
                                                surface_stride_x=1,
                                                surface_stride_y=1,
                                                surface_linewidth=0,
                                                surface_antialiased=True,
                                                surface_rstride=1,
                                                surface_cstride=1,
                                                
                                                # 2D heatmap parameters (when plot_mode='2d')
                                                cmap='hot',
                                                origin='lower',
                                                interpolation='gaussian',
                                                aspect='equal',
                                                
                                                # Colorbar control
                                                show_colorbar=True,
                                                colorbar_pad=0.02,
                                                colorbar_width='4%',
                                                vmin=None,
                                                vmax=None,
                                                
                                                # Grid and styling
                                                show_grid=True,
                                                grid_alpha=0.3,
                                                
                                                # Combined figure save control
                                                save_combined_figure=False):
        """
        Plot electrostatic potential as 3D histograms, smooth 3D surfaces, or 2D heatmaps
        
        Parameters
        ----------
        z_indices : str or list
            Z-slice indices to plot ('all' or list of indices)
        plot_mode : str, default='3d'
            Plot mode: '3d' for 3D histograms, 'surface' for smooth 3D surfaces, '2d' for 2D heatmaps
        save_plots : bool
            Whether to save plots
        figsize : tuple
            Figure size for combined plot
        dpi : int
            Resolution for saved figures
        
        Individual figure control:
        save_individual_figures : bool, default=False
            Save each z-slice as separate figure
        show_individual_figures : bool, default=False
            Display individual figures interactively
        show_combined_figure : bool, default=True
            Create/show multi-panel combined figure
        individual_figsize : tuple, default=(8, 7)
            Figure size for individual plots
        
        Publication settings:
        title_fontsize : int, default=14
            Font size for titles
        show_title : bool, default=True
            Whether to show titles
        label_fontsize : int, default=12
            Font size for axis labels
        tick_fontsize : int, default=10
            Font size for tick labels
        colorbar_label_fontsize : int, default=11
            Font size for colorbar labels
        
        3D histogram parameters:
        bar_alpha : float, default=0.7
            Transparency of 3D bars
        colormap : str, default='viridis'
            Colormap for 3D bars
        threshold_percentile : float, default=1
            Minimum percentile threshold for showing bars
        
        🆕 NEW 3D surface parameters:
        surface_alpha : float, default=0.8
            Transparency of 3D surface (0-1)
        surface_cmap : str, default='RdYlBu_r'
            Colormap for 3D surface (publication-ready: 'RdYlBu_r', 'coolwarm', 'seismic')
        surface_lighting : bool, default=True
            Enable realistic lighting and shading on surface
        surface_smoothing : bool, default=True
            Apply Gaussian smoothing to surface data for smoother appearance
        surface_smoothing_sigma : float, default=1.0
            Gaussian smoothing parameter (higher = smoother)
        surface_stride_x : int, default=1
            X stride for surface sampling (higher = faster but less detailed)
        surface_stride_y : int, default=1
            Y stride for surface sampling (higher = faster but less detailed)
        surface_linewidth : float, default=0
            Width of surface wireframe lines (0 = no wireframe)
        surface_antialiased : bool, default=True
            Enable antialiasing for smoother surface edges
        surface_rstride : int, default=1
            Row stride for surface mesh
        surface_cstride : int, default=1
            Column stride for surface mesh
        
        2D heatmap parameters:
        cmap : str, default='hot'
            Colormap for 2D heatmaps
        origin : str, default='lower'
            Origin for 2D plots
        interpolation : str, default='gaussian'
            Interpolation for 2D plots
        aspect : str, default='equal'
            Aspect ratio for 2D plots
        
        Colorbar control:
        show_colorbar : bool, default=True
            Whether to show colorbars
        colorbar_pad : float, default=0.02
            Padding between plot and colorbar
        colorbar_width : str, default='4%'
            Width of colorbar
        vmin, vmax : float, optional
            Color scale limits
        
        Grid and styling:
        show_grid : bool, default=True
            Show grid lines (2D mode only)
        grid_alpha : float, default=0.3
            Grid transparency
        
        save_combined_figure : bool, default=False
            Whether to save combined figure independently
        """
        
        # Check if electrostatic potential data exists
        if not hasattr(self.analysis.results, 'electrostatic_potential_xy'):
            print("❌ No electrostatic potential XY data found!")
            print("   Please run calculate_electrostatic_potential_spatial_distribution_xy() first")
            return None
        
        potential_data = self.analysis.results.electrostatic_potential_xy
        
        # Check required keys
        if 'z_slices' not in potential_data:
            print("❌ Missing required key 'z_slices' in potential data!")
            return None
        
        z_slices = potential_data['z_slices']
        
        if not z_slices:
            print("❌ No z-slice data available in electrostatic_potential_xy")
            return None
        
        # Get available z-centers from the slices
        available_z_centers = [slice_data['z_center'] for slice_data in z_slices]
        
        # Determine which z-slices to plot
        if z_indices == 'all':
            z_indices_to_plot = list(range(len(available_z_centers)))
        elif isinstance(z_indices, (list, tuple)):
            z_indices_to_plot = z_indices
        else:
            z_indices_to_plot = [z_indices]
        
        # Validate indices
        z_indices_to_plot = [i for i in z_indices_to_plot if 0 <= i < len(available_z_centers)]
        
        if not z_indices_to_plot:
            print("❌ No valid z-indices to plot!")
            return None
        
        print(f"\n🎨 Plotting electrostatic potential ({plot_mode}) for {len(z_indices_to_plot)} z-slices")
        
        # Determine color scale from all data
        all_grids = []
        for z_idx in z_indices_to_plot:
            slice_data = z_slices[z_idx]
            if 'negative_potential_grid' in slice_data:
                all_grids.append(slice_data['negative_potential_grid'])
        
        if not all_grids:
            print("❌ No negative potential grids found!")
            return None
        
        # Calculate color scale
        if vmin is None:
            vmin = min(np.min(grid) for grid in all_grids)
        if vmax is None:
            vmax = max(np.max(grid) for grid in all_grids)
        
        print(f"📊 Color scale: {vmin:.4f} to {vmax:.4f}")
        
        # Function to create single plot
        def create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_index):
            """Helper function to create single electrostatic potential plot"""
            
            if plot_mode == '3d':
                # 3D histogram mode
                from mpl_toolkits.mplot3d import Axes3D
                
                # Create meshgrid for bar positions
                X, Y = np.meshgrid(x_centers, y_centers)
                
                # Flatten arrays for bar3d
                x_flat = X.flatten()
                y_flat = Y.flatten()
                z_flat = np.zeros_like(x_flat)  # Base of bars at z=0
                heights = potential_grid.flatten()
                
                # Apply threshold
                threshold = np.percentile(heights, threshold_percentile)
                mask = heights > threshold
                
                if np.any(mask):
                    # Bar dimensions
                    dx = x_centers[1] - x_centers[0] if len(x_centers) > 1 else 1.0
                    dy = y_centers[1] - y_centers[0] if len(y_centers) > 1 else 1.0
                    
                    # Create 3D bars
                    bars = ax.bar3d(x_flat[mask], y_flat[mask], z_flat[mask],
                                dx, dy, heights[mask],
                                alpha=bar_alpha, cmap=colormap)
                    
                    # Set color mapping
                    colors = plt.cm.get_cmap(colormap)(
                        (heights[mask] - vmin) / (vmax - vmin) if vmax > vmin else np.zeros_like(heights[mask])
                    )
                    
                    # Apply colors to bars
                    # for bar, color in zip(bars, colors):
                    #     bar.set_color(color)
                    bars.set_facecolors(colors)
                    
                # Set labels for 3D
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize)
                
                # Set box aspect ratio
                ax.set_box_aspect([1, 1, 0.5])
                
                return None  # No colorbar for 3D mode in this implementation
            
            elif plot_mode == 'surface':
                # 🆕 NEW: 3D smooth surface mode
                from mpl_toolkits.mplot3d import Axes3D
                from scipy.ndimage import gaussian_filter
                
                # Apply smoothing if requested
                if surface_smoothing:
                    smoothed_grid = gaussian_filter(potential_grid, sigma=surface_smoothing_sigma)
                    print(f"    Applied surface smoothing (σ={surface_smoothing_sigma:.1f})")
                else:
                    smoothed_grid = potential_grid
                
                # Create meshgrid
                X, Y = np.meshgrid(x_centers, y_centers)
                
                # Create smooth 3D surface using plot_surface
                surf = ax.plot_surface(X, Y, smoothed_grid, 
                                    cmap=surface_cmap,
                                    alpha=surface_alpha,
                                    vmin=vmin, vmax=vmax,
                                    rstride=surface_rstride,
                                    cstride=surface_cstride,
                                    linewidth=surface_linewidth,
                                    antialiased=surface_antialiased,
                                    shade=surface_lighting)
                
                # 🔧 FIX 2: REMOVE GRAY GRID BACKGROUND - make panes transparent
                # ax.invert_xaxis()
                ax.xaxis.pane.fill = False
                ax.yaxis.pane.fill = False
                ax.zaxis.pane.fill = False
                
                # Optional: Also make grid lines more subtle or remove them
                ax.xaxis.pane.set_edgecolor('white')
                ax.yaxis.pane.set_edgecolor('white')  
                ax.zaxis.pane.set_edgecolor('white')
                ax.xaxis.pane.set_alpha(0)
                ax.yaxis.pane.set_alpha(0)
                ax.zaxis.pane.set_alpha(0)


                # Set labels for 3D surface
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize)
                
                # Set box aspect ratio for better visualization
                ax.set_box_aspect([1, 1, 0.6])
                
                # Optimize viewing angle for publication
                ax.view_init(elev=30, azim=45)
                
                # Return surface object for colorbar
                return surf
            
            else:
                # 2D heatmap mode
                x_extent = [x_centers[0], x_centers[-1]]
                y_extent = [y_centers[0], y_centers[-1]]
                
                im = ax.imshow(potential_grid, cmap=cmap, vmin=vmin, vmax=vmax,
                            origin=origin, interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha)
                
                # Set labels for 2D
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                
                return im
        
        # Save and/or show individual figures
        if save_individual_figures or show_individual_figures:
            print(f"📄 Processing individual figures...")
            
            for idx, z_idx in enumerate(z_indices_to_plot):
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                print(f"  Individual figure {idx + 1}/{len(z_indices_to_plot)}: z = {z_center:.2f} Å")
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"    ⚠️ No negative potential grid for z-slice {z_idx}")
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                # Create single figure
                if plot_mode == '3d' or plot_mode == 'surface':
                    fig_single = plt.figure(figsize=individual_figsize)
                    ax_single = fig_single.add_subplot(111, projection='3d')
                else:
                    fig_single, ax_single = plt.subplots(figsize=individual_figsize)
                
                im = create_single_potential_plot(ax_single, potential_grid, x_centers, y_centers, z_center, idx)
                
                # Add title
                if show_title:
                    title = f'Electrostatic Potential: z = {z_center:.2f} Å'
                    ax_single.set_title(title, fontsize=title_fontsize)
                
                # Tick formatting
                ax_single.tick_params(labelsize=tick_fontsize)
                
                # Add colorbar 
                if show_colorbar and im is not None:
                    if plot_mode == 'surface':
                        # For 3D surfaces, use fig.colorbar
                        cbar = fig_single.colorbar(im, ax=ax_single, shrink=0.6, aspect=20)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                    elif plot_mode == '2d':
                        # For 2D mode
                        from mpl_toolkits.axes_grid1 import make_axes_locatable
                        divider = make_axes_locatable(ax_single)
                        cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar = plt.colorbar(im, cax=cax)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                
                plt.tight_layout()
                
                # Save individual figure
                if save_individual_figures:
                    individual_filename = f'electrostatic_potential_{plot_mode}_z{z_center:.1f}A_individual.png'
                    plt.savefig(individual_filename, dpi=dpi, bbox_inches='tight')
                    print(f"    ✅ Saved: {individual_filename}")
                
                # Show individual figure
                if show_individual_figures:
                    plt.show()
                else:
                    plt.close(fig_single)
        
        # Create combined figure
        if show_combined_figure:
            print(f"📊 Creating combined figure...")
            
            n_plots = len(z_indices_to_plot)
            if n_plots == 1:
                if plot_mode == '3d' or plot_mode == 'surface':
                    fig = plt.figure(figsize=figsize)
                    ax = fig.add_subplot(111, projection='3d')
                    axes = [ax]
                else:
                    fig, ax = plt.subplots(figsize=figsize)
                    axes = [ax]
            else:
                ncols = min(3, n_plots)
                nrows = (n_plots - 1) // ncols + 1
                
                if plot_mode == '3d' or plot_mode == 'surface':
                    fig = plt.figure(figsize=figsize)
                    axes = []
                    for i in range(n_plots):
                        ax = fig.add_subplot(nrows, ncols, i+1, projection='3d')
                        axes.append(ax)
                else:
                    fig, axes = plt.subplots(nrows, ncols, figsize=figsize)
                    if n_plots > 1:
                        axes = axes.flatten() if hasattr(axes, 'flatten') else [axes]
            
            # Plot each z-slice
            for plot_idx, z_idx in enumerate(z_indices_to_plot):
                if plot_idx >= len(axes):
                    break
                    
                ax = axes[plot_idx]
                
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"⚠️ No negative potential grid for z-slice {z_idx} (z={z_center:.2f})")
                    ax.text(0.5, 0.5, f'No data for z={z_center:.2f}Å', 
                        ha='center', va='center', transform=ax.transAxes)
                    if show_title:
                        ax.set_title(f'z = {z_center:.2f} Å')
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                im = create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_idx)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    ax.set_title(title, fontsize=title_fontsize)
                
                # Tick formatting
                ax.tick_params(labelsize=tick_fontsize)
                
                # Add colorbar for 2D mode only (3D surface colorbars are handled separately)
                if show_colorbar and plot_mode == '2d' and im is not None:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
            
            # Hide extra subplots
            if n_plots > 1 and len(axes) > n_plots:
                for i in range(n_plots, len(axes)):
                    if hasattr(axes[i], 'remove'):
                        axes[i].remove()
                    else:
                        axes[i].axis('off')
            
            plt.tight_layout()
            
            # Save combined figure
            if save_combined_figure:
                combined_filename = f'electrostatic_potential_{plot_mode}_COMBINED.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved combined: {combined_filename}")
            
            plt.show()
        else:
            print("Skipping combined figure (show_combined_figure=False)")
        
        # Summary
        print(f"\n=== Electrostatic Potential {plot_mode.upper()} Summary ===")
        print(f"  Z-slices plotted: {len(z_indices_to_plot)}")
        print(f"  Available z-centers: {[f'{z:.1f}' for z in available_z_centers]}")
        print(f"  Plot mode: {plot_mode}")
        print(f"  Color range: {vmin:.4f} to {vmax:.4f}")
        print(f"  Individual figures saved: {save_individual_figures}")
        print(f"  Combined figure saved: {save_combined_figure}")
        
        if plot_mode == '3d':
            print(f"  3D parameters: alpha={bar_alpha}, colormap={colormap}")
            print(f"  Threshold percentile: {threshold_percentile}%")
        elif plot_mode == 'surface':
            print(f"  3D Surface parameters: alpha={surface_alpha}, colormap={surface_cmap}")
            print(f"  Surface smoothing: {'ON' if surface_smoothing else 'OFF'} (σ={surface_smoothing_sigma})")
            print(f"  Surface lighting: {'ON' if surface_lighting else 'OFF'}")
        else:
            print(f"  2D parameters: cmap={cmap}, interpolation={interpolation}")
        
        print(f"  Note: Higher bars/intensity = more negative potential = stronger negative charge")
        
        return fig


