    #         azim = azimuth if azimuth is not None else 45
    #         print(f"  Viewing angles: elevation={elev}, azimuth={azim}")
    #     else:
    #         print(f"  2D parameters: cmap={cmap}, interpolation={interpolation}")
        
    #     print(f"  Note: Higher bars/intensity = more negative potential = stronger negative charge")
    #     if overlay_clay_contours:
    #         print(f"        Clay contours show substrate structure at XY plane")
    #     if show_si_network or show_mgo_atoms:
    #         print(f"        Clay atoms show hexagonal surface pattern")
        
    #     return fig


    def plot_electrostatic_potential_3d_histograms_flipped3(self, z_indices='all', plot_mode='3d',
                                                save_plots=True, figsize=(15, 10), dpi=300,
                                                
                                                # Individual figure control
                                                save_individual_figures=False,
                                                show_individual_figures=False,
                                                show_combined_figure=True,
                                                individual_figsize=(8, 7),
                                                
                                                # Publication settings
                                                title_fontsize=14,
                                                show_title=True,
                                                label_fontsize=12,
                                                tick_fontsize=10,
                                                colorbar_label_fontsize=11,
                                                
                                                # 3D histogram parameters
                                                bar_alpha=0.7,
                                                colormap='viridis',
                                                threshold_percentile=1,
                                                
                                                # 3D surface parameters
                                                surface_alpha=0.8,
                                                surface_cmap='RdYlBu_r',
                                                surface_lighting=True,
                                                surface_smoothing=True,
                                                surface_smoothing_sigma=1.0,
                                                surface_stride_x=1,
                                                surface_stride_y=1,
                                                surface_linewidth=0,
                                                surface_antialiased=True,
                                                surface_rstride=1,
                                                surface_cstride=1,
                                                elevation=None,
                                                azimuth=None,
                                                
                                                # 2D heatmap parameters
                                                cmap='hot',
                                                origin='lower',
                                                interpolation='gaussian',
                                                aspect='equal',
                                                
                                                # Colorbar control
                                                show_colorbar=True,
                                                colorbar_pad=0.02,
                                                colorbar_width='4%',
                                                vmin=None,
                                                vmax=None,
                                                
                                                # Separate Z-axis and colorbar scaling control
                                                z_scale_factor=None,
                                                z_axis_limit=None,
                                                colorbar_vmin=None,
                                                colorbar_vmax=None,
                                                
                                                # Grid and styling
                                                show_grid=True,
                                                grid_alpha=0.3,
                                                
                                                # Combined figure save control
                                                save_combined_figure=False,
                                                
                                                # Clay overlay parameters
                                                overlay_clay_contours=False,
                                                clay_contour_results=None,
                                                clay_surface_offset=None,
                                                mg_contour_color='white',
                                                mg_contour_alpha=0.3,
                                                mg_contour_levels=5,
                                                mg_contour_linewidth=1,
                                                mg_texture_intensity=0.2,
                                                clay_z_tolerance=5.0,
                                                
                                                # Si network and Mg atom overlay parameters
                                                show_si_network=False,
                                                show_mgo_atoms=False,
                                                show_si_atoms=False,
                                                mg_vdw_scaling=2.0,
                                                si_vdw_scaling=1.0,
                                                si_connection_threshold=4.5,
                                                si_color='orange',
                                                si_connection_alpha=0.6,
                                                si_connection_linewidth=1.2,
                                                si_connection_style='lines',
                                                show_hexagonal_pattern=True,
                                                si_center_alpha=0.8,
                                                si_atom_alpha=0.6,
                                                si_radial_fade=True,
                                                si_fade_alpha_min=0.1,
                                                si_fade_alpha_max=0.8,
                                                mgo_color='darkgreen',
                                                mgo_atom_alpha=0.6,
                                                mgo_radial_fade=True,
                                                fade_alpha_min=0.1,
                                                fade_alpha_max=0.8):
        """
        Plot electrostatic potential as 3D histograms, smooth 3D surfaces, or 2D heatmaps
        with clay contours and enhanced Si/Mg atom styling
        """
        # Check if electrostatic potential data exists
        if not hasattr(self.analysis.results, 'electrostatic_potential_xy'):
            print("❌ No electrostatic potential XY data found!")
            print("   Please run calculate_electrostatic_potential_spatial_distribution_xy() first")
            return None
        
        potential_data = self.analysis.results.electrostatic_potential_xy
        
        # Check required keys
        if 'z_slices' not in potential_data:
            print("❌ Missing required key 'z_slices' in potential data!")
            return None
        
        z_slices = potential_data['z_slices']
        
        if not z_slices:
            print("❌ No z-slice data available in electrostatic_potential_xy")
            return None
        
        # Get available z-centers from the slices
        available_z_centers = [slice_data['z_center'] for slice_data in z_slices]
        
        # Determine which z-slices to plot
        if z_indices == 'all':
            z_indices_to_plot = list(range(len(available_z_centers)))
        elif isinstance(z_indices, (list, tuple)):
            z_indices_to_plot = z_indices
        else:
            z_indices_to_plot = [z_indices]
        
        # Validate indices
        z_indices_to_plot = [i for i in z_indices_to_plot if 0 <= i < len(available_z_centers)]
        
        if not z_indices_to_plot:
            print("❌ No valid z-indices to plot!")
            return None
        
        print(f"\n🎨 Plotting electrostatic potential ({plot_mode}) for {len(z_indices_to_plot)} z-slices")
        if overlay_clay_contours:
            print(f"🧱 Clay contour overlay: ENABLED")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"🔸 Clay atom overlays: Si network={show_si_network}, Si atoms={show_si_atoms}, Mg atoms={show_mgo_atoms}")
        
        # Determine color scale from all data
        all_grids = []
        for z_idx in z_indices_to_plot:
            slice_data = z_slices[z_idx]
            if 'negative_potential_grid' in slice_data:
                all_grids.append(slice_data['negative_potential_grid'])
        
        if not all_grids:
            print("❌ No negative potential grids found!")
            return None
        
        # Calculate separate scales for Z-axis and colorbar
        data_min = min(np.min(grid) for grid in all_grids)
        data_max = max(np.max(grid) for grid in all_grids)
        
        # Z-axis scaling (for geometric display)
        if vmin is None:
            vmin = data_min
        if vmax is None:
            vmax = data_max
        
        # Colorbar scaling (for color mapping - independent of geometric height)
        colorbar_vmin_actual = colorbar_vmin if colorbar_vmin is not None else vmin
        colorbar_vmax_actual = colorbar_vmax if colorbar_vmax is not None else vmax
        
        print(f"📊 Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"🎨 Colorbar scale: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"📏 Z-axis scaling factor: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"📏 Z-axis limit: {z_axis_limit}")
        
        # GET CLAY ATOM POSITIONS for overlays
        si_positions = None
        mgo_positions = None
        
        if show_si_network or show_mgo_atoms or show_si_atoms:
            try:
                if show_si_network or show_si_atoms:
                    si_atoms = self.analysis.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
                    if len(si_atoms) > 0:
                        si_positions = si_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            si_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(si_atoms)} Si atoms")
                
                if show_mgo_atoms:
                    mgo_atoms = self.analysis.universe.select_atoms("resname MMT and (name Mgo or name MGO or name Mg or name MG)")
                    if len(mgo_atoms) > 0:
                        mgo_positions = mgo_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            mgo_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(mgo_atoms)} Mg atoms")
                            
            except Exception as e:
                print(f"Warning: Could not load clay atoms: {e}")
                show_si_network = False
                show_mgo_atoms = False
                show_si_atoms = False
        
        # VdW radii (Angstroms)
        BASE_MG_RADIUS = 0.72  # Mg VdW radius
        BASE_SI_RADIUS = 1.11   # Si VdW radius
        
        # CLAY ATOM OVERLAY FUNCTIONS WITH ENHANCED STYLING
        def add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Mg atoms using direct atom positions with visual clipping"""
            if not show_mgo_atoms or mgo_positions is None or len(mgo_positions) == 0:
                return
            
            # Filter Mg atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = mgo_positions[:, 2] >= 0
            else:
                region_mask = mgo_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(mgo_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            mg_positions = mgo_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_MG_RADIUS * mg_vdw_scaling
            
            print(f"   🟢 Adding {len(mg_positions)} Mg atoms (radius: {scaled_radius:.2f}Å)")
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            for mg_pos in mg_positions:
                x, y = mg_pos[0], mg_pos[1]
                
                if not is_3d:
                    # Skip if center is completely outside bounds (2D mode)
                    if (x + scaled_radius < x_min or x - scaled_radius > x_max or 
                        y + scaled_radius < y_min or y - scaled_radius > y_max):
                        continue
                
                if mgo_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(fade_alpha_max, fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=mgo_color, alpha=alpha,
                                    marker='o', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=mgo_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=mgo_color, alpha=mgo_atom_alpha,
                                marker='o', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=mgo_color, alpha=mgo_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)

        def add_si_network_fixed(ax, z_center, is_3d=False):
            """Add Si atoms connected by lines using direct atom positions with visual clipping"""
            if not show_si_network or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_pos = si_positions[final_mask]
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            print(f"   🟠 Adding Si network: {len(si_pos)} atoms, threshold: {si_connection_threshold:.1f}Å")
            
            si_array = si_pos[:, :2]  # Only XY coordinates
            
            # Draw connections between nearby Si atoms (with clipping)
            for i in range(len(si_array)):
                for j in range(i+1, len(si_array)):
                    distance = np.linalg.norm(si_array[i] - si_array[j])
                    
                    if distance < si_connection_threshold:
                        x_coords = [si_array[i][0], si_array[j][0]]
                        y_coords = [si_array[i][1], si_array[j][1]]
                        
                        if not is_3d:
                            # Check if connection line intersects with plot area (2D mode)
                            line_x_min, line_x_max = min(x_coords), max(x_coords)
                            line_y_min, line_y_max = min(y_coords), max(y_coords)
                            
                            line_in_bounds = (
                                line_x_max >= x_min and line_x_min <= x_max and
                                line_y_max >= y_min and line_y_min <= y_max
                            )
                            
                            if not line_in_bounds:
                                continue
                        
                        # CREATE 3D OR 2D LINE WITH VISUAL CLIPPING
                        if is_3d:
                            # For 3D surface plots, create 3D lines at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            z_coords = [z_base, z_base]
                            
                            if si_connection_style == 'lines':
                                linestyle = '-'
                            elif si_connection_style == 'dashed':
                                linestyle = '--'
                            elif si_connection_style == 'dotted':
                                linestyle = ':'
                            else:
                                linestyle = '-'
                            
                            # Plot 3D line
                            ax.plot(x_coords, y_coords, z_coords,
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=linestyle,
                                    zorder=3)
                        else:
                            # For 2D plots
                            if si_connection_style == 'lines':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, zorder=3)[0]
                            elif si_connection_style == 'dashed':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle='--', zorder=3)[0]
                            elif si_connection_style == 'dotted':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=':', zorder=3)[0]
                            
                            # Apply visual clipping to line
                            line.set_clip_box(ax.bbox)
            
            # Show Si atom centers if requested
            if show_hexagonal_pattern:
                if is_3d:
                    # For 3D surface plots, create 3D scatter points at base plane
                    z_base = 0.0  # Place at z=0 base plane
                    z_coords = [z_base] * len(si_array)
                    ax.scatter(si_array[:, 0], si_array[:, 1], z_coords, 
                            s=25, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                else:
                    # For 2D plots
                    scatter = ax.scatter(si_array[:, 0], si_array[:, 1], 
                            s=20, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                    scatter.set_clip_box(ax.bbox)

        def add_vdw_si_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Si atoms using direct atom positions with visual clipping"""
            if not show_si_atoms or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_atom_positions = si_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_SI_RADIUS * si_vdw_scaling
            
            print(f"   🔷 Adding {len(si_atom_positions)} Si atoms (radius: {scaled_radius:.2f}Å)")
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            for si_pos in si_atom_positions:
                x, y = si_pos[0], si_pos[1]
                
                if not is_3d:
                    # Skip if center is completely outside bounds (2D mode)
                    if (x + scaled_radius < x_min or x - scaled_radius > x_max or 
                        y + scaled_radius < y_min or y - scaled_radius > y_max):
                        continue
                
                if si_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(si_fade_alpha_max, si_fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=si_color, alpha=alpha,
                                    marker='s', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=si_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=si_color, alpha=si_atom_alpha,
                                marker='s', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=si_color, alpha=si_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)

        def _add_clay_contour_overlay(ax, z_center, is_3d=False, clay_offset=None, potential_surface=None):
            """Add clay atom contours with intelligent base positioning"""
            if not overlay_clay_contours or clay_contour_results is None:
                print(f"    ⚠️ Clay contours disabled or no clay results")
                return
            
            if not clay_contour_results.get('z_slices'):
                print(f"    ⚠️ No z_slices in clay_contour_results")
                return
            
            print(f"    🧱 Adding clay contours for z={z_center:.1f}Å (3D mode: {is_3d})...")
            
            # Find best matching clay slice
            best_clay_slice = None
            min_distance = float('inf')
            
            for clay_slice in clay_contour_results['z_slices']:
                clay_z_center = clay_slice.get('z_center')
                if clay_z_center is not None:
                    distance = abs(clay_z_center - z_center)
                    if distance <= clay_z_tolerance and distance < min_distance:
                        min_distance = distance
                        best_clay_slice = clay_slice
            
            if best_clay_slice is None:
                print(f"    ❌ No clay slice found within tolerance {clay_z_tolerance}Å of z={z_center:.1f}Å")
                return
            
            print(f"    ✓ Using clay slice at z={best_clay_slice['z_center']:.1f}Å (distance: {min_distance:.1f}Å)")
            
            # Try different possible grid names
            clay_grid = None
            grid_name = None
            possible_grid_names = ['mg_grid', 'combined_grid', 'si_grid', 'clay_grid', 'grid']
            
            for name in possible_grid_names:
                if name in best_clay_slice and best_clay_slice[name] is not None:
                    clay_grid = best_clay_slice[name]
                    grid_name = name
                    print(f"    ✓ Found clay grid: '{name}' with shape {clay_grid.shape}")
                    break
            
            if clay_grid is None:
                print(f"    ❌ No valid clay grid found. Available keys: {list(best_clay_slice.keys())}")
                return
            
            # Get coordinate arrays
            if 'x_centers' not in best_clay_slice or 'y_centers' not in best_clay_slice:
                print(f"    ❌ Missing coordinate arrays in clay slice")
                return
            
            x_centers = best_clay_slice['x_centers']
            y_centers = best_clay_slice['y_centers']
            
            if np.max(clay_grid) == 0:
                print(f"    ⚠️ Clay grid is all zeros - no contours to draw")
                return
            
            # Transform clay coordinates to match electrostatic coordinates
            x_clay_transformed = x_centers - x_centers.min()
            y_clay_transformed = y_centers - y_centers.min()
            
            # Create meshgrid for contouring with transformed coordinates
            X, Y = np.meshgrid(x_clay_transformed, y_clay_transformed)
            
            # Calculate proper base plane for each figure
            if clay_offset is not None:
                if potential_surface is not None:
                    surface_min = np.min(potential_surface)
                    z_base_level = surface_min + clay_offset
                    print(f"    Using surface offset: clay_offset={clay_offset}, surface_min={surface_min:.3f}, z_base={z_base_level:.3f}")
                else:
                    z_base_level = clay_offset
                    print(f"    Using direct offset: clay_offset={clay_offset}, z_base={z_base_level:.3f}")
            elif is_3d and potential_surface is not None:
                surface_min = np.min(potential_surface)
                surface_max = np.max(potential_surface)
                z_base_level = surface_min - 0.1 * (surface_max - surface_min)
                print(f"    Using calculated base: surface_min={surface_min:.3f}, z_base={z_base_level:.3f}")
            elif is_3d:
                z_base_level = -0.05 * abs(z_center) if z_center != 0 else -0.01
                print(f"    Using fallback base: z_base={z_base_level:.3f}")
            else:
                z_base_level = 0.0
                print(f"    Using 2D base: z=0")
            
            # Calculate contour levels
            non_zero_values = clay_grid[clay_grid > 0]
            if len(non_zero_values) == 0:
                print(f"    ⚠️ No non-zero values in clay grid")
                return
            
            if mg_contour_levels == 1:
                levels = [np.mean(non_zero_values)]
            else:
                levels = np.linspace(np.min(non_zero_values), 
                                    np.max(non_zero_values), 
                                    mg_contour_levels)
            
            print(f"    Contour levels: {levels[:3]}...{levels[-3:]} ({len(levels)} total)")
            
            try:
                if is_3d:
                    # For 3D surface plots, add contours at the calculated base plane
                    Z_base = np.full_like(X, z_base_level)
                    
                    # Add clay density contours at base level
                    for level in levels:
                        level_mask = clay_grid >= level
                        if np.any(level_mask):
                            level_grid = np.zeros_like(clay_grid)
                            level_grid[level_mask] = 1.0
                            
                            Z_level = Z_base + level_grid * mg_texture_intensity * 0.0001
                            
                            ax.contour(X, Y, Z_level, 
                                    levels=[z_base_level + mg_texture_intensity * 0.0001 * 0.5],
                                    colors=[mg_contour_color],
                                    alpha=mg_contour_alpha * 0.7,
                                    linewidths=mg_contour_linewidth)
                    
                    print(f"    ✅ Added clay contours at z={z_base_level:.3f} with {len(levels)} levels")
                    
                else:
                    # For 2D plots, add regular contours with transformed coordinates
                    ax.contour(X, Y, clay_grid, 
                            levels=levels,
                            colors=[mg_contour_color],
                            alpha=mg_contour_alpha,
                            linewidths=mg_contour_linewidth)
                    
                    print(f"    ✅ Added 2D clay contours with {len(levels)} levels")
                    
            except Exception as e:
                print(f"    ❌ Error creating contours: {e}")
                import traceback
                traceback.print_exc()

        # Function to create single plot
        def create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_index):
            """Helper function to create single electrostatic potential plot"""
            
            if plot_mode == '3d':
                # 3D histogram mode
                from mpl_toolkits.mplot3d import Axes3D
                
                # Create meshgrid for bar positions - use original coordinates
                X, Y = np.meshgrid(x_centers, y_centers)
                
                # DON'T flip the data - keep it as is
                potential_grid_display = potential_grid
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    potential_grid_scaled = potential_grid_display * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(potential_grid_scaled):.3f})")
                else:
                    potential_grid_scaled = potential_grid_display
                
                # Flatten arrays for bar3d
                x_flat = X.flatten()
                y_flat = Y.flatten()
                z_flat = np.zeros_like(x_flat)  # Base of bars at z=0
                heights = potential_grid_scaled.flatten()
                
                # Apply threshold
                threshold = np.percentile(heights, threshold_percentile)
                mask = heights > threshold
                
                if np.any(mask):
                    # Bar dimensions
                    dx = x_centers[1] - x_centers[0] if len(x_centers) > 1 else 1.0
                    dy = y_centers[1] - y_centers[0] if len(y_centers) > 1 else 1.0
                    
                    # Create 3D bars
                    bars = ax.bar3d(x_flat[mask], y_flat[mask], z_flat[mask],
                                dx, dy, heights[mask],
                                alpha=bar_alpha, cmap=colormap)
                    
                    # Set color mapping using ORIGINAL data range (not scaled heights)
                    original_heights = potential_grid_display.flatten()[mask]
                    colors = plt.cm.get_cmap(colormap)(
                        (original_heights - colorbar_vmin_actual) / (colorbar_vmax_actual - colorbar_vmin_actual) 
                        if colorbar_vmax_actual > colorbar_vmin_actual else np.zeros_like(original_heights)
                    )
                    
                    # Apply colors to bars
                    bars.set_facecolors(colors)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions
                x_display_min = x_centers.min() - x_centers.min()  # Start from 0
                x_display_max = x_centers.max() - x_centers.min()
                y_display_min = y_centers.min() - y_centers.min()  # Start from 0
                y_display_max = y_centers.max() - y_centers.min()
                
                ax.set_xlim(x_display_min, x_display_max)
                ax.set_ylim(y_display_min, y_display_max)
                
                print(f"    ✅ Set 3D axis limits BEFORE clay overlay: X=[{x_display_min:.1f}, {x_display_max:.1f}], Y=[{y_display_min:.1f}, {y_display_max:.1f}]")
                
                # Add clay contour overlay at base of 3D plot
                _add_clay_contour_overlay(ax, z_center, is_3d=True, 
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=potential_grid_scaled)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                    
                # Set labels for 3D with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ✅ FIX 2: ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)  # Increase Y tick padding
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)   # Standard X tick padding
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)   # Standard Z tick padding
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio
                ax.set_box_aspect([1, 1, 0.5])
                
                # Set viewing angle if provided
                if elevation is not None or azimuth is not None:
                    elev = elevation if elevation is not None else ax.elev
                    azim = azimuth if azimuth is not None else ax.azim
                    ax.view_init(elev=elev, azim=azim)
                
                return None  # No colorbar for 3D mode in this implementation
            
            elif plot_mode == 'surface':
                # 3D smooth surface mode
                from mpl_toolkits.mplot3d import Axes3D
                from scipy.ndimage import gaussian_filter
                
                # Apply smoothing if requested
                if surface_smoothing:
                    smoothed_grid = gaussian_filter(potential_grid, sigma=surface_smoothing_sigma)
                    print(f"    Applied surface smoothing (σ={surface_smoothing_sigma:.1f})")
                else:
                    smoothed_grid = potential_grid
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    smoothed_grid_scaled = smoothed_grid * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(smoothed_grid_scaled):.3f})")
                else:
                    smoothed_grid_scaled = smoothed_grid
                
                # Create meshgrid - use original coordinates starting from 0
                x_display = x_centers - x_centers.min()  # Start X from 0
                y_display = y_centers - y_centers.min()  # Start Y from 0
                
                X, Y = np.meshgrid(x_display, y_display)
                
                # DON'T flip the data - keep it as is
                smoothed_grid_display = smoothed_grid_scaled  # Use scaled version for height
                
                # Create smooth 3D surface using plot_surface with transformed coordinates
                surf = ax.plot_surface(X, Y, smoothed_grid_display,
                                    cmap=surface_cmap,
                                    alpha=surface_alpha,
                                    vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                                    rstride=surface_rstride,
                                    cstride=surface_cstride,
                                    linewidth=surface_linewidth,
                                    antialiased=surface_antialiased,
                                    shade=surface_lighting)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions
                ax.set_xlim(x_display.min(), x_display.max())
                ax.set_ylim(y_display.min(), y_display.max())
                
                print(f"    ✅ Set surface axis limits BEFORE clay overlay: X=[{x_display.min():.1f}, {x_display.max():.1f}], Y=[{y_display.min():.1f}, {y_display.max():.1f}]")
                
                # Add clay contour overlay at base of 3D plot
                _add_clay_contour_overlay(ax, z_center, is_3d=True, 
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=smoothed_grid_display)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                
                # REMOVE GRAY GRID BACKGROUND - make panes transparent
                ax.invert_xaxis()
                ax.invert_yaxis()
                ax.xaxis.pane.fill = False
                ax.yaxis.pane.fill = False
                ax.zaxis.pane.fill = False
                
                # Optional: Also make grid lines more subtle or remove them
                ax.xaxis.pane.set_edgecolor('white')
                ax.yaxis.pane.set_edgecolor('white')  
                ax.zaxis.pane.set_edgecolor('white')
                ax.xaxis.pane.set_alpha(0)
                ax.yaxis.pane.set_alpha(0)
                ax.zaxis.pane.set_alpha(0)

                # Set labels for 3D surface with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ✅ FIX 2: ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)  # Increase Y tick padding
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)   # Standard X tick padding
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)   # Standard Z tick padding
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio for better visualization
                ax.set_box_aspect([1, 1, 0.6])
                
                # Set viewing angle
                elev = elevation if elevation is not None else 30
                azim = azimuth if azimuth is not None else 45
                ax.view_init(elev=elev, azim=azim)
                
                # Return surface object for colorbar
                return surf
            
            else:
                # 2D heatmap mode
                # Transform coordinates to start from 0
                x_min, x_max = x_centers.min(), x_centers.max()
                y_min, y_max = y_centers.min(), y_centers.max()
                
                # Create extent that starts from 0
                x_extent = [0, x_max - x_min]  # X starts from 0
                y_extent = [0, y_max - y_min]  # Y starts from 0
                
                # DON'T flip the data - display it as is
                im = ax.imshow(potential_grid, cmap=cmap, 
                            vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                            origin='lower',  # This puts (0,0) at bottom-left 
                            interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions
                ax.set_xlim(x_extent[0], x_extent[1])
                ax.set_ylim(y_extent[0], y_extent[1])
                
                print(f"    ✅ Set 2D axis limits BEFORE clay overlay: X=[{x_extent[0]:.1f}, {x_extent[1]:.1f}], Y=[{y_extent[0]:.1f}, {y_extent[1]:.1f}]")
                
                # Add clay contour overlay for 2D plots
                _add_clay_contour_overlay(ax, z_center, is_3d=False,
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=potential_grid)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=False)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=False)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False)
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha)
                
                # Set labels for 2D (normal spacing is fine for 2D)
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                
                return im

        # Save and/or show individual figures
        if save_individual_figures or show_individual_figures:
            print(f"📄 Processing individual figures...")
            
            for idx, z_idx in enumerate(z_indices_to_plot):
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                print(f"  Individual figure {idx + 1}/{len(z_indices_to_plot)}: z = {z_center:.2f} Å")
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"    ⚠️ No negative potential grid for z-slice {z_idx}")
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                # ✅ FIX 3: INCREASE INDIVIDUAL FIGURE SIZE FOR 3D PLOTS TO PREVENT Y-LABEL CROPPING
                if plot_mode == '3d' or plot_mode == 'surface':
                    # Use larger figure size for 3D to accommodate Y-axis labels
                    adjusted_individual_figsize = (individual_figsize[0] * 1.2, individual_figsize[1] * 1.1)
                    fig_single = plt.figure(figsize=adjusted_individual_figsize)
                    ax_single = fig_single.add_subplot(111, projection='3d')
                else:
                    fig_single, ax_single = plt.subplots(figsize=individual_figsize)
                
                im = create_single_potential_plot(ax_single, potential_grid, x_centers, y_centers, z_center, idx)
                
                # Add title
                if show_title:
                    title = f'Electrostatic Potential: z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax_single.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar 
                if show_colorbar and im is not None:
                    if plot_mode == 'surface':
                        # For 3D surfaces, use fig.colorbar with colorbar limits
                        cbar = fig_single.colorbar(im, ax=ax_single, shrink=0.6, aspect=20)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                    elif plot_mode == '2d':
                        # For 2D mode
                        from mpl_toolkits.axes_grid1 import make_axes_locatable
                        divider = make_axes_locatable(ax_single)
                        cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar = plt.colorbar(im, cax=cax)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                
                # ✅ FIX 4: USE plt.subplots_adjust() INSTEAD OF plt.tight_layout() FOR 3D PLOTS
                if plot_mode == '3d' or plot_mode == 'surface':
                    # For 3D plots, use manual spacing to prevent Y-label cropping
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
                else:
                    # For 2D plots, tight_layout works fine
                    plt.tight_layout()
                
                # Save individual figure
                if save_individual_figures:
                    clay_suffix = '_with_clay' if overlay_clay_contours else ''
                    atom_suffix = ''
                    if show_si_network or show_mgo_atoms or show_si_atoms:
                        atom_suffix += '_with_atoms'
                    individual_filename = f'electrostatic_potential_{plot_mode}_z{z_center:.1f}A_individual{clay_suffix}{atom_suffix}.png'
                    plt.savefig(individual_filename, dpi=dpi, bbox_inches='tight')
                    print(f"    ✅ Saved: {individual_filename}")
                
                # Show individual figure
                if show_individual_figures:
                    plt.show()
                else:
                    plt.close(fig_single)

        # Create combined figure
        if show_combined_figure:
            print(f"📊 Creating combined figure...")
            
            n_plots = len(z_indices_to_plot)
            if n_plots == 1:
                if plot_mode == '3d' or plot_mode == 'surface':
                    # ✅ FIX 5: INCREASE COMBINED FIGURE SIZE FOR SINGLE 3D PLOT
                    adjusted_figsize = (figsize[0] * 1.2, figsize[1] * 1.1)
                    fig = plt.figure(figsize=adjusted_figsize)
                    ax = fig.add_subplot(111, projection='3d')
                    axes = [ax]
                else:
                    fig, ax = plt.subplots(figsize=figsize)
                    axes = [ax]
            else:
                ncols = min(3, n_plots)
                nrows = (n_plots - 1) // ncols + 1
                
                if plot_mode == '3d' or plot_mode == 'surface':
                    # ✅ FIX 5: INCREASE COMBINED FIGURE SIZE FOR MULTI-PANEL 3D PLOTS
                    adjusted_figsize = (figsize[0] * 1.3, figsize[1] * 1.2)
                    fig = plt.figure(figsize=adjusted_figsize)
                    axes = []
                    for i in range(n_plots):
                        ax = fig.add_subplot(nrows, ncols, i+1, projection='3d')
                        axes.append(ax)
                else:
                    fig, axes = plt.subplots(nrows, ncols, figsize=figsize)
                    if n_plots > 1:
                        axes = axes.flatten() if hasattr(axes, 'flatten') else [axes]
            
            # Plot each z-slice
            for plot_idx, z_idx in enumerate(z_indices_to_plot):
                if plot_idx >= len(axes):
                    break
                    
                ax = axes[plot_idx]
                
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"⚠️ No negative potential grid for z-slice {z_idx} (z={z_center:.2f})")
                    ax.text(0.5, 0.5, f'No data for z={z_center:.2f}Å', 
                        ha='center', va='center', transform=ax.transAxes)
                    if show_title:
                        ax.set_title(f'z = {z_center:.2f} Å')
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                im = create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_idx)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar for 2D mode only (3D surface colorbars are handled separately)
                if show_colorbar and plot_mode == '2d' and im is not None:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
            
            # Hide extra subplots
            if n_plots > 1 and len(axes) > n_plots:
                for i in range(n_plots, len(axes)):
                    if hasattr(axes[i], 'remove'):
                        axes[i].remove()
                    else:
                        axes[i].axis('off')
            
            # ✅ FIX 6: USE plt.subplots_adjust() FOR COMBINED 3D FIGURES
            if plot_mode == '3d' or plot_mode == 'surface':
                # For 3D multi-panel plots, use manual spacing to prevent overlap
                if n_plots > 1:
                    # More space for multi-panel 3D figures
                    plt.subplots_adjust(left=0.08, right=0.92, bottom=0.08, top=0.92, 
                                    wspace=0.4, hspace=0.3)  # ✅ Increased wspace for Y-label spacing
                else:
                    # Single 3D plot
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
            else:
                # For 2D plots, tight_layout works fine
                plt.tight_layout()
            
            # Save combined figure
            if save_combined_figure:
                clay_suffix = '_with_clay' if overlay_clay_contours else ''
                atom_suffix = ''
                if show_si_network or show_mgo_atoms or show_si_atoms:
                    atom_suffix += '_with_atoms'
                combined_filename = f'electrostatic_potential_{plot_mode}_COMBINED{clay_suffix}{atom_suffix}.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved combined: {combined_filename}")
            
            plt.show()
        else:
            print("Skipping combined figure (show_combined_figure=False)")

        
        # Summary
        print(f"\n=== Electrostatic Potential {plot_mode.upper()} Summary ===")
        print(f"  Z-slices plotted: {len(z_indices_to_plot)}")
        print(f"  Available z-centers: {[f'{z:.1f}' for z in available_z_centers]}")
        print(f"  Plot mode: {plot_mode}")
        print(f"  Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"  Colorbar range: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"  Z-scaling applied: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"  Z-axis limited to: {z_axis_limit}")
        print(f"  Individual figures saved: {save_individual_figures}")
        print(f"  Combined figure saved: {save_combined_figure}")
        
        # Clay overlay summary
        if overlay_clay_contours:
            print(f"\n🧱 Clay Overlay Summary:")
            print(f"  Clay contours: ENABLED")
            print(f"  Contour color: {mg_contour_color}")
            print(f"  Contour levels: {mg_contour_levels}")
            print(f"  Contour alpha: {mg_contour_alpha}")
            print(f"  Texture intensity: {mg_texture_intensity}")
            print(f"  Z-tolerance: {clay_z_tolerance}Å")
        
        # Clay atom overlay summary
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"\n🔸 Clay Atom Overlay Summary:")
            if show_si_network:
                print(f"  Si network: ENABLED")
                print(f"    Connection threshold: {si_connection_threshold}Å")
                print(f"    Color: {si_color}, alpha: {si_connection_alpha}")
                print(f"    Style: {si_connection_style}, linewidth: {si_connection_linewidth}")
                if show_hexagonal_pattern:
                    print(f"    Hexagonal pattern: ENABLED")
            if show_si_atoms:
                print(f"  Si atoms: ENABLED")
                print(f"    VdW scaling: {si_vdw_scaling}x (radius: {BASE_SI_RADIUS * si_vdw_scaling:.2f}Å)")
                print(f"    Color: {si_color}, alpha: {si_atom_alpha}")
                if si_radial_fade:
                    print(f"    Radial fade: ENABLED")
            if show_mgo_atoms:
                print(f"  Mg atoms: ENABLED")
                print(f"    VdW scaling: {mg_vdw_scaling}x (radius: {BASE_MG_RADIUS * mg_vdw_scaling:.2f}Å)")
                print(f"    Color: {mgo_color}, alpha: {mgo_atom_alpha}")
                if mgo_radial_fade:
                    print(f"    Radial fade: ENABLED")
            print(f"  Clay z-tolerance: {clay_z_tolerance}Å")
        
        if plot_mode == '3d':
            print(f"  3D parameters: alpha={bar_alpha}, colormap={colormap}")
            print(f"  Threshold percentile: {threshold_percentile}%")
            if elevation is not None or azimuth is not None:
                print(f"  Viewing angles: elevation={elevation}, azimuth={azimuth}")
        elif plot_mode == 'surface':
            print(f"  3D Surface parameters: alpha={surface_alpha}, colormap={surface_cmap}")
            print(f"  Surface smoothing: {'ON' if surface_smoothing else 'OFF'} (σ={surface_smoothing_sigma})")
            print(f"  Surface lighting: {'ON' if surface_lighting else 'OFF'}")
            elev = elevation if elevation is not None else 30
            azim = azimuth if azimuth is not None else 45
            print(f"  Viewing angles: elevation={elev}, azimuth={azim}")
        else:
            print(f"  2D parameters: cmap={cmap}, interpolation={interpolation}")
        
        print(f"  Note: Higher bars/intensity = more negative potential = stronger negative charge")
        if overlay_clay_contours:
            print(f"        Clay contours show substrate structure at XY plane")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"        Clay atoms show hexagonal surface pattern")
        
        return fig



    def plot_electrostatic_potential_3d_histograms_flipped4(self, z_indices='all', plot_mode='3d',
                                                save_plots=True, figsize=(15, 10), dpi=300,
                                                
                                                # Individual figure control
                                                save_individual_figures=False,
                                                show_individual_figures=False,
                                                show_combined_figure=True,
                                                individual_figsize=(8, 7),
                                                
                                                # Publication settings
                                                title_fontsize=14,
                                                show_title=True,
                                                label_fontsize=12,
                                                tick_fontsize=10,
                                                colorbar_label_fontsize=11,
                                                
                                                # 3D histogram parameters
                                                bar_alpha=0.7,
                                                colormap='viridis',
                                                threshold_percentile=1,
                                                
                                                # 3D surface parameters
                                                surface_alpha=0.8,
                                                surface_cmap='RdYlBu_r',
                                                surface_lighting=True,
                                                surface_smoothing=True,
                                                surface_smoothing_sigma=1.0,
                                                surface_stride_x=1,
                                                surface_stride_y=1,
                                                surface_linewidth=0,
                                                surface_antialiased=True,
                                                surface_rstride=1,
                                                surface_cstride=1,
                                                elevation=None,
                                                azimuth=None,
                                                
                                                # 2D heatmap parameters
                                                cmap='hot',
                                                origin='lower',
                                                interpolation='gaussian',
                                                aspect='equal',
                                                
                                                # Colorbar control
                                                show_colorbar=True,
                                                colorbar_pad=0.02,
                                                colorbar_width='4%',
                                                vmin=None,
                                                vmax=None,
                                                
                                                # Separate Z-axis and colorbar scaling control
                                                z_scale_factor=None,
                                                z_axis_limit=None,
                                                colorbar_vmin=None,
                                                colorbar_vmax=None,
                                                
                                                # Grid and styling
                                                show_grid=True,
                                                grid_alpha=0.3,
                                                
                                                # Combined figure save control
                                                save_combined_figure=False,
                                                
                                                # Clay overlay parameters
                                                overlay_clay_contours=False,
                                                clay_contour_results=None,
                                                clay_surface_offset=None,
                                                mg_contour_color='white',
                                                mg_contour_alpha=0.3,
                                                mg_contour_levels=5,
                                                mg_contour_linewidth=1,
                                                mg_texture_intensity=0.2,
                                                clay_z_tolerance=5.0,
                                                
                                                # Si network and Mg atom overlay parameters
                                                show_si_network=False,
                                                show_mgo_atoms=False,
                                                show_si_atoms=False,
                                                mg_vdw_scaling=2.0,
                                                si_vdw_scaling=1.0,
                                                si_connection_threshold=4.5,
                                                si_color='orange',
                                                si_connection_alpha=0.6,
                                                si_connection_linewidth=1.2,
                                                si_connection_style='lines',
                                                show_hexagonal_pattern=True,
                                                si_center_alpha=0.8,
                                                si_atom_alpha=0.6,
                                                si_radial_fade=True,
                                                si_fade_alpha_min=0.1,
                                                si_fade_alpha_max=0.8,
                                                mgo_color='darkgreen',
                                                mgo_atom_alpha=0.6,
                                                mgo_radial_fade=True,
                                                fade_alpha_min=0.1,
                                                fade_alpha_max=0.8):
        """
        Plot electrostatic potential as 3D histograms, smooth 3D surfaces, or 2D heatmaps
        with clay contours and enhanced Si/Mg atom styling
        """
        # Check if electrostatic potential data exists
        if not hasattr(self.analysis.results, 'electrostatic_potential_xy'):
            print("❌ No electrostatic potential XY data found!")
            print("   Please run calculate_electrostatic_potential_spatial_distribution_xy() first")
            return None
        
        potential_data = self.analysis.results.electrostatic_potential_xy
        
        # Check required keys
        if 'z_slices' not in potential_data:
            print("❌ Missing required key 'z_slices' in potential data!")
            return None
        
        z_slices = potential_data['z_slices']
        
        if not z_slices:
            print("❌ No z-slice data available in electrostatic_potential_xy")
            return None
        
        # Get available z-centers from the slices
        available_z_centers = [slice_data['z_center'] for slice_data in z_slices]
        
        # Determine which z-slices to plot
        if z_indices == 'all':
            z_indices_to_plot = list(range(len(available_z_centers)))
        elif isinstance(z_indices, (list, tuple)):
            z_indices_to_plot = z_indices
        else:
            z_indices_to_plot = [z_indices]
        
        # Validate indices
        z_indices_to_plot = [i for i in z_indices_to_plot if 0 <= i < len(available_z_centers)]
        
        if not z_indices_to_plot:
            print("❌ No valid z-indices to plot!")
            return None
        
        print(f"\n🎨 Plotting electrostatic potential ({plot_mode}) for {len(z_indices_to_plot)} z-slices")
        if overlay_clay_contours:
            print(f"🧱 Clay contour overlay: ENABLED")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"🔸 Clay atom overlays: Si network={show_si_network}, Si atoms={show_si_atoms}, Mg atoms={show_mgo_atoms}")
        
        # Determine color scale from all data
        all_grids = []
        for z_idx in z_indices_to_plot:
            slice_data = z_slices[z_idx]
            if 'negative_potential_grid' in slice_data:
                all_grids.append(slice_data['negative_potential_grid'])
        
        if not all_grids:
            print("❌ No negative potential grids found!")
            return None
        
        # Calculate separate scales for Z-axis and colorbar
        data_min = min(np.min(grid) for grid in all_grids)
        data_max = max(np.max(grid) for grid in all_grids)
        
        # Z-axis scaling (for geometric display)
        if vmin is None:
            vmin = data_min
        if vmax is None:
            vmax = data_max
        
        # Colorbar scaling (for color mapping - independent of geometric height)
        colorbar_vmin_actual = colorbar_vmin if colorbar_vmin is not None else vmin
        colorbar_vmax_actual = colorbar_vmax if colorbar_vmax is not None else vmax
        
        print(f"📊 Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"🎨 Colorbar scale: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"📏 Z-axis scaling factor: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"📏 Z-axis limit: {z_axis_limit}")
        
        # GET CLAY ATOM POSITIONS for overlays
        si_positions = None
        mgo_positions = None
        
        if show_si_network or show_mgo_atoms or show_si_atoms:
            try:
                if show_si_network or show_si_atoms:
                    si_atoms = self.analysis.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
                    if len(si_atoms) > 0:
                        si_positions = si_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            si_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(si_atoms)} Si atoms")
                
                if show_mgo_atoms:
                    mgo_atoms = self.analysis.universe.select_atoms("resname MMT and (name Mgo or name MGO or name Mg or name MG)")
                    if len(mgo_atoms) > 0:
                        mgo_positions = mgo_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            mgo_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(mgo_atoms)} Mg atoms")
                            
            except Exception as e:
                print(f"Warning: Could not load clay atoms: {e}")
                show_si_network = False
                show_mgo_atoms = False
                show_si_atoms = False
        
        # VdW radii (Angstroms)
        BASE_MG_RADIUS = 0.72  # Mg VdW radius
        BASE_SI_RADIUS = 1.11   # Si VdW radius
        
        # CLAY ATOM OVERLAY FUNCTIONS WITH ENHANCED STYLING
        def add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Mg atoms using direct atom positions with visual clipping"""
            if not show_mgo_atoms or mgo_positions is None or len(mgo_positions) == 0:
                return
            
            # Filter Mg atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = mgo_positions[:, 2] >= 0
            else:
                region_mask = mgo_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(mgo_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            mg_positions = mgo_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_MG_RADIUS * mg_vdw_scaling
            
            print(f"   🟢 Adding {len(mg_positions)} Mg atoms (radius: {scaled_radius:.2f}Å)")
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            for mg_pos in mg_positions:
                x, y = mg_pos[0], mg_pos[1]
                
                if not is_3d:
                    # Skip if center is completely outside bounds (2D mode)
                    if (x + scaled_radius < x_min or x - scaled_radius > x_max or 
                        y + scaled_radius < y_min or y - scaled_radius > y_max):
                        continue
                
                if mgo_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(fade_alpha_max, fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=mgo_color, alpha=alpha,
                                    marker='o', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=mgo_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=mgo_color, alpha=mgo_atom_alpha,
                                marker='o', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=mgo_color, alpha=mgo_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)

        def add_si_network_fixed(ax, z_center, is_3d=False):
            """Add Si atoms connected by lines using direct atom positions with visual clipping"""
            if not show_si_network or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_pos = si_positions[final_mask]
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            print(f"   🟠 Adding Si network: {len(si_pos)} atoms, threshold: {si_connection_threshold:.1f}Å")
            
            si_array = si_pos[:, :2]  # Only XY coordinates
            
            # Draw connections between nearby Si atoms (with clipping)
            for i in range(len(si_array)):
                for j in range(i+1, len(si_array)):
                    distance = np.linalg.norm(si_array[i] - si_array[j])
                    
                    if distance < si_connection_threshold:
                        x_coords = [si_array[i][0], si_array[j][0]]
                        y_coords = [si_array[i][1], si_array[j][1]]
                        
                        if not is_3d:
                            # Check if connection line intersects with plot area (2D mode)
                            line_x_min, line_x_max = min(x_coords), max(x_coords)
                            line_y_min, line_y_max = min(y_coords), max(y_coords)
                            
                            line_in_bounds = (
                                line_x_max >= x_min and line_x_min <= x_max and
                                line_y_max >= y_min and line_y_min <= y_max
                            )
                            
                            if not line_in_bounds:
                                continue
                        
                        # CREATE 3D OR 2D LINE WITH VISUAL CLIPPING
                        if is_3d:
                            # For 3D surface plots, create 3D lines at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            z_coords = [z_base, z_base]
                            
                            if si_connection_style == 'lines':
                                linestyle = '-'
                            elif si_connection_style == 'dashed':
                                linestyle = '--'
                            elif si_connection_style == 'dotted':
                                linestyle = ':'
                            else:
                                linestyle = '-'
                            
                            # Plot 3D line
                            ax.plot(x_coords, y_coords, z_coords,
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=linestyle,
                                    zorder=3)
                        else:
                            # For 2D plots
                            if si_connection_style == 'lines':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, zorder=3)[0]
                            elif si_connection_style == 'dashed':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle='--', zorder=3)[0]
                            elif si_connection_style == 'dotted':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=':', zorder=3)[0]
                            
                            # Apply visual clipping to line
                            line.set_clip_box(ax.bbox)
            
            # Show Si atom centers if requested
            if show_hexagonal_pattern:
                if is_3d:
                    # For 3D surface plots, create 3D scatter points at base plane
                    z_base = 0.0  # Place at z=0 base plane
                    z_coords = [z_base] * len(si_array)
                    ax.scatter(si_array[:, 0], si_array[:, 1], z_coords, 
                            s=25, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                else:
                    # For 2D plots
                    scatter = ax.scatter(si_array[:, 0], si_array[:, 1], 
                            s=20, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                    scatter.set_clip_box(ax.bbox)

        def add_vdw_si_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Si atoms using direct atom positions with visual clipping"""
            if not show_si_atoms or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_atom_positions = si_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_SI_RADIUS * si_vdw_scaling
            
            print(f"   🔷 Adding {len(si_atom_positions)} Si atoms (radius: {scaled_radius:.2f}Å)")
            
            if not is_3d:
                # GET AXIS LIMITS FOR CLIPPING (2D mode)
                x_min, x_max = ax.get_xlim()
                y_min, y_max = ax.get_ylim()
            
            for si_pos in si_atom_positions:
                x, y = si_pos[0], si_pos[1]
                
                if not is_3d:
                    # Skip if center is completely outside bounds (2D mode)
                    if (x + scaled_radius < x_min or x - scaled_radius > x_max or 
                        y + scaled_radius < y_min or y - scaled_radius > y_max):
                        continue
                
                if si_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(si_fade_alpha_max, si_fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=si_color, alpha=alpha,
                                    marker='s', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=si_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=si_color, alpha=si_atom_alpha,
                                marker='s', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=si_color, alpha=si_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)

        def _add_clay_contour_overlay(ax, z_center, is_3d=False, clay_offset=None, potential_surface=None):
            """Add clay atom contours with intelligent base positioning"""
            if not overlay_clay_contours or clay_contour_results is None:
                print(f"    ⚠️ Clay contours disabled or no clay results")
                return
            
            if not clay_contour_results.get('z_slices'):
                print(f"    ⚠️ No z_slices in clay_contour_results")
                return
            
            print(f"    🧱 Adding clay contours for z={z_center:.1f}Å (3D mode: {is_3d})...")
            
            # Find best matching clay slice
            best_clay_slice = None
            min_distance = float('inf')
            
            for clay_slice in clay_contour_results['z_slices']:
                clay_z_center = clay_slice.get('z_center')
                if clay_z_center is not None:
                    distance = abs(clay_z_center - z_center)
                    if distance <= clay_z_tolerance and distance < min_distance:
                        min_distance = distance
                        best_clay_slice = clay_slice
            
            if best_clay_slice is None:
                print(f"    ❌ No clay slice found within tolerance {clay_z_tolerance}Å of z={z_center:.1f}Å")
                return
            
            print(f"    ✓ Using clay slice at z={best_clay_slice['z_center']:.1f}Å (distance: {min_distance:.1f}Å)")
            
            # Try different possible grid names
            clay_grid = None
            grid_name = None
            possible_grid_names = ['mg_grid', 'combined_grid', 'si_grid', 'clay_grid', 'grid']
            
            for name in possible_grid_names:
                if name in best_clay_slice and best_clay_slice[name] is not None:
                    clay_grid = best_clay_slice[name]
                    grid_name = name
                    print(f"    ✓ Found clay grid: '{name}' with shape {clay_grid.shape}")
                    break
            
            if clay_grid is None:
                print(f"    ❌ No valid clay grid found. Available keys: {list(best_clay_slice.keys())}")
                return
            
            # Get coordinate arrays
            if 'x_centers' not in best_clay_slice or 'y_centers' not in best_clay_slice:
                print(f"    ❌ Missing coordinate arrays in clay slice")
                return
            
            x_centers = best_clay_slice['x_centers']
            y_centers = best_clay_slice['y_centers']
            
            if np.max(clay_grid) == 0:
                print(f"    ⚠️ Clay grid is all zeros - no contours to draw")
                return
            
            # Transform clay coordinates to match electrostatic coordinates
            x_clay_transformed = x_centers - x_centers.min()
            y_clay_transformed = y_centers - y_centers.min()
            
            # Create meshgrid for contouring with transformed coordinates
            X, Y = np.meshgrid(x_clay_transformed, y_clay_transformed)
            
            # Calculate proper base plane for each figure
            if clay_offset is not None:
                if potential_surface is not None:
                    surface_min = np.min(potential_surface)
                    z_base_level = surface_min + clay_offset
                    print(f"    Using surface offset: clay_offset={clay_offset}, surface_min={surface_min:.3f}, z_base={z_base_level:.3f}")
                else:
                    z_base_level = clay_offset
                    print(f"    Using direct offset: clay_offset={clay_offset}, z_base={z_base_level:.3f}")
            elif is_3d and potential_surface is not None:
                surface_min = np.min(potential_surface)
                surface_max = np.max(potential_surface)
                z_base_level = surface_min - 0.1 * (surface_max - surface_min)
                print(f"    Using calculated base: surface_min={surface_min:.3f}, z_base={z_base_level:.3f}")
            elif is_3d:
                z_base_level = -0.05 * abs(z_center) if z_center != 0 else -0.01
                print(f"    Using fallback base: z_base={z_base_level:.3f}")
            else:
                z_base_level = 0.0
                print(f"    Using 2D base: z=0")
            
            # Calculate contour levels
            non_zero_values = clay_grid[clay_grid > 0]
            if len(non_zero_values) == 0:
                print(f"    ⚠️ No non-zero values in clay grid")
                return
            
            if mg_contour_levels == 1:
                levels = [np.mean(non_zero_values)]
            else:
                levels = np.linspace(np.min(non_zero_values), 
                                    np.max(non_zero_values), 
                                    mg_contour_levels)
            
            print(f"    Contour levels: {levels[:3]}...{levels[-3:]} ({len(levels)} total)")
            
            try:
                if is_3d:
                    # For 3D surface plots, add contours at the calculated base plane
                    Z_base = np.full_like(X, z_base_level)
                    
                    # Add clay density contours at base level
                    for level in levels:
                        level_mask = clay_grid >= level
                        if np.any(level_mask):
                            level_grid = np.zeros_like(clay_grid)
                            level_grid[level_mask] = 1.0
                            
                            Z_level = Z_base + level_grid * mg_texture_intensity * 0.0001
                            
                            ax.contour(X, Y, Z_level, 
                                    levels=[z_base_level + mg_texture_intensity * 0.0001 * 0.5],
                                    colors=[mg_contour_color],
                                    alpha=mg_contour_alpha * 0.7,
                                    linewidths=mg_contour_linewidth)
                    
                    print(f"    ✅ Added clay contours at z={z_base_level:.3f} with {len(levels)} levels")
                    
                else:
                    # For 2D plots, add regular contours with transformed coordinates
                    ax.contour(X, Y, clay_grid, 
                            levels=levels,
                            colors=[mg_contour_color],
                            alpha=mg_contour_alpha,
                            linewidths=mg_contour_linewidth)
                    
                    print(f"    ✅ Added 2D clay contours with {len(levels)} levels")
                    
            except Exception as e:
                print(f"    ❌ Error creating contours: {e}")
                import traceback
                traceback.print_exc()


        # Function to create single plot
        def create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_index):
            """Helper function to create single electrostatic potential plot"""
            
            if plot_mode == '3d':
                # 3D histogram mode
                from mpl_toolkits.mplot3d import Axes3D
                
                # Create meshgrid for bar positions - use original coordinates
                X, Y = np.meshgrid(x_centers, y_centers)
                
                # DON'T flip the data - keep it as is
                potential_grid_display = potential_grid
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    potential_grid_scaled = potential_grid_display * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(potential_grid_scaled):.3f})")
                else:
                    potential_grid_scaled = potential_grid_display
                
                # Flatten arrays for bar3d
                x_flat = X.flatten()
                y_flat = Y.flatten()
                z_flat = np.zeros_like(x_flat)  # Base of bars at z=0
                heights = potential_grid_scaled.flatten()
                
                # Apply threshold
                threshold = np.percentile(heights, threshold_percentile)
                mask = heights > threshold
                
                if np.any(mask):
                    # Bar dimensions
                    dx = x_centers[1] - x_centers[0] if len(x_centers) > 1 else 1.0
                    dy = y_centers[1] - y_centers[0] if len(y_centers) > 1 else 1.0
                    
                    # Create 3D bars
                    bars = ax.bar3d(x_flat[mask], y_flat[mask], z_flat[mask],
                                dx, dy, heights[mask],
                                alpha=bar_alpha, cmap=colormap)
                    
                    # Set color mapping using ORIGINAL data range (not scaled heights)
                    original_heights = potential_grid_display.flatten()[mask]
                    colors = plt.cm.get_cmap(colormap)(
                        (original_heights - colorbar_vmin_actual) / (colorbar_vmax_actual - colorbar_vmin_actual) 
                        if colorbar_vmax_actual > colorbar_vmin_actual else np.zeros_like(original_heights)
                    )
                    
                    # Apply colors to bars
                    bars.set_facecolors(colors)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions with buffer
                x_display_min = x_centers.min() - x_centers.min()  # Start from 0
                x_display_max = x_centers.max() - x_centers.min()
                y_display_min = y_centers.min() - y_centers.min()  # Start from 0
                y_display_max = y_centers.max() - y_centers.min()
                
                # Add small buffer to axis limits to accommodate contours and clay overlays
                x_buffer = (x_display_max - x_display_min) * 0.02  # 2% buffer
                y_buffer = (y_display_max - y_display_min) * 0.02
                
                ax.set_xlim(x_display_min - x_buffer, x_display_max + x_buffer)
                ax.set_ylim(y_display_min - y_buffer, y_display_max + y_buffer)
                
                print(f"    ✅ Set 3D axis limits with buffer: X=[{x_display_min - x_buffer:.1f}, {x_display_max + x_buffer:.1f}], Y=[{y_display_min - y_buffer:.1f}, {y_display_max + y_buffer:.1f}]")
                
                # Add clay contour overlay at base of 3D plot
                _add_clay_contour_overlay(ax, z_center, is_3d=True, 
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=potential_grid_scaled)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                    
                # Set labels for 3D with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio
                ax.set_box_aspect([1, 1, 0.5])
                
                # Set viewing angle if provided
                if elevation is not None or azimuth is not None:
                    elev = elevation if elevation is not None else ax.elev
                    azim = azimuth if azimuth is not None else ax.azim
                    ax.view_init(elev=elev, azim=azim)
                
                return None  # No colorbar for 3D mode in this implementation
            
            elif plot_mode == 'surface':
                # 3D smooth surface mode
                from mpl_toolkits.mplot3d import Axes3D
                from scipy.ndimage import gaussian_filter
                
                # Apply smoothing if requested
                if surface_smoothing:
                    smoothed_grid = gaussian_filter(potential_grid, sigma=surface_smoothing_sigma)
                    print(f"    Applied surface smoothing (σ={surface_smoothing_sigma:.1f})")
                else:
                    smoothed_grid = potential_grid
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    smoothed_grid_scaled = smoothed_grid * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(smoothed_grid_scaled):.3f})")
                else:
                    smoothed_grid_scaled = smoothed_grid
                
                # Create meshgrid - use original coordinates starting from 0
                x_display = x_centers - x_centers.min()  # Start X from 0
                y_display = y_centers - y_centers.min()  # Start Y from 0
                
                X, Y = np.meshgrid(x_display, y_display)
                
                # DON'T flip the data - keep it as is
                smoothed_grid_display = smoothed_grid_scaled  # Use scaled version for height
                
                # Create smooth 3D surface using plot_surface with transformed coordinates
                surf = ax.plot_surface(X, Y, smoothed_grid_display,
                                    cmap=surface_cmap,
                                    alpha=surface_alpha,
                                    vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                                    rstride=surface_rstride,
                                    cstride=surface_cstride,
                                    linewidth=surface_linewidth,
                                    antialiased=surface_antialiased,
                                    shade=surface_lighting)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions with buffer
                # Add small buffer to axis limits to accommodate contours and clay overlays
                x_buffer = (x_display.max() - x_display.min()) * 0.02  # 2% buffer
                y_buffer = (y_display.max() - y_display.min()) * 0.02
                
                ax.set_xlim(x_display.min() - x_buffer, x_display.max() + x_buffer)
                ax.set_ylim(y_display.min() - y_buffer, y_display.max() + y_buffer)
                
                print(f"    ✅ Set surface axis limits with buffer: X=[{x_display.min() - x_buffer:.1f}, {x_display.max() + x_buffer:.1f}], Y=[{y_display.min() - y_buffer:.1f}, {y_display.max() + y_buffer:.1f}]")
                
                # Add clay contour overlay at base of 3D plot
                _add_clay_contour_overlay(ax, z_center, is_3d=True, 
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=smoothed_grid_display)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                
                # REMOVE GRAY GRID BACKGROUND - make panes transparent
                ax.invert_xaxis()
                ax.invert_yaxis()
                ax.xaxis.pane.fill = False
                ax.yaxis.pane.fill = False
                ax.zaxis.pane.fill = False
                
                # Optional: Also make grid lines more subtle or remove them
                ax.xaxis.pane.set_edgecolor('white')
                ax.yaxis.pane.set_edgecolor('white')  
                ax.zaxis.pane.set_edgecolor('white')
                ax.xaxis.pane.set_alpha(0)
                ax.yaxis.pane.set_alpha(0)
                ax.zaxis.pane.set_alpha(0)

                # Set labels for 3D surface with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio for better visualization
                ax.set_box_aspect([1, 1, 0.6])
                
                # Set viewing angle
                elev = elevation if elevation is not None else 30
                azim = azimuth if azimuth is not None else 45
                ax.view_init(elev=elev, azim=azim)
                
                # Return surface object for colorbar
                return surf
            
            else:
                # 2D heatmap mode
                # Transform coordinates to start from 0
                x_min, x_max = x_centers.min(), x_centers.max()
                y_min, y_max = y_centers.min(), y_centers.max()
                
                # Create extent that starts from 0
                x_extent = [0, x_max - x_min]  # X starts from 0
                y_extent = [0, y_max - y_min]  # Y starts from 0
                
                # DON'T flip the data - display it as is
                im = ax.imshow(potential_grid, cmap=cmap, 
                            vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                            origin='lower',  # This puts (0,0) at bottom-left 
                            interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions with buffer
                # Add small buffer to axis limits to accommodate contours and clay overlays
                x_buffer = (x_extent[1] - x_extent[0]) * 0.02  # 2% buffer
                y_buffer = (y_extent[1] - y_extent[0]) * 0.02
                
                ax.set_xlim(x_extent[0] - x_buffer, x_extent[1] + x_buffer)
                ax.set_ylim(y_extent[0] - y_buffer, y_extent[1] + y_buffer)
                
                print(f"    ✅ Set 2D axis limits with buffer: X=[{x_extent[0] - x_buffer:.1f}, {x_extent[1] + x_buffer:.1f}], Y=[{y_extent[0] - y_buffer:.1f}, {y_extent[1] + y_buffer:.1f}]")
                
                # Add clay contours if requested
                _add_clay_contour_overlay(ax, z_center, is_3d=False,
                                        clay_offset=clay_surface_offset, 
                                        potential_surface=potential_grid)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=False)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=False)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False)
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha)
                
                # Set labels for 2D (normal spacing is fine for 2D)
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                
                return im

        # Save and/or show individual figures
        if save_individual_figures or show_individual_figures:
            print(f"📄 Processing individual figures...")
            
            for idx, z_idx in enumerate(z_indices_to_plot):
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                print(f"  Individual figure {idx + 1}/{len(z_indices_to_plot)}: z = {z_center:.2f} Å")
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"    ⚠️ No negative potential grid for z-slice {z_idx}")
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                # INCREASE INDIVIDUAL FIGURE SIZE FOR 3D PLOTS TO PREVENT Y-LABEL CROPPING
                if plot_mode == '3d' or plot_mode == 'surface':
                    # Use larger figure size for 3D to accommodate Y-axis labels
                    adjusted_individual_figsize = (individual_figsize[0] * 1.2, individual_figsize[1] * 1.1)
                    fig_single = plt.figure(figsize=adjusted_individual_figsize)
                    ax_single = fig_single.add_subplot(111, projection='3d')
                else:
                    fig_single, ax_single = plt.subplots(figsize=individual_figsize)
                
                im = create_single_potential_plot(ax_single, potential_grid, x_centers, y_centers, z_center, idx)
                
                # Add title
                if show_title:
                    title = f'Electrostatic Potential: z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax_single.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar 
                if show_colorbar and im is not None:
                    if plot_mode == 'surface':
                        # For 3D surfaces, use fig.colorbar with colorbar limits
                        cbar = fig_single.colorbar(im, ax=ax_single, shrink=0.6, aspect=20)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                    elif plot_mode == '2d':
                        # For 2D mode
                        from mpl_toolkits.axes_grid1 import make_axes_locatable
                        divider = make_axes_locatable(ax_single)
                        cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar = plt.colorbar(im, cax=cax)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                
                # USE plt.subplots_adjust() INSTEAD OF plt.tight_layout() FOR 3D PLOTS
                if plot_mode == '3d' or plot_mode == 'surface':
                    # For 3D plots, use manual spacing to prevent Y-label cropping
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
                else:
                    # For 2D plots, tight_layout works fine
                    plt.tight_layout()
                
                # Save individual figure
                if save_individual_figures:
                    clay_suffix = '_with_clay' if overlay_clay_contours else ''
                    atom_suffix = ''
                    if show_si_network or show_mgo_atoms or show_si_atoms:
                        atom_suffix += '_with_atoms'
                    individual_filename = f'electrostatic_potential_{plot_mode}_z{z_center:.1f}A_individual{clay_suffix}{atom_suffix}.png'
                    plt.savefig(individual_filename, dpi=dpi, bbox_inches='tight')
                    print(f"    ✅ Saved: {individual_filename}")
                
                # Show individual figure
                if show_individual_figures:
                    plt.show()
                else:
                    plt.close(fig_single)

        # Create combined figure
        if show_combined_figure:
            print(f"📊 Creating combined figure...")
            
            n_plots = len(z_indices_to_plot)
            if n_plots == 1:
                if plot_mode == '3d' or plot_mode == 'surface':
                    # INCREASE COMBINED FIGURE SIZE FOR SINGLE 3D PLOT
                    adjusted_figsize = (figsize[0] * 1.2, figsize[1] * 1.1)
                    fig = plt.figure(figsize=adjusted_figsize)
                    ax = fig.add_subplot(111, projection='3d')
                    axes = [ax]
                else:
                    fig, ax = plt.subplots(figsize=figsize)
                    axes = [ax]
            else:
                ncols = min(3, n_plots)
                nrows = (n_plots - 1) // ncols + 1
                
                if plot_mode == '3d' or plot_mode == 'surface':
                    # INCREASE COMBINED FIGURE SIZE FOR MULTI-PANEL 3D PLOTS
                    adjusted_figsize = (figsize[0] * 1.3, figsize[1] * 1.2)
                    fig = plt.figure(figsize=adjusted_figsize)
                    axes = []
                    for i in range(n_plots):
                        ax = fig.add_subplot(nrows, ncols, i+1, projection='3d')
                        axes.append(ax)
                else:
                    fig, axes = plt.subplots(nrows, ncols, figsize=figsize)
                    if n_plots > 1:
                        axes = axes.flatten() if hasattr(axes, 'flatten') else [axes]
            
            # Plot each z-slice
            for plot_idx, z_idx in enumerate(z_indices_to_plot):
                if plot_idx >= len(axes):
                    break
                    
                ax = axes[plot_idx]
                
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"⚠️ No negative potential grid for z-slice {z_idx} (z={z_center:.2f})")
                    ax.text(0.5, 0.5, f'No data for z={z_center:.2f}Å', 
                        ha='center', va='center', transform=ax.transAxes)
                    if show_title:
                        ax.set_title(f'z = {z_center:.2f} Å')
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                im = create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_idx)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar for 2D mode only (3D surface colorbars are handled separately)
                if show_colorbar and plot_mode == '2d' and im is not None:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
            
            # Hide extra subplots
            if n_plots > 1 and len(axes) > n_plots:
                for i in range(n_plots, len(axes)):
                    if hasattr(axes[i], 'remove'):
                        axes[i].remove()
                    else:
                        axes[i].axis('off')
            
            # USE plt.subplots_adjust() FOR COMBINED 3D FIGURES
            if plot_mode == '3d' or plot_mode == 'surface':
                # For 3D multi-panel plots, use manual spacing to prevent overlap
                if n_plots > 1:
                    # More space for multi-panel 3D figures
                    plt.subplots_adjust(left=0.08, right=0.92, bottom=0.08, top=0.92, 
                                    wspace=0.4, hspace=0.3)  # Increased wspace for Y-label spacing
                else:
                    # Single 3D plot
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
            else:
                # For 2D plots, tight_layout works fine
                plt.tight_layout()
            
            # Save combined figure
            if save_combined_figure:
                clay_suffix = '_with_clay' if overlay_clay_contours else ''
                atom_suffix = ''
                if show_si_network or show_mgo_atoms or show_si_atoms:
                    atom_suffix += '_with_atoms'
                combined_filename = f'electrostatic_potential_{plot_mode}_COMBINED{clay_suffix}{atom_suffix}.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved combined: {combined_filename}")
            
            plt.show()
        else:
            print("Skipping combined figure (show_combined_figure=False)")

        
        # Summary
        print(f"\n=== Electrostatic Potential {plot_mode.upper()} Summary ===")
        print(f"  Z-slices plotted: {len(z_indices_to_plot)}")
        print(f"  Available z-centers: {[f'{z:.1f}' for z in available_z_centers]}")
        print(f"  Plot mode: {plot_mode}")
        print(f"  Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"  Colorbar range: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"  Z-scaling applied: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"  Z-axis limited to: {z_axis_limit}")
        print(f"  Individual figures saved: {save_individual_figures}")
        print(f"  Combined figure saved: {save_combined_figure}")
        
        # Clay overlay summary
        if overlay_clay_contours:
            print(f"\n🧱 Clay Overlay Summary:")
            print(f"  Clay contours: ENABLED")
            print(f"  Contour color: {mg_contour_color}")
            print(f"  Contour levels: {mg_contour_levels}")
            print(f"  Contour alpha: {mg_contour_alpha}")
            print(f"  Texture intensity: {mg_texture_intensity}")
            print(f"  Z-tolerance: {clay_z_tolerance}Å")
        
        # Clay atom overlay summary
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"\n🔸 Clay Atom Overlay Summary:")
            if show_si_network:
                print(f"  Si network: ENABLED")
                print(f"    Connection threshold: {si_connection_threshold}Å")
                print(f"    Color: {si_color}, alpha: {si_connection_alpha}")
                print(f"    Style: {si_connection_style}, linewidth: {si_connection_linewidth}")
                if show_hexagonal_pattern:
                    print(f"    Hexagonal pattern: ENABLED")
            if show_si_atoms:
                print(f"  Si atoms: ENABLED")
                print(f"    VdW scaling: {si_vdw_scaling}x (radius: {BASE_SI_RADIUS * si_vdw_scaling:.2f}Å)")
                print(f"    Color: {si_color}, alpha: {si_atom_alpha}")
                if si_radial_fade:
                    print(f"    Radial fade: ENABLED")
            if show_mgo_atoms:
                print(f"  Mg atoms: ENABLED")
                print(f"    VdW scaling: {mg_vdw_scaling}x (radius: {BASE_MG_RADIUS * mg_vdw_scaling:.2f}Å)")
                print(f"    Color: {mgo_color}, alpha: {mgo_atom_alpha}")
                if mgo_radial_fade:
                    print(f"    Radial fade: ENABLED")
            print(f"  Clay z-tolerance: {clay_z_tolerance}Å")
        
        if plot_mode == '3d':
            print(f"  3D parameters: alpha={bar_alpha}, colormap={colormap}")
            print(f"  Threshold percentile: {threshold_percentile}%")
            if elevation is not None or azimuth is not None:
                print(f"  Viewing angles: elevation={elevation}, azimuth={azimuth}")
        elif plot_mode == 'surface':
            print(f"  3D Surface parameters: alpha={surface_alpha}, colormap={surface_cmap}")
            print(f"  Surface smoothing: {'ON' if surface_smoothing else 'OFF'} (σ={surface_smoothing_sigma})")
            print(f"  Surface lighting: {'ON' if surface_lighting else 'OFF'}")
            elev = elevation if elevation is not None else 30
            azim = azimuth if azimuth is not None else 45
            print(f"  Viewing angles: elevation={elev}, azimuth={azim}")
        else:
            print(f"  2D parameters: cmap={cmap}, interpolation={interpolation}")
        
        print(f"  Note: Higher bars/intensity = more negative potential = stronger negative charge")
        if overlay_clay_contours:
            print(f"        Clay contours show substrate structure at XY plane")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"        Clay atoms show hexagonal surface pattern")
        
        return fig



    def plot_electrostatic_potential_3d_histograms_flipped5(self, z_indices='all', plot_mode='3d',
                                            save_plots=True, figsize=(15, 10), dpi=300,
                                            
                                            # Individual figure control
                                            save_individual_figures=False,
                                            show_individual_figures=False,
                                            show_combined_figure=True,
                                            individual_figsize=(8, 7),
                                            
                                            # Publication settings
                                            title_fontsize=14,
                                            show_title=True,
                                            label_fontsize=12,
                                            tick_fontsize=10,
                                            colorbar_label_fontsize=11,
                                            
                                            # 3D histogram parameters
                                            bar_alpha=0.7,
                                            colormap='viridis',
                                            threshold_percentile=1,
                                            
                                            # 3D surface parameters
                                            surface_alpha=0.8,
                                            surface_cmap='RdYlBu_r',
                                            surface_lighting=True,
                                            surface_smoothing=True,
                                            surface_smoothing_sigma=1.0,
                                            surface_stride_x=1,
                                            surface_stride_y=1,
                                            surface_linewidth=0,
                                            surface_antialiased=True,
                                            surface_rstride=1,
                                            surface_cstride=1,
                                            elevation=None,
                                            azimuth=None,
                                            
                                            # 2D heatmap parameters
                                            cmap='hot',
                                            origin='lower',
                                            interpolation='gaussian',
                                            aspect='equal',
                                            
                                            # Colorbar control
                                            show_colorbar=True,
                                            colorbar_pad=0.02,
                                            colorbar_width='4%',
                                            vmin=None,
                                            vmax=None,
                                            
                                            # Separate Z-axis and colorbar scaling control
                                            z_scale_factor=None,
                                            z_axis_limit=None,
                                            colorbar_vmin=None,
                                            colorbar_vmax=None,
                                            
                                            # Grid and styling
                                            show_grid=True,
                                            grid_alpha=0.3,
                                            
                                            # Combined figure save control
                                            save_combined_figure=False,
                                            
                                            # Clay overlay parameters
                                            overlay_clay_contours=False,
                                            clay_contour_results=None,
                                            clay_surface_offset=None,
                                            mg_contour_color='white',
                                            mg_contour_alpha=0.3,
                                            mg_contour_levels=5,
                                            mg_contour_linewidth=1,
                                            mg_texture_intensity=0.2,
                                            clay_z_tolerance=5.0,
                                            
                                            # Si network and Mg atom overlay parameters
                                            show_si_network=False,
                                            show_mgo_atoms=False,
                                            show_si_atoms=False,
                                            mg_vdw_scaling=2.0,
                                            si_vdw_scaling=1.0,
                                            si_connection_threshold=4.5,
                                            si_color='orange',
                                            si_connection_alpha=0.6,
                                            si_connection_linewidth=1.2,
                                            si_connection_style='lines',
                                            show_hexagonal_pattern=True,
                                            si_center_alpha=0.8,
                                            si_atom_alpha=0.6,
                                            si_radial_fade=True,
                                            si_fade_alpha_min=0.1,
                                            si_fade_alpha_max=0.8,
                                            mgo_color='darkgreen',
                                            mgo_atom_alpha=0.6,
                                            mgo_radial_fade=True,
                                            fade_alpha_min=0.1,
                                            fade_alpha_max=0.8,
                                            
                                            # Buffer control parameters
                                            buffer_2d=False,
                                            buffer_3d=True):
        """
        Plot electrostatic potential as 3D histograms, smooth 3D surfaces, or 2D heatmaps
        with clay contours, enhanced Si/Mg atom styling, and FIXED Y-AXIS LABEL SPACING
        
        Parameters
        ----------
        buffer_2d : bool, default=False
            Whether to add axis buffers for 2D plots (prevents clay overlay clipping)
        buffer_3d : bool, default=True  
            Whether to add axis buffers for 3D plots (prevents clay overlay clipping)
        """
        # Check if electrostatic potential data exists
        if not hasattr(self.analysis.results, 'electrostatic_potential_xy'):
            print("❌ No electrostatic potential XY data found!")
            print("   Please run calculate_electrostatic_potential_spatial_distribution_xy() first")
            return None
        
        potential_data = self.analysis.results.electrostatic_potential_xy
        
        # Check required keys
        if 'z_slices' not in potential_data:
            print("❌ Missing required key 'z_slices' in potential data!")
            return None
        
        z_slices = potential_data['z_slices']
        
        if not z_slices:
            print("❌ No z-slice data available in electrostatic_potential_xy")
            return None
        
        # Get available z-centers from the slices
        available_z_centers = [slice_data['z_center'] for slice_data in z_slices]
        
        # Determine which z-slices to plot
        if z_indices == 'all':
            z_indices_to_plot = list(range(len(available_z_centers)))
        elif isinstance(z_indices, (list, tuple)):
            z_indices_to_plot = z_indices
        else:
            z_indices_to_plot = [z_indices]
        
        # Validate indices
        z_indices_to_plot = [i for i in z_indices_to_plot if 0 <= i < len(available_z_centers)]
        
        if not z_indices_to_plot:
            print("❌ No valid z-indices to plot!")
            return None
        
        print(f"\n🎨 Plotting electrostatic potential ({plot_mode}) for {len(z_indices_to_plot)} z-slices")
        if overlay_clay_contours:
            print(f"🧱 Clay contour overlay: ENABLED")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"🔸 Clay atom overlays: Si network={show_si_network}, Si atoms={show_si_atoms}, Mg atoms={show_mgo_atoms}")
        
        # Print buffer settings
        print(f"📏 Buffer settings: 2D={buffer_2d}, 3D={buffer_3d}")

        # Determine color scale from all data
        all_grids = []
        for z_idx in z_indices_to_plot:
            slice_data = z_slices[z_idx]
            if 'negative_potential_grid' in slice_data:
                all_grids.append(slice_data['negative_potential_grid'])
        
        if not all_grids:
            print("❌ No negative potential grids found!")
            return None
        
        # Calculate separate scales for Z-axis and colorbar
        data_min = min(np.min(grid) for grid in all_grids)
        data_max = max(np.max(grid) for grid in all_grids)
        
        # Z-axis scaling (for geometric display)
        if vmin is None:
            vmin = data_min
        if vmax is None:
            vmax = data_max
        
        # Colorbar scaling (for color mapping - independent of geometric height)
        colorbar_vmin_actual = colorbar_vmin if colorbar_vmin is not None else vmin
        colorbar_vmax_actual = colorbar_vmax if colorbar_vmax is not None else vmax
        
        print(f"📊 Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"🎨 Colorbar scale: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"📏 Z-axis scaling factor: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"📏 Z-axis limit: {z_axis_limit}")
        
        # GET CLAY ATOM POSITIONS for overlays
        si_positions = None
        mgo_positions = None
        
        if show_si_network or show_mgo_atoms or show_si_atoms:
            try:
                if show_si_network or show_si_atoms:
                    si_atoms = self.analysis.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
                    if len(si_atoms) > 0:
                        si_positions = si_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            si_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(si_atoms)} Si atoms")
                
                if show_mgo_atoms:
                    mgo_atoms = self.analysis.universe.select_atoms("resname MMT and (name Mgo or name MGO or name Mg or name MG)")
                    if len(mgo_atoms) > 0:
                        mgo_positions = mgo_atoms.positions.copy()
                        if self.analysis.center_box:
                            box_center_z = self.analysis.universe.dimensions[2] / 2
                            mgo_positions[:, 2] -= box_center_z
                        print(f"✓ Found {len(mgo_atoms)} Mg atoms")
                            
            except Exception as e:
                print(f"Warning: Could not load clay atoms: {e}")
                show_si_network = False
                show_mgo_atoms = False
                show_si_atoms = False
        
        # VdW radii (Angstroms)
        BASE_MG_RADIUS = 0.72  # Mg VdW radius
        BASE_SI_RADIUS = 1.11   # Si VdW radius
        
        # CLAY ATOM OVERLAY FUNCTIONS WITH ENHANCED STYLING AND BUFFER CONTROL
        def add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Mg atoms using direct atom positions with visual clipping"""
            if not show_mgo_atoms or mgo_positions is None or len(mgo_positions) == 0:
                return
            
            # Filter Mg atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = mgo_positions[:, 2] >= 0
            else:
                region_mask = mgo_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(mgo_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            mg_positions = mgo_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_MG_RADIUS * mg_vdw_scaling
            
            print(f"   🟢 Adding {len(mg_positions)} Mg atoms (radius: {scaled_radius:.2f}Å)")
            
            # Get axis limits for buffer calculation
            x_min, x_max = ax.get_xlim()
            y_min, y_max = ax.get_ylim()
            
            # Add buffer based on mode
            x_range = x_max - x_min
            y_range = y_max - y_min
            
            if is_3d and buffer_3d:
                buffer_x = x_range * 0.02  # 2% buffer for 3D
                buffer_y = y_range * 0.02
                print(f"   📏 Applied 3D buffer: {buffer_x:.2f} x {buffer_y:.2f}")
            elif not is_3d and buffer_2d:
                buffer_x = x_range * 0.02  # 2% buffer for 2D  
                buffer_y = y_range * 0.02
                print(f"   📏 Applied 2D buffer: {buffer_x:.2f} x {buffer_y:.2f}")
            else:
                buffer_x = buffer_y = 0.0
                print(f"   📏 No buffer applied")
            
            # Adjust axis limits with buffer
            if buffer_x > 0 or buffer_y > 0:
                ax.set_xlim(x_min - buffer_x, x_max + buffer_x)
                ax.set_ylim(y_min - buffer_y, y_max + buffer_y)
            
            for mg_pos in mg_positions:
                x, y = mg_pos[0], mg_pos[1]
                
                if mgo_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(fade_alpha_max, fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=mgo_color, alpha=alpha,
                                    marker='o', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=mgo_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=mgo_color, alpha=mgo_atom_alpha,
                                marker='o', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=mgo_color, alpha=mgo_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)

        def add_si_network_fixed(ax, z_center, is_3d=False):
            """Add Si atoms connected by lines using direct atom positions with visual clipping"""
            if not show_si_network or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_pos = si_positions[final_mask]
            
            # Apply similar buffer logic for Si networks
            x_min, x_max = ax.get_xlim()
            y_min, y_max = ax.get_ylim()
            
            x_range = x_max - x_min
            y_range = y_max - y_min
            
            if is_3d and buffer_3d:
                buffer_x = x_range * 0.02
                buffer_y = y_range * 0.02
            elif not is_3d and buffer_2d:
                buffer_x = x_range * 0.02
                buffer_y = y_range * 0.02
            else:
                buffer_x = buffer_y = 0.0
            
            # Adjust axis limits with buffer
            if buffer_x > 0 or buffer_y > 0:
                ax.set_xlim(x_min - buffer_x, x_max + buffer_x)
                ax.set_ylim(y_min - buffer_y, y_max + buffer_y)
            
            print(f"   🟠 Adding Si network: {len(si_pos)} atoms, threshold: {si_connection_threshold:.1f}Å")
            
            si_array = si_pos[:, :2]  # Only XY coordinates
            
            # Draw connections between nearby Si atoms (with clipping)
            for i in range(len(si_array)):
                for j in range(i+1, len(si_array)):
                    distance = np.linalg.norm(si_array[i] - si_array[j])
                    
                    if distance < si_connection_threshold:
                        x_coords = [si_array[i][0], si_array[j][0]]
                        y_coords = [si_array[i][1], si_array[j][1]]
                        
                        if not is_3d:
                            # Check if connection line intersects with plot area (2D mode)
                            line_x_min, line_x_max = min(x_coords), max(x_coords)
                            line_y_min, line_y_max = min(y_coords), max(y_coords)
                            
                            line_in_bounds = (
                                line_x_max >= x_min and line_x_min <= x_max and
                                line_y_max >= y_min and line_y_min <= y_max
                            )
                            
                            if not line_in_bounds:
                                continue
                        
                        # CREATE 3D OR 2D LINE WITH VISUAL CLIPPING
                        if is_3d:
                            # For 3D surface plots, create 3D lines at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            z_coords = [z_base, z_base]
                            
                            if si_connection_style == 'lines':
                                linestyle = '-'
                            elif si_connection_style == 'dashed':
                                linestyle = '--'
                            elif si_connection_style == 'dotted':
                                linestyle = ':'
                            else:
                                linestyle = '-'
                            
                            # Plot 3D line
                            ax.plot(x_coords, y_coords, z_coords,
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=linestyle,
                                    zorder=3)
                        else:
                            # For 2D plots
                            if si_connection_style == 'lines':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, zorder=3)[0]
                            elif si_connection_style == 'dashed':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle='--', zorder=3)[0]
                            elif si_connection_style == 'dotted':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=':', zorder=3)[0]
                            
                            # Apply visual clipping to line
                            line.set_clip_box(ax.bbox)
            
            # Show Si atom centers if requested
            if show_hexagonal_pattern:
                if is_3d:
                    # For 3D surface plots, create 3D scatter points at base plane
                    z_base = 0.0  # Place at z=0 base plane
                    z_coords = [z_base] * len(si_array)
                    ax.scatter(si_array[:, 0], si_array[:, 1], z_coords, 
                            s=25, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                else:
                    # For 2D plots
                    scatter = ax.scatter(si_array[:, 0], si_array[:, 1], 
                            s=20, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4)
                    scatter.set_clip_box(ax.bbox)

        def add_vdw_si_atoms_fixed(ax, z_center, is_3d=False):
            """Add VdW-scaled Si atoms using direct atom positions with visual clipping"""
            if not show_si_atoms or si_positions is None or len(si_positions) == 0:
                return
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions[:, 2] >= 0
            else:
                region_mask = si_positions[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_atom_positions = si_positions[final_mask]
            
            # Use correct scaling calculation
            scaled_radius = BASE_SI_RADIUS * si_vdw_scaling
            
            print(f"   🔷 Adding {len(si_atom_positions)} Si atoms (radius: {scaled_radius:.2f}Å)")
            
            # Apply buffer logic similar to Mg atoms
            x_min, x_max = ax.get_xlim()
            y_min, y_max = ax.get_ylim()
            
            x_range = x_max - x_min
            y_range = y_max - y_min
            
            if is_3d and buffer_3d:
                buffer_x = x_range * 0.02
                buffer_y = y_range * 0.02
            elif not is_3d and buffer_2d:
                buffer_x = x_range * 0.02
                buffer_y = y_range * 0.02
            else:
                buffer_x = buffer_y = 0.0
            
            # Adjust axis limits with buffer
            if buffer_x > 0 or buffer_y > 0:
                ax.set_xlim(x_min - buffer_x, x_max + buffer_x)
                ax.set_ylim(y_min - buffer_y, y_max + buffer_y)
            
            for si_pos in si_atom_positions:
                x, y = si_pos[0], si_pos[1]
                
                if si_radial_fade:
                    # Create multiple concentric circles/spheres with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(si_fade_alpha_max, si_fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        if is_3d:
                            # For 3D surface plots, create 3D scatter points at base plane
                            z_base = 0.0  # Place at z=0 base plane
                            ax.scatter(x, y, z_base, 
                                    s=radius*200,  # Scale radius to marker size for visibility
                                    c=si_color, alpha=alpha,
                                    marker='s', edgecolors='black', 
                                    linewidth=0.2,
                                    zorder=5+i)
                        else:
                            # For 2D plots
                            circle = plt.Circle((x, y), radius, 
                                            color=si_color, alpha=alpha,
                                            zorder=5+i)
                            circle.set_clip_box(ax.bbox)
                            ax.add_patch(circle)
                else:
                    # Simple solid circle/sphere
                    if is_3d:
                        # For 3D surface plots, create single 3D scatter point
                        z_base = 0.0  # Place at z=0 base plane
                        ax.scatter(x, y, z_base,
                                s=scaled_radius*200,  # Scale radius to marker size
                                c=si_color, alpha=si_atom_alpha,
                                marker='s', edgecolors='black',
                                linewidth=0.5,
                                zorder=10)
                    else:
                        # For 2D plots
                        circle = plt.Circle((x, y), scaled_radius, 
                                        color=si_color, alpha=si_atom_alpha,
                                        zorder=10)
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)
        # FIXED CLAY CONTOUR OVERLAY FUNCTION - RESTORED FROM FLIPPED4
        def _add_clay_contour_overlay(ax, z_center, clay_contour_results, contour_params):
            """Add clay atom contours (lines only, no fill) to existing plots with 3D support"""
            if clay_contour_results is None or not clay_contour_results.get('z_slices'):
                print(f"    ⚠️ No clay contour results available")
                return
            
            print(f"    🧱 Adding clay contours for z={z_center:.1f}Å...")
            
            # Find the best matching clay slice
            best_clay_slice = None
            min_distance = float('inf')
            
            for clay_slice in clay_contour_results['z_slices']:
                clay_z_center = clay_slice.get('z_center')
                if clay_z_center is not None:
                    distance = abs(clay_z_center - z_center)
                    if distance <= clay_z_tolerance and distance < min_distance:
                        min_distance = distance
                        best_clay_slice = clay_slice
            
            if best_clay_slice is None:
                print(f"    ❌ No clay slice found within tolerance {clay_z_tolerance}Å of z={z_center:.1f}Å")
                return
            
            print(f"    ✓ Using clay slice at z={best_clay_slice['z_center']:.1f}Å (distance: {min_distance:.1f}Å)")
            
            # Try different possible grid names
            clay_grid = None
            grid_name = None
            possible_grid_names = ['mg_grid', 'combined_grid', 'si_grid', 'clay_grid', 'grid']
            
            for name in possible_grid_names:
                if name in best_clay_slice and best_clay_slice[name] is not None:
                    clay_grid = best_clay_slice[name]
                    grid_name = name
                    print(f"    ✓ Found clay grid: '{name}' with shape {clay_grid.shape}")
                    break
            
            if clay_grid is None:
                print(f"    ❌ No valid clay grid found. Available keys: {list(best_clay_slice.keys())}")
                return
            
            # Get coordinate arrays
            if 'x_centers' not in best_clay_slice or 'y_centers' not in best_clay_slice:
                print(f"    ❌ Missing coordinate arrays in clay slice")
                return
            
            x_centers = best_clay_slice['x_centers']
            y_centers = best_clay_slice['y_centers']
            
            if np.max(clay_grid) == 0:
                print(f"    ⚠️ Clay grid is all zeros - no contours to draw")
                return
            
            # Transform clay coordinates to match electrostatic coordinates (start from 0)
            x_clay_transformed = x_centers - x_centers.min()
            y_clay_transformed = y_centers - y_centers.min()
            
            # Create meshgrid for contouring with transformed coordinates
            X, Y = np.meshgrid(x_clay_transformed, y_clay_transformed)
            
            # Calculate contour levels
            non_zero_values = clay_grid[clay_grid > 0]
            if len(non_zero_values) == 0:
                print(f"    ⚠️ No non-zero values in clay grid")
                return
            
            if contour_params.get('mg_contour_levels', 5) == 1:
                levels = [np.mean(non_zero_values)]
            else:
                levels = np.linspace(np.min(non_zero_values), 
                                    np.max(non_zero_values), 
                                    contour_params.get('mg_contour_levels', 5))
            
            print(f"    Contour levels: {levels[:3]}...{levels[-3:]} ({len(levels)} total)")
            
            try:
                # Check if this is a 3D axis
                is_3d = hasattr(ax, 'zaxis')
                
                if is_3d:
                    # For 3D plots: add contours at the base plane (z=0)
                    contours = ax.contour(X, Y, clay_grid, 
                            levels=levels,
                            colors=[contour_params.get('mg_contour_color', 'white')],
                            alpha=contour_params.get('mg_contour_alpha', 0.3),
                            linewidths=contour_params.get('mg_contour_linewidth', 1),
                            zdir='z', offset=0.0)  # Place contours at z=0 base plane
                else:
                    # For 2D plots: add normal contours
                    contours = ax.contour(X, Y, clay_grid, 
                            levels=levels,
                            colors=[contour_params.get('mg_contour_color', 'white')],
                            alpha=contour_params.get('mg_contour_alpha', 0.3),
                            linewidths=contour_params.get('mg_contour_linewidth', 1))
                
                print(f"    ✅ Added clay contours with {len(levels)} levels")
                
            except Exception as e:
                print(f"    ❌ Error creating contours: {e}")

        # Function to create single plot with FIXED Y-AXIS LABELING
        def create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_index):
            """Helper function to create single electrostatic potential plot with FIXED Y-AXIS SPACING"""
            
            if plot_mode == '3d':
                # 3D histogram mode
                from mpl_toolkits.mplot3d import Axes3D
                
                # Create meshgrid for bar positions - use original coordinates
                X, Y = np.meshgrid(x_centers, y_centers)  # Keep original order
                
                # DON'T flip the data - keep it as is
                potential_grid_display = potential_grid  # No flipping!
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    potential_grid_scaled = potential_grid_display * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(potential_grid_scaled):.3f})")
                else:
                    potential_grid_scaled = potential_grid_display
                
                # Flatten arrays for bar3d
                x_flat = X.flatten()
                y_flat = Y.flatten()
                z_flat = np.zeros_like(x_flat)  # Base of bars at z=0
                heights = potential_grid_scaled.flatten()
                
                # Apply threshold
                threshold = np.percentile(heights, threshold_percentile)
                mask = heights > threshold
                
                if np.any(mask):
                    # Bar dimensions
                    dx = x_centers[1] - x_centers[0] if len(x_centers) > 1 else 1.0
                    dy = y_centers[1] - y_centers[0] if len(y_centers) > 1 else 1.0
                    
                    # Create 3D bars
                    bars = ax.bar3d(x_flat[mask], y_flat[mask], z_flat[mask],
                                dx, dy, heights[mask],
                                alpha=bar_alpha, cmap=colormap)
                    
                    # Set color mapping using ORIGINAL data range (not scaled heights)
                    original_heights = potential_grid_display.flatten()[mask]
                    colors = plt.cm.get_cmap(colormap)(
                        (original_heights - colorbar_vmin_actual) / (colorbar_vmax_actual - colorbar_vmin_actual)
                        if colorbar_vmax_actual > colorbar_vmin_actual else np.zeros_like(original_heights)
                    )
                    
                    # Apply colors to bars
                    bars.set_facecolors(colors)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions WITH CONDITIONAL BUFFER
                # Transform coordinates to match 2D coordinate system
                x_display_min = x_centers.min() - x_centers.min()  # Start from 0
                x_display_max = x_centers.max() - x_centers.min()
                y_display_min = y_centers.min() - y_centers.min()  # Start from 0
                y_display_max = y_centers.max() - y_centers.min()
                
                # Apply buffer conditionally based on plot mode and buffer settings
                is_3d_mode = True  # This is 3D mode
                apply_buffer = buffer_3d  # Only apply buffer if buffer_3d=True
                
                if apply_buffer:
                    x_buffer = (x_display_max - x_display_min) * 0.02  # 2% buffer
                    y_buffer = (y_display_max - y_display_min) * 0.02
                    print(f"    📏 Applied 3D buffer: {x_buffer:.2f} x {y_buffer:.2f}")
                else:
                    x_buffer = y_buffer = 0.0
                    print(f"    📏 No buffer applied for 3D mode")
                
                # Set 3D axis limits with conditional buffer
                ax.set_xlim(x_display_min - x_buffer, x_display_max + x_buffer)
                ax.set_ylim(y_display_min - y_buffer, y_display_max + y_buffer)
                
                # Add clay contours if requested (RESTORED)
                if overlay_clay_contours and clay_contour_results:
                    contour_params = {
                        'mg_contour_levels': mg_contour_levels,
                        'mg_contour_color': mg_contour_color,
                        'mg_contour_alpha': mg_contour_alpha,
                        'mg_contour_linewidth': mg_contour_linewidth
                    }
                    _add_clay_contour_overlay(ax, z_center, clay_contour_results, contour_params)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                
                # Set labels for 3D with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ✅ FIX 2: ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)  # Increase Y tick padding
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)   # Standard X tick padding
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)   # Standard Z tick padding
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio
                ax.set_box_aspect([1, 1, 0.5])
                
                # Set viewing angle if provided
                if elevation is not None or azimuth is not None:
                    elev = elevation if elevation is not None else ax.elev
                    azim = azimuth if azimuth is not None else ax.azim
                    ax.view_init(elev=elev, azim=azim)
                
                return None  # No colorbar for 3D mode in this implementation
            
            elif plot_mode == 'surface':
                # 3D smooth surface mode
                from mpl_toolkits.mplot3d import Axes3D
                from scipy.ndimage import gaussian_filter
                
                # Apply smoothing if requested
                if surface_smoothing:
                    smoothed_grid = gaussian_filter(potential_grid, sigma=surface_smoothing_sigma)
                    print(f"    Applied surface smoothing (σ={surface_smoothing_sigma:.1f})")
                else:
                    smoothed_grid = potential_grid
                
                # Apply Z-scaling for display height
                if z_scale_factor is not None:
                    smoothed_grid_scaled = smoothed_grid * z_scale_factor
                    print(f"    Applied Z-scaling: {z_scale_factor}x (max height: {np.max(smoothed_grid_scaled):.3f})")
                else:
                    smoothed_grid_scaled = smoothed_grid
                
                # Create meshgrid - use original coordinates starting from 0
                # Transform coordinates to start from 0
                x_display = x_centers - x_centers.min()  # Start X from 0
                y_display = y_centers - y_centers.min()  # Start Y from 0
                
                X, Y = np.meshgrid(x_display, y_display)
                
                # DON'T flip the data - keep it as is
                smoothed_grid_display = smoothed_grid_scaled  # Use scaled version for height
                
                # Create smooth 3D surface using plot_surface with transformed coordinates
                surf = ax.plot_surface(X, Y, smoothed_grid_display,
                                    cmap=surface_cmap,
                                    alpha=surface_alpha,
                                    vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                                    rstride=surface_rstride,
                                    cstride=surface_cstride,
                                    linewidth=surface_linewidth,
                                    antialiased=surface_antialiased,
                                    shade=surface_lighting)
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions WITH CONDITIONAL BUFFER
                # Apply buffer conditionally based on plot mode and buffer settings
                is_3d_mode = True  # This is 3D surface mode
                apply_buffer = buffer_3d  # Only apply buffer if buffer_3d=True
                
                if apply_buffer:
                    x_buffer = (x_display.max() - x_display.min()) * 0.02  # 2% buffer
                    y_buffer = (y_display.max() - y_display.min()) * 0.02
                    print(f"    📏 Applied 3D surface buffer: {x_buffer:.2f} x {y_buffer:.2f}")
                else:
                    x_buffer = y_buffer = 0.0
                    print(f"    📏 No buffer applied for 3D surface mode")
                
                # Set axis limits with conditional buffer
                ax.set_xlim(x_display.min() - x_buffer, x_display.max() + x_buffer)
                ax.set_ylim(y_display.min() - y_buffer, y_display.max() + y_buffer)
                
                # Add clay contours for surface mode (RESTORED)
                if overlay_clay_contours and clay_contour_results:
                    contour_params = {
                        'mg_contour_levels': mg_contour_levels,
                        'mg_contour_color': mg_contour_color,
                        'mg_contour_alpha': mg_contour_alpha,
                        'mg_contour_linewidth': mg_contour_linewidth
                    }
                    _add_clay_contour_overlay(ax, z_center, clay_contour_results, contour_params)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=True)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=True)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=True)
                
                # FIX 2: REMOVE GRAY GRID BACKGROUND - make panes transparent
                ax.invert_xaxis()
                ax.invert_yaxis()
                ax.xaxis.pane.fill = False
                ax.yaxis.pane.fill = False
                ax.zaxis.pane.fill = False
                
                # Optional: Also make grid lines more subtle or remove them
                ax.xaxis.pane.set_edgecolor('white')
                ax.yaxis.pane.set_edgecolor('white')
                ax.zaxis.pane.set_edgecolor('white')
                ax.xaxis.pane.set_alpha(0)
                ax.yaxis.pane.set_alpha(0)
                ax.zaxis.pane.set_alpha(0)

                # Set labels for 3D surface with LARGER SPACING
                ax.set_xlabel('X (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize, labelpad=15)  # ✅ FIX 1: Add labelpad
                ax.set_zlabel('Negative Potential', fontsize=label_fontsize, labelpad=10)
                
                # ✅ FIX 2: ADJUST TICK LABEL PADDING FOR Y-AXIS
                ax.tick_params(axis='y', which='major', pad=10, labelsize=tick_fontsize)  # Increase Y tick padding
                ax.tick_params(axis='x', which='major', pad=8, labelsize=tick_fontsize)   # Standard X tick padding
                ax.tick_params(axis='z', which='major', pad=5, labelsize=tick_fontsize)   # Standard Z tick padding
                
                # Set Z-axis limit if specified
                if z_axis_limit is not None:
                    ax.set_zlim(0, z_axis_limit)
                    print(f"    Set Z-axis limit: 0 to {z_axis_limit}")
                
                # Set box aspect ratio for better visualization
                ax.set_box_aspect([1, 1, 0.6])
                
                # Set viewing angle
                elev = elevation if elevation is not None else 30
                azim = azimuth if azimuth is not None else 45
                ax.view_init(elev=elev, azim=azim)
                
                # Return surface object for colorbar
                return surf
            
            else:
                # 2D heatmap mode
                # Transform coordinates to start from 0
                x_min, x_max = x_centers.min(), x_centers.max()
                y_min, y_max = y_centers.min(), y_centers.max()
                
                # Create extent that starts from 0
                x_extent = [0, x_max - x_min]  # X starts from 0
                y_extent = [0, y_max - y_min]  # Y starts from 0
                
                # DON'T flip the data - display it as is
                # Use colorbar limits for 2D display
                im = ax.imshow(potential_grid, cmap=cmap,
                            vmin=colorbar_vmin_actual, vmax=colorbar_vmax_actual,
                            origin='lower',  # This puts (0,0) at bottom-left
                            interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                
                # CRITICAL FIX: Set axis limits BEFORE clay overlay functions WITH CONDITIONAL BUFFER
                # Apply buffer conditionally based on plot mode and buffer settings
                is_3d_mode = False  # This is 2D mode
                apply_buffer = buffer_2d  # Only apply buffer if buffer_2d=True
                
                if apply_buffer:
                    x_buffer = (x_extent[1] - x_extent[0]) * 0.02  # 2% buffer
                    y_buffer = (y_extent[1] - y_extent[0]) * 0.02
                    print(f"    📏 Applied 2D buffer: {x_buffer:.2f} x {y_buffer:.2f}")
                else:
                    x_buffer = y_buffer = 0.0
                    print(f"    📏 No buffer applied for 2D mode")
                
                # Set axis limits with conditional buffer
                ax.set_xlim(x_extent[0] - x_buffer, x_extent[1] + x_buffer)
                ax.set_ylim(y_extent[0] - y_buffer, y_extent[1] + y_buffer)
                
                # FIXED: Add clay contours for 2D mode (RESTORED)
                if overlay_clay_contours and clay_contour_results:
                    contour_params = {
                        'mg_contour_levels': mg_contour_levels,
                        'mg_contour_color': mg_contour_color,
                        'mg_contour_alpha': mg_contour_alpha,
                        'mg_contour_linewidth': mg_contour_linewidth
                    }
                    _add_clay_contour_overlay(ax, z_center, clay_contour_results, contour_params)
                
                # NOW call clay overlay functions with correct axis limits
                add_si_network_fixed(ax, z_center, is_3d=False)
                add_vdw_si_atoms_fixed(ax, z_center, is_3d=False)
                add_vdw_mg_atoms_fixed(ax, z_center, is_3d=False)
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha)
                
                # Set labels for 2D (normal spacing is fine for 2D)
                ax.set_xlabel('X (Å)', fontsize=label_fontsize)
                ax.set_ylabel('Y (Å)', fontsize=label_fontsize)
                
                return im

        # Save and/or show individual figures
        if save_individual_figures or show_individual_figures:
            print(f"📄 Processing individual figures...")
            
            for idx, z_idx in enumerate(z_indices_to_plot):
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                print(f"  Individual figure {idx + 1}/{len(z_indices_to_plot)}: z = {z_center:.2f} Å")
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"    ⚠️ No negative potential grid for z-slice {z_idx}")
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                # ✅ FIX 3: INCREASE INDIVIDUAL FIGURE SIZE FOR 3D PLOTS TO PREVENT Y-LABEL CROPPING
                if plot_mode == '3d' or plot_mode == 'surface':
                    # Use larger figure size for 3D to accommodate Y-axis labels
                    adjusted_individual_figsize = (individual_figsize[0] * 1.2, individual_figsize[1] * 1.1)
                    fig_single = plt.figure(figsize=adjusted_individual_figsize)
                    ax_single = fig_single.add_subplot(111, projection='3d')
                else:
                    fig_single, ax_single = plt.subplots(figsize=individual_figsize)
                
                im = create_single_potential_plot(ax_single, potential_grid, x_centers, y_centers, z_center, idx)
                
                # Add title
                if show_title:
                    title = f'Electrostatic Potential: z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax_single.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar 
                if show_colorbar and im is not None:
                    if plot_mode == 'surface':
                        # For 3D surfaces, use fig.colorbar with colorbar limits
                        cbar = fig_single.colorbar(im, ax=ax_single, shrink=0.6, aspect=20)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                    elif plot_mode == '2d':
                        # For 2D mode
                        from mpl_toolkits.axes_grid1 import make_axes_locatable
                        divider = make_axes_locatable(ax_single)
                        cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar = plt.colorbar(im, cax=cax)
                        cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                        cbar.ax.tick_params(labelsize=tick_fontsize)
                
                # ✅ FIX 4: USE plt.subplots_adjust() INSTEAD OF plt.tight_layout() FOR 3D PLOTS
                if plot_mode == '3d' or plot_mode == 'surface':
                    # For 3D plots, use manual spacing to prevent Y-label cropping
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
                else:
                    # For 2D plots, tight_layout works fine
                    plt.tight_layout()
                
                # Save individual figure
                if save_individual_figures:
                    clay_suffix = '_with_clay' if overlay_clay_contours else ''
                    atom_suffix = ''
                    if show_si_network or show_mgo_atoms or show_si_atoms:
                        atom_suffix += '_with_atoms'
                    individual_filename = f'electrostatic_potential_{plot_mode}_z{z_center:.1f}A_individual{clay_suffix}{atom_suffix}.png'
                    plt.savefig(individual_filename, dpi=dpi, bbox_inches='tight')
                    print(f"    ✅ Saved: {individual_filename}")
                
                # Show individual figure
                if show_individual_figures:
                    plt.show()
                else:
                    plt.close(fig_single)

        # Create combined figure
        if show_combined_figure:
            print(f"📊 Creating combined figure...")
            
            n_plots = len(z_indices_to_plot)
            if n_plots == 1:
                if plot_mode == '3d' or plot_mode == 'surface':
                    # ✅ FIX 5: INCREASE COMBINED FIGURE SIZE FOR SINGLE 3D PLOT
                    adjusted_figsize = (figsize[0] * 1.2, figsize[1] * 1.1)
                    fig = plt.figure(figsize=adjusted_figsize)
                    ax = fig.add_subplot(111, projection='3d')
                    axes = [ax]
                else:
                    fig, ax = plt.subplots(figsize=figsize)
                    axes = [ax]
            else:
                ncols = min(3, n_plots)
                nrows = (n_plots - 1) // ncols + 1
                
                if plot_mode == '3d' or plot_mode == 'surface':
                    # ✅ FIX 5: INCREASE COMBINED FIGURE SIZE FOR MULTI-PANEL 3D PLOTS
                    adjusted_figsize = (figsize[0] * 1.3, figsize[1] * 1.2)
                    fig = plt.figure(figsize=adjusted_figsize)
                    axes = []
                    for i in range(n_plots):
                        ax = fig.add_subplot(nrows, ncols, i+1, projection='3d')
                        axes.append(ax)
                else:
                    fig, axes = plt.subplots(nrows, ncols, figsize=figsize)
                    if n_plots > 1:
                        axes = axes.flatten() if hasattr(axes, 'flatten') else [axes]
            
            # Plot each z-slice
            for plot_idx, z_idx in enumerate(z_indices_to_plot):
                if plot_idx >= len(axes):
                    break
                    
                ax = axes[plot_idx]
                
                slice_data = z_slices[z_idx]
                z_center = slice_data['z_center']
                
                # Get potential data
                if 'negative_potential_grid' not in slice_data:
                    print(f"⚠️ No negative potential grid for z-slice {z_idx} (z={z_center:.2f})")
                    ax.text(0.5, 0.5, f'No data for z={z_center:.2f}Å', 
                        ha='center', va='center', transform=ax.transAxes)
                    if show_title:
                        ax.set_title(f'z = {z_center:.2f} Å')
                    continue
                
                potential_grid = slice_data['negative_potential_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                im = create_single_potential_plot(ax, potential_grid, x_centers, y_centers, z_center, plot_idx)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    if overlay_clay_contours:
                        # title += ' (+ Clay)'
                        pass
                    ax.set_title(title, fontsize=title_fontsize)
                
                # Add colorbar for 2D mode only (3D surface colorbars are handled separately)
                if show_colorbar and plot_mode == '2d' and im is not None:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Negative Potential', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
            
            # Hide extra subplots
            if n_plots > 1 and len(axes) > n_plots:
                for i in range(n_plots, len(axes)):
                    if hasattr(axes[i], 'remove'):
                        axes[i].remove()
                    else:
                        axes[i].axis('off')
            
            # ✅ FIX 6: USE plt.subplots_adjust() FOR COMBINED 3D FIGURES
            if plot_mode == '3d' or plot_mode == 'surface':
                # For 3D multi-panel plots, use manual spacing to prevent overlap
                if n_plots > 1:
                    # More space for multi-panel 3D figures
                    plt.subplots_adjust(left=0.08, right=0.92, bottom=0.08, top=0.92, 
                                    wspace=0.4, hspace=0.3)  # ✅ Increased wspace for Y-label spacing
                else:
                    # Single 3D plot
                    plt.subplots_adjust(left=0.15, right=0.85, bottom=0.1, top=0.9)
            else:
                # For 2D plots, tight_layout works fine
                plt.tight_layout()
            
            # Save combined figure
            if save_combined_figure:
                clay_suffix = '_with_clay' if overlay_clay_contours else ''
                atom_suffix = ''
                if show_si_network or show_mgo_atoms or show_si_atoms:
                    atom_suffix += '_with_atoms'
                combined_filename = f'electrostatic_potential_{plot_mode}_COMBINED{clay_suffix}{atom_suffix}.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved combined: {combined_filename}")
            
            plt.show()
        else:
            print("Skipping combined figure (show_combined_figure=False)")
        
        # Summary
        print(f"\n=== Electrostatic Potential {plot_mode.upper()} Summary ===")
        print(f"  Z-slices plotted: {len(z_indices_to_plot)}")
        print(f"  Available z-centers: {[f'{z:.1f}' for z in available_z_centers]}")
        print(f"  Plot mode: {plot_mode}")
        print(f"  Data range: {data_min:.4f} to {data_max:.4f}")
        print(f"  Colorbar range: {colorbar_vmin_actual:.4f} to {colorbar_vmax_actual:.4f}")
        if z_scale_factor is not None:
            print(f"  Z-scaling applied: {z_scale_factor}x")
        if z_axis_limit is not None:
            print(f"  Z-axis limited to: {z_axis_limit}")
        print(f"  Individual figures saved: {save_individual_figures}")
        print(f"  Combined figure saved: {save_combined_figure}")
        
        # Clay atom overlay summary
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"\n🔸 Clay Atom Overlay Summary:")
            if show_si_network:
                print(f"  Si network: ENABLED")
                print(f"    Connection threshold: {si_connection_threshold}Å")
                print(f"    Color: {si_color}, alpha: {si_connection_alpha}")
                print(f"    Style: {si_connection_style}, linewidth: {si_connection_linewidth}")
                if show_hexagonal_pattern:
                    print(f"    Hexagonal pattern: ENABLED")
            if show_si_atoms:
                print(f"  Si atoms: ENABLED")
                print(f"    VdW scaling: {si_vdw_scaling}x (radius: {BASE_SI_RADIUS * si_vdw_scaling:.2f}Å)")
                print(f"    Color: {si_color}, alpha: {si_atom_alpha}")
                if si_radial_fade:
                    print(f"    Radial fade: ENABLED")
            if show_mgo_atoms:
                print(f"  Mg atoms: ENABLED")
                print(f"    VdW scaling: {mg_vdw_scaling}x (radius: {BASE_MG_RADIUS * mg_vdw_scaling:.2f}Å)")
                print(f"    Color: {mgo_color}, alpha: {mgo_atom_alpha}")
                if mgo_radial_fade:
                    print(f"    Radial fade: ENABLED")
            print(f"  Clay z-tolerance: {clay_z_tolerance}Å")
        
        if overlay_clay_contours:
            print(f"\n🧱 Clay Contour Overlay:")
            print(f"  Contour levels: {mg_contour_levels}")
            print(f"  Contour color: {mg_contour_color}")
            print(f"  Contour alpha: {mg_contour_alpha}")
        
        if plot_mode == '3d':
            print(f"  3D parameters: alpha={bar_alpha}, colormap={colormap}")
            print(f"  Threshold percentile: {threshold_percentile}%")
            if elevation is not None or azimuth is not None:
                print(f"  Viewing angles: elevation={elevation}, azimuth={azimuth}")
        elif plot_mode == 'surface':
            print(f"  3D Surface parameters: alpha={surface_alpha}, colormap={surface_cmap}")
            print(f"  Surface smoothing: {'ON' if surface_smoothing else 'OFF'} (σ={surface_smoothing_sigma})")
            print(f"  Surface lighting: {'ON' if surface_lighting else 'OFF'}")
            elev = elevation if elevation is not None else 30
            azim = azimuth if azimuth is not None else 45
            print(f"  Viewing angles: elevation={elev}, azimuth={azim}")
        else:
            print(f"  2D parameters: cmap={cmap}, interpolation={interpolation}")
        
        print(f"  📏 Y-AXIS LABEL FIXES APPLIED:")
        print(f"    ✅ Added labelpad=15 for X/Y axis labels")
        print(f"    ✅ Added pad=10 for Y-axis tick labels") 
        print(f"    ✅ Increased figure sizes for 3D plots")
        print(f"    ✅ Used subplots_adjust() instead of tight_layout() for 3D")
        print(f"    ✅ Increased wspace=0.4 for multi-panel 3D plots")
        
        print(f"  Note: Higher bars/intensity = more negative potential = stronger negative charge")
        if show_si_network or show_mgo_atoms or show_si_atoms:
            print(f"        Clay atoms show hexagonal surface pattern")
        
        return fig                    


