    def plot_water_structure_custom_regions(self, regions, **kwargs):
        '''
        Plot water structure for multiple custom regions
        
        Parameters
        ----------
        regions : list of tuples
            List of (z_min, z_max) tuples defining regions to plot
        **kwargs : dict
            Additional arguments for plot_water_structure_analysis
        '''
        for i, (z_min, z_max) in enumerate(regions):
            print(f"\nPlotting region {i+1}: z = {z_min:.1f} to {z_max:.1f} Å")
            filename = kwargs.get('filename', f'water_structure_region_{i+1}_z{z_min:.0f}to{z_max:.0f}.png')
            self.plot_water_structure_analysis(z_min=z_min, z_max=z_max, 
                                            filename=filename, **kwargs)

    # Interactive version (optional)
    def plot_water_structure_interactive(self):
        '''Create interactive water structure plot with z-range sliders'''
        
        try:
            import ipywidgets as widgets
            from IPython.display import display
        except ImportError:
            print("ipywidgets not available. Install with: pip install ipywidgets")
            return
        
        if not hasattr(self.analysis.results, 'water_structure'):
            print("No water structure data available.")
            return
        
        z_centers = self.analysis.results.water_structure['z_centers']
        z_full_min, z_full_max = z_centers.min(), z_centers.max()
        
        def update_plot(z_min_val, z_max_val, show_refs, highlight_int):
            self.plot_water_structure_analysis(z_min=z_min_val, z_max=z_max_val, 
                                            save_plots=False, 
                                            show_bulk_references=show_refs,
                                            highlight_interfaces=highlight_int)
        
        z_min_slider = widgets.FloatSlider(
            value=z_full_min, min=z_full_min, max=z_full_max, step=1.0,
            description='Z Min (Å):', style={'description_width': 'initial'})
        
        z_max_slider = widgets.FloatSlider(
            value=z_full_max, min=z_full_min, max=z_full_max, step=1.0,
            description='Z Max (Å):', style={'description_width': 'initial'})
        
        refs_checkbox = widgets.Checkbox(
            value=True, description='Show bulk references')
        
        interface_checkbox = widgets.Checkbox(
            value=False, description='Highlight interfaces')
        
        interactive_plot = widgets.interactive(update_plot, 
                                            z_min_val=z_min_slider,
                                            z_max_val=z_max_slider,
                                            show_refs=refs_checkbox,
                                            highlight_int=interface_checkbox)
        display(interactive_plot)

    def plot_interfaces(self, save_plots=True, figsize=None, filename=None):
        '''Plot detected interfaces overlaid on density profile'''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'interfaces'):
            print("No interfaces detected. Run detect_interfaces() first.")
            return
        
        figsize = figsize or self.default_figsize
        fig, ax = plt.subplots(figsize=figsize)
        
        # Plot water density
        ax.plot(self.analysis.z_centers, self.analysis.results.water_density, 'b-', linewidth=2, label='Water density')
        
        # Overlay interfaces
        interfaces = self.analysis.results.interfaces
        for i, (start, end) in enumerate(interfaces['all_interfaces']):
            ax.axvspan(start, end, alpha=0.3, color='red', label=f'Interface {i+1}' if i == 0 else "")
        
        ax.set_xlabel('z (Å)')
        ax.set_ylabel('Water Density (molecules/Å³)')
        ax.set_title('Detected Interfaces', fontweight='bold')
        ax.legend()
        ax.grid(True, alpha=0.3)
        ax.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'interface_detection.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Interface detection plot saved as: {filename}")
        
        plt.show()

    def create_summary_dashboard(self, save_plots=True, figsize=(20, 15), filename=None):
        '''Create a comprehensive dashboard with multiple analysis results'''
        
        self._validate_analysis()
        
        fig = plt.figure(figsize=figsize)
        
        # Create a grid layout
        gs = fig.add_gridspec(3, 4, hspace=0.3, wspace=0.3)
        
        # Plot 1: Density profiles (top-left, spans 2 columns)
        ax1 = fig.add_subplot(gs[0, :2])
        ax1.plot(self.analysis.z_centers, self.analysis.results.water_density, 'b-', linewidth=2, label='Water')
        ax1.plot(self.analysis.z_centers, self.analysis.results.cation_density, 'r-', linewidth=2, label='Cations')
        ax1.plot(self.analysis.z_centers, self.analysis.results.anion_density, 'g-', linewidth=2, label='Anions')
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Density (molecules/Å³)')
        ax1.set_title('Density Profiles', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Ion-specific densities (top-right, spans 2 columns)
        ax2 = fig.add_subplot(gs[0, 2:])
        color_idx = 0
        for ion_type, density in self.analysis.results.ion_densities_by_type.items():
            color = self.default_colors[color_idx % len(self.default_colors)]
            ax2.plot(self.analysis.z_centers, density, color=color, linewidth=2, label=ion_type)
            color_idx += 1
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Density (ions/Å³)')
        ax2.set_title('Ion-Specific Densities', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Coordination analysis (if available)
        ax3 = fig.add_subplot(gs[1, 0])
        if hasattr(self.analysis.results, 'coordination_vs_z') and self.analysis.results.coordination_vs_z:
            for ion_type, data in self.analysis.results.coordination_vs_z.items():
                if data['z_positions']:
                    ax3.scatter(data['z_positions'], data['coordination_numbers'], 
                               alpha=0.6, s=10, label=ion_type)
        ax3.set_xlabel('z (Å)')
        ax3.set_ylabel('Coordination Number')
        ax3.set_title('Coordination vs Z', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        
        # Plot 4: Electrostatic potential (if available)
        ax4 = fig.add_subplot(gs[1, 1])
        if hasattr(self.analysis.results, 'electrostatic_potential'):
            ax4.plot(self.analysis.z_centers, self.analysis.results.electrostatic_potential, 'g-', linewidth=2)
            ax4.set_xlabel('z (Å)')
            ax4.set_ylabel('Potential')
            ax4.set_title('Electrostatic Potential', fontweight='bold')
            ax4.grid(True, alpha=0.3)
        else:
            ax4.text(0.5, 0.5, 'No electrostatic\npotential data', ha='center', va='center', transform=ax4.transAxes)
            ax4.set_title('Electrostatic Potential', fontweight='bold')
        
        # Plot 5: Ion clustering (if available)
        ax5 = fig.add_subplot(gs[1, 2])
        if hasattr(self.analysis.results, 'ion_clustering'):
            clustering_data = self.analysis.results.ion_clustering
            for ion_type, cluster_sizes in clustering_data['average_cluster_size'].items():
                ax5.plot(clustering_data['z_centers'], cluster_sizes, linewidth=2, label=ion_type)
            ax5.set_xlabel('z (Å)')
            ax5.set_ylabel('Avg Cluster Size')
            ax5.set_title('Ion Clustering', fontweight='bold')
            ax5.legend()
            ax5.grid(True, alpha=0.3)
        else:
            ax5.text(0.5, 0.5, 'No clustering\ndata', ha='center', va='center', transform=ax5.transAxes)
            ax5.set_title('Ion Clustering', fontweight='bold')
        
        # Plot 6: Water structure (if available)
        ax6 = fig.add_subplot(gs[1, 3])
        if hasattr(self.analysis.results, 'water_structure'):
            struct_data = self.analysis.results.water_structure
            ax6.plot(struct_data['z_centers'], struct_data['tetrahedral_order'], 'b-', linewidth=2)
            ax6.set_xlabel('z (Å)')
            ax6.set_ylabel('Q parameter')
            ax6.set_title('Tetrahedral Order', fontweight='bold')
            ax6.grid(True, alpha=0.3)
        else:
            ax6.text(0.5, 0.5, 'No water\nstructure data', ha='center', va='center', transform=ax6.transAxes)
            ax6.set_title('Water Structure', fontweight='bold')
        
        # Bottom row: Summary statistics or interfaces
        ax7 = fig.add_subplot(gs[2, :])
        
        # Create summary text
        summary_text = f"Analysis Summary:\n"
        summary_text += f"• Total frames analyzed: {self.analysis.n_frames_analyzed}\n"
        summary_text += f"• Z-range: {self.analysis.z_min:.1f} to {self.analysis.z_max:.1f} Å\n"
        summary_text += f"• Number of bins: {self.analysis.n_bins}\n"
        summary_text += f"• Water molecules: {len(self.analysis.waters)}\n"
        summary_text += f"• Cations: {len(self.analysis.cations)}\n"
        summary_text += f"• Anions: {len(self.analysis.anions)}\n"
        
        # Add interface information if available
        if hasattr(self.analysis.results, 'interfaces'):
            interfaces = self.analysis.results.interfaces
            summary_text += f"• Detected interfaces: {len(interfaces['all_interfaces'])}\n"
        
        ax7.text(0.02, 0.98, summary_text, transform=ax7.transAxes, fontsize=12,
                verticalalignment='top', bbox=dict(boxstyle='round', facecolor='lightgray', alpha=0.8))
        ax7.set_xlim(0, 1)
        ax7.set_ylim(0, 1)
        ax7.axis('off')
        
        plt.suptitle('Z-Directional Analysis Dashboard', fontsize=16, fontweight='bold')
        
        if save_plots:
            filename = filename or 'z_analysis_dashboard.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Analysis dashboard saved as: {filename}")
        
        plt.show()

 
    def plot_local_temperature_vs_z(self, save_plots=True, figsize=None, filename=None):
        '''Plot local temperature profile vs z-position'''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'local_temperature'):
            print("No local temperature data available. Run calculate_local_temperature_vs_z() first.")
            return
        
        figsize = figsize or self.default_figsize
        fig, ax = plt.subplots(figsize=figsize)
        
        # Fix: local_temperature is a numpy array, not a dict
        temperatures = self.analysis.results.local_temperature
        z_centers = self.analysis.z_centers  # Get from main analysis object
        
        # Filter out invalid temperatures (zeros or NaNs)
        valid_mask = (temperatures > 0) & ~np.isnan(temperatures)
        
        if not np.any(valid_mask):
            print("No valid temperature data available.")
            return
        
        ax.plot(z_centers[valid_mask], temperatures[valid_mask], 'r-', linewidth=2, marker='o', markersize=4)
        ax.set_xlabel('z (Å)')
        ax.set_ylabel('Temperature (K)')
        ax.set_title('Local Temperature Profile vs Z-Position', fontweight='bold')
        ax.grid(True, alpha=0.3)
        ax.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Add mean temperature line
        mean_temp = np.mean(temperatures[valid_mask])
        ax.axhline(mean_temp, color='g', linestyle='--', alpha=0.7, 
                label=f'Mean: {mean_temp:.1f} K')
        ax.legend()
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'local_temperature_vs_z.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Local temperature plot saved as: {filename}")
        
        plt.show()
        
        # Print summary
        print(f"\nLocal Temperature Analysis Summary:")
        print(f"  Mean temperature: {mean_temp:.2f} K")
        print(f"  Temperature range: {np.min(temperatures[valid_mask]):.2f} - {np.max(temperatures[valid_mask]):.2f} K")
        print(f"  Standard deviation: {np.std(temperatures[valid_mask]):.2f} K")


    def plot_dipole_orientation_vs_z(self, save_plots=True, figsize=None, 
                                    bin_size=2.0, filename=None,
                                    dpi=600,
                                    title_fontsize=16,
                                    show_title=False,
                                    label_fontsize=14,
                                    tick_fontsize=12,
                                    legend_fontsize=12,
                                    show_legend=False,
                                    cmap='hot',
                                    colorbar_pad=0.02,
                                    colorbar_width='4%',
                                    vmin=None,
                                    vmax=None,
                                    colorbar_percentile=None,
                                    use_cache=True,
                                    cache_filename='dipole_orientation_cache.npz'):
        '''
        Plot water dipole orientation vs z-position with heatmap
        
        Parameters
        ----------
        save_plots : bool
            Whether to save the plot
        figsize : tuple
            Figure size (width, height)
        bin_size : float
            Z-bin width for averaging (Å)
        filename : str
            Output filename
        dpi : int
            Resolution for saved figure (default: 600)
        title_fontsize : int
            Font size for titles (default: 16)
        show_title : bool
            Whether to show titles (default: False)
        label_fontsize : int
            Font size for axis labels (default: 14)
        tick_fontsize : int
            Font size for tick labels (default: 12)
        legend_fontsize : int
            Font size for legend (default: 12)
        show_legend : bool
            Whether to show legend (default: False)
        cmap : str
            Colormap for heatmap (default: 'hot')
        colorbar_pad : float
            Padding between plot and colorbar (default: 0.02)
        colorbar_width : str
            Width of colorbar as percentage (default: '4%')
        vmin : float, optional
            Minimum value for colorbar scale (manual control)
        vmax : float, optional
            Maximum value for colorbar scale (manual control)
        colorbar_percentile : tuple of (float, float), optional
            Percentile range for auto-clipping, e.g., (5, 95)
            Overridden by vmin/vmax if provided
        use_cache : bool
            Whether to use cached data if available (default: True)
        cache_filename : str
            Name of cache file (default: 'dipole_orientation_cache.npz')
        '''
        
        self._validate_analysis()
        
        # ✅ CACHE IMPLEMENTATION
        import os
        
        cache_exists = os.path.exists(cache_filename)
        
        if use_cache and cache_exists:
            print(f"📦 Loading dipole data from cache: {cache_filename}")
            try:
                cache_data = np.load(cache_filename)
                z_pos = cache_data['z_positions']
                angles = cache_data['dipole_angles']
                print(f"✓ Loaded {len(z_pos)} data points from cache")
            except Exception as e:
                print(f"⚠ Error loading cache: {e}")
                print("  Computing from scratch...")
                use_cache = False
        
        if not use_cache or not cache_exists:
            if not self.analysis.results.dipole_vs_z['z_positions']:
                print("No dipole orientation data available. This is collected during run() analysis.")
                return
            
            z_pos = np.array(self.analysis.results.dipole_vs_z['z_positions'])
            angles = np.array(self.analysis.results.dipole_vs_z['dipole_angles'])
            
            print(f"💾 Saving dipole data to cache: {cache_filename}")
            try:
                np.savez(cache_filename, z_positions=z_pos, dipole_angles=angles)
                print(f"✓ Cache saved with {len(z_pos)} data points")
            except Exception as e:
                print(f"⚠ Warning: Could not save cache: {e}")
        
        # Create figure
        figsize = figsize or (12, 6)
        fig, ax = plt.subplots(1, 1, figsize=figsize)
        
        # 2D Histogram Heatmap
        z_bins = np.arange(self.analysis.z_min, self.analysis.z_max + bin_size, bin_size)
        angle_bins = np.arange(0, 181, 5)
        
        H, xedges, yedges = np.histogram2d(z_pos, angles, bins=[z_bins, angle_bins])
        
        # ✅ COLORBAR SCALE ADJUSTMENT (Option 3: Flexible)
        # Priority: vmin/vmax > percentile > full range
        if vmin is None and vmax is None and colorbar_percentile is not None:
            # Use percentile-based clipping
            vmin_calc = np.percentile(H, colorbar_percentile[0])
            vmax_calc = np.percentile(H, colorbar_percentile[1])
            print(f"📊 Using percentile clipping: {colorbar_percentile}")
            print(f"   vmin = {vmin_calc:.1f} ({colorbar_percentile[0]}th percentile)")
            print(f"   vmax = {vmax_calc:.1f} ({colorbar_percentile[1]}th percentile)")
        elif vmin is not None or vmax is not None:
            # Use manual vmin/vmax
            vmin_calc = vmin if vmin is not None else H.min()
            vmax_calc = vmax if vmax is not None else H.max()
            print(f"🎯 Using manual colorbar limits:")
            print(f"   vmin = {vmin_calc:.1f}")
            print(f"   vmax = {vmax_calc:.1f}")
        else:
            # Use full data range (default behavior)
            vmin_calc = H.min()
            vmax_calc = H.max()
            print(f"📈 Using full data range: {vmin_calc:.1f} to {vmax_calc:.1f}")
        
        # Calculate clipping statistics
        n_clipped_low = np.sum(H < vmin_calc)
        n_clipped_high = np.sum(H > vmax_calc)
        total_bins = H.size
        pct_clipped = (n_clipped_low + n_clipped_high) / total_bins * 100
        
        if pct_clipped > 0:
            print(f"✂️  Clipping statistics:")
            print(f"   {n_clipped_low} bins below vmin ({n_clipped_low/total_bins*100:.1f}%)")
            print(f"   {n_clipped_high} bins above vmax ({n_clipped_high/total_bins*100:.1f}%)")
            print(f"   Total clipped: {pct_clipped:.1f}%")
        
        # Plot heatmap with adjusted scale
        im = ax.imshow(H.T, origin='lower', aspect='auto', cmap=cmap,
                        extent=[z_bins[0], z_bins[-1], angle_bins[0], angle_bins[-1]],
                        interpolation='gaussian',
                        vmin=vmin_calc, vmax=vmax_calc)
        
        ax.axhline(90, color='cyan', linestyle='--', linewidth=2, 
                alpha=0.7, label='Random (90°)')
        ax.axvline(0, color='white', linestyle='--', linewidth=1, alpha=0.5)
        
        ax.set_xlabel('z (Å)', fontsize=label_fontsize)
        ax.set_ylabel('Dipole Angle (degrees)', fontsize=label_fontsize)
        
        if show_title:
            ax.set_title('Dipole Orientation Density Map', 
                        fontweight='bold', fontsize=title_fontsize)
        
        # ✅ Add colorbar using standard method with custom parameters
        width_fraction = float(colorbar_width.strip('%')) / 100
        
        cbar = plt.colorbar(im, ax=ax, pad=colorbar_pad, fraction=width_fraction, aspect=20)
        
        # ✅ Rescale colorbar to thousands - KEEP ORIGINAL LABEL
        if pct_clipped > 0:
            cbar.set_label('Count Density (×10³) [clipped]', fontsize=label_fontsize)
        else:
            cbar.set_label('Count Density (×10³)', fontsize=label_fontsize)
        
        # Get current tick locations and rescale them
        tick_locations = cbar.get_ticks()
        
        # Rescale tick labels to thousands (divide by 1000)
        cbar.ax.set_yticklabels([f'{int(val/1000)}' for val in tick_locations])
        cbar.ax.tick_params(labelsize=tick_fontsize)
        
        # Set tick label fontsizes
        ax.tick_params(axis='both', which='major', labelsize=tick_fontsize)
        
        if show_legend:
            ax.legend(loc='upper right', fontsize=legend_fontsize)
        
        plt.tight_layout()
        
        if save_plots:
            if filename is None:
                # Include scale info in filename
                scale_suffix = ''
                if vmin is not None or vmax is not None:
                    scale_suffix = f'_vmin{vmin_calc:.0f}_vmax{vmax_calc:.0f}'
                elif colorbar_percentile is not None:
                    scale_suffix = f'_p{colorbar_percentile[0]}-{colorbar_percentile[1]}'
                
                filename = f'dipole_orientation_heatmap_dpi{dpi}_cmap_{cmap}{scale_suffix}.png'
            
            plt.savefig(filename, dpi=dpi, bbox_inches='tight')
            print(f"✓ Dipole orientation heatmap saved: {filename} (dpi={dpi})")
        
        plt.show()
        
        # Print summary
        print(f"\n=== Dipole Orientation Analysis Summary ===")
        print(f"  Total water molecules analyzed: {len(angles)}")
        print(f"  Mean dipole angle: {np.mean(angles):.1f}°")
        print(f"  Standard deviation: {np.std(angles):.1f}°")
        print(f"  Median dipole angle: {np.median(angles):.1f}°")
        print(f"  Colormap: {cmap}")
        print(f"  Colorbar width: {colorbar_width}")
        print(f"  Colorbar padding: {colorbar_pad}")
        print(f"  Colorbar scale: {vmin_calc:.1f} to {vmax_calc:.1f}")
        if pct_clipped > 0:
            print(f"  ⚠️  {pct_clipped:.1f}% of data clipped")
        print(f"  Cache: {'✓ Used' if use_cache and cache_exists else '✗ Not used'}")
        print(f"  Note: 90° indicates random orientation")
        print(f"        <90° indicates preferential alignment")
        print(f"        >90° indicates preferential anti-alignment")


    def _add_clay_atoms_to_xy_plot(self, ax, z_center, z_tolerance=5.0):
        """Add clay atom positions to XY plot"""
        
        try:
            # Get clay atoms within z-tolerance of the slice
            clay_atoms = self.analysis.universe.select_atoms("name SI or name AL or name MG")  # Adjust selection as needed
            
            # Use first frame for reference
            current_frame = self.analysis.universe.trajectory.ts.frame
            self.analysis.universe.trajectory[0]  # Go to first frame
            
            clay_positions = clay_atoms.positions
            
            # Apply z-offset for centering if needed
            z_offset = 0
            if self.analysis.center_box and self.analysis.universe.dimensions is not None:
                z_offset = self.analysis.universe.dimensions[2] / 2
            
            # Filter by z-position
            z_positions = clay_positions[:, 2] - z_offset
            in_slice = np.abs(z_positions - z_center) <= z_tolerance
            
            if np.any(in_slice):
                slice_clay = clay_positions[in_slice]
                
                # Apply periodic boundary conditions
                box_x, box_y = self.analysis.universe.dimensions[0], self.analysis.universe.dimensions[1]
                slice_clay[:, 0] = slice_clay[:, 0] % box_x
                slice_clay[:, 1] = slice_clay[:, 1] % box_y
                
                # Plot clay atoms
                ax.scatter(slice_clay[:, 0], slice_clay[:, 1], 
                        s=20, c='black', alpha=0.5, marker='o', 
                        label='Clay atoms')
            
            # Return to original frame
            self.analysis.universe.trajectory[current_frame]
            
        except Exception as e:
            print(f"Could not add clay atoms: {e}")

    def _add_mgo_atoms_to_xy_plot(self, ax, z_center, z_tolerance=5.0):
        """Add MgO atom positions to XY plot"""
        
        try:
            # Get MgO atoms within z-tolerance of the slice
            mgo_atoms = self.analysis.universe.select_atoms("name MG or name MGO or name Mgo")  # Adjust selection as needed
            
            # Use first frame for reference
            current_frame = self.analysis.universe.trajectory.ts.frame
            self.analysis.universe.trajectory[0]  # Go to first frame
            
            mgo_positions = mgo_atoms.positions
            
            # Apply z-offset for centering if needed
            z_offset = 0
            if self.analysis.center_box and self.analysis.universe.dimensions is not None:
                z_offset = self.analysis.universe.dimensions[2] / 2
            
            # Filter by z-position
            z_positions = mgo_positions[:, 2] - z_offset
            in_slice = np.abs(z_positions - z_center) <= z_tolerance
            
            if np.any(in_slice):
                slice_mgo = mgo_positions[in_slice]
                
                # Apply periodic boundary conditions
                box_x, box_y = self.analysis.universe.dimensions[0], self.analysis.universe.dimensions[1]
                slice_mgo[:, 0] = slice_mgo[:, 0] % box_x
                slice_mgo[:, 1] = slice_mgo[:, 1] % box_y
                
                # Plot MgO atoms
                ax.scatter(slice_mgo[:, 0], slice_mgo[:, 1], 
                        s=60, c='green', alpha=0.7, marker='s', 
                        label='Mg atoms')
            
            # Return to original frame
            self.analysis.universe.trajectory[current_frame]
            
        except Exception as e:
            print(f"Could not add MgO atoms: {e}")


