    def plot_water_dipole_orientation_xy(self, z_indices='all', save_plots=True, cmap='twilight', 
                                figsize=(8, 6), vmax=180, vmin=0, dpi=300, 
                                
                                # 🆕 INDIVIDUAL FIGURE CONTROL
                                save_individual_figures=False,
                                show_individual_figures=False, 
                                show_combined_figure=True,
                                individual_figsize=(8, 7),
                                
                                # 🆕 COLORBAR CONTROL
                                vmin_manual=None,
                                vmax_manual=None,
                                
                                # 🆕 REGION-SPECIFIC COLORBAR CONTROL
                                vmin_positive=None,
                                vmax_positive=None,
                                vmin_negative=None,
                                vmax_negative=None,
                                vmin_zero=None,
                                vmax_zero=None,
                                
                                # 🆕 COMBINED FIGURE SAVE CONTROL
                                save_combined_figure=False,
                                
                                # 🆕 MGO CONTOUR OVERLAY CONTROL
                                overlay_clay_contours=False,
                                clay_contour_results=None,
                                clay_contour_z_tolerance=2.0,
                                overlay_mg_contours=True,
                                mg_contour_color='white',
                                mg_contour_alpha=0.6,
                                mg_contour_linewidth=1.0,
                                mg_contour_levels=5,
                                
                                # 🔄 EXISTING PARAMETERS (unchanged)
                                title_fontsize=14, label_fontsize=12, tick_fontsize=10, 
                                colorbar_label_fontsize=11, legend_fontsize=10, 
                                grid_alpha=0.3, subplot_wspace=0.3, subplot_hspace=0.4, 
                                colorbar_width='5%', colorbar_pad=0.05, origin='lower', 
                                interpolation='bilinear', aspect='equal', show_colorbar=True, 
                                show_grid=True, filename=None, show_title=True, 
                                clay_analysis_func=None, clay_analysis_params=None, 
                                show_clay_spatial=False):
        """
        Plot water dipole orientation in XY plane for different z-slices with optional clay overlay
        """
        
        # Check if water dipole orientation data exists
        if not hasattr(self.analysis.results, 'water_dipole_xy'):
            print("❌ No water dipole orientation XY data found!")
            print("   Please run calculate_water_dipole_orientation_xy() first")
            return None
        
        dipole_data = self.analysis.results.water_dipole_xy
        
        # Check if the required keys exist
        if 'z_slices' not in dipole_data:
            print("❌ Missing required key 'z_slices' in dipole data!")
            return None
        
        z_slices = dipole_data['z_slices']
        
        if not z_slices:
            print("❌ No z-slice data available in water_dipole_xy")
            return None
        
        # Get available z-centers from the slices
        available_z_centers = [slice_data['z_center'] for slice_data in z_slices]
        
        # Determine which z-slices to plot
        if z_indices == 'all':
            z_indices_to_plot = list(range(len(available_z_centers)))
        elif isinstance(z_indices, (list, tuple)):
            z_indices_to_plot = z_indices
        else:
            z_indices_to_plot = [z_indices]
        
        # Validate indices
        z_indices_to_plot = [i for i in z_indices_to_plot if 0 <= i < len(available_z_centers)]
        
        if not z_indices_to_plot:
            print("❌ No valid z-indices to plot!")
            return None
        
        print(f"\n🎨 Plotting dipole orientation for {len(z_indices_to_plot)} z-slices")
        
        # 🆕 REGION-SPECIFIC COLORBAR LOGIC
        def get_colorbar_limits_for_z(z_center):
            """Determine colorbar limits based on z-position"""
            zero_threshold = 2.0  # ±2 Å around zero
            
            # Check region-specific limits first
            if abs(z_center) <= zero_threshold:
                # Near zero region
                if vmin_zero is not None or vmax_zero is not None:
                    return (vmin_zero if vmin_zero is not None else vmin,
                        vmax_zero if vmax_zero is not None else vmax)
            elif z_center > zero_threshold:
                # Positive region
                if vmin_positive is not None or vmax_positive is not None:
                    return (vmin_positive if vmin_positive is not None else vmin,
                        vmax_positive if vmax_positive is not None else vmax)
            else:
                # Negative region
                if vmin_negative is not None or vmax_negative is not None:
                    return (vmin_negative if vmin_negative is not None else vmin,
                        vmax_negative if vmax_negative is not None else vmax)
            
            # Fall back to manual limits or defaults
            vmin_actual = vmin_manual if vmin_manual is not None else vmin
            vmax_actual = vmax_manual if vmax_manual is not None else vmax
            return (vmin_actual, vmax_actual)
        
        # ✅ FIXED APPROACH: Use direct atom positions instead of complex clay data structures
        si_positions = None
        mgo_positions = None
        
        if show_clay_spatial:
            print("🧱 Loading clay atom positions for direct overlay (FIXED approach)...")
            try:
                # Get Si atoms directly from universe
                si_atoms = self.analysis.universe.select_atoms("resname MMT and (name Si or name SI or name Sio or name SIO)")
                if len(si_atoms) > 0:
                    si_positions = si_atoms.positions.copy()
                    if self.analysis.center_box:
                        box_center_z = self.analysis.universe.dimensions[2] / 2
                        si_positions[:, 2] -= box_center_z
                        # Apply XY centering if dipole coordinates are centered
                        first_slice = z_slices[0]
                        x_centers = first_slice['x_centers']
                        y_centers = first_slice['y_centers']
                        if (np.min(x_centers) < 0) and (np.max(x_centers) > 0):
                            box_center_x = self.analysis.universe.dimensions[0] / 2
                            si_positions[:, 0] -= box_center_x
                        if (np.min(y_centers) < 0) and (np.max(y_centers) > 0):
                            box_center_y = self.analysis.universe.dimensions[1] / 2
                            si_positions[:, 1] -= box_center_y
                    print(f"✓ Found {len(si_atoms)} Si atoms")
                
                # Get Mg atoms directly from universe
                mgo_atoms = self.analysis.universe.select_atoms("resname MMT and (name Mgo or name MGO or name Mg or name MG)")
                if len(mgo_atoms) > 0:
                    mgo_positions = mgo_atoms.positions.copy()
                    if self.analysis.center_box:
                        box_center_z = self.analysis.universe.dimensions[2] / 2
                        mgo_positions[:, 2] -= box_center_z
                        # Apply XY centering if dipole coordinates are centered
                        first_slice = z_slices[0]
                        x_centers = first_slice['x_centers']
                        y_centers = first_slice['y_centers']
                        if (np.min(x_centers) < 0) and (np.max(x_centers) > 0):
                            box_center_x = self.analysis.universe.dimensions[0] / 2
                            mgo_positions[:, 0] -= box_center_x
                        if (np.min(y_centers) < 0) and (np.max(y_centers) > 0):
                            box_center_y = self.analysis.universe.dimensions[1] / 2
                            mgo_positions[:, 1] -= box_center_y
                    print(f"✓ Found {len(mgo_atoms)} Mg atoms")
                    
            except Exception as e:
                print(f"⚠️ Error loading clay atoms: {e}")
                show_clay_spatial = False
        
        # 🆕 CALCULATE CLAY CONTOURS IF OVERLAY IS REQUESTED
        clay_contour_data = None
        if overlay_clay_contours:
            if clay_contour_results is None:
                print("🧮 Calculating clay contours for overlay...")
                try:
                    clay_contour_data = self.analysis.calculate_clay_spatial_distribution_xy(
                        z_slice_centers=available_z_centers,
                        z_slice_width=2.0,
                        mg_vdw_scaling=2.0,
                        si_vdw_scaling=1.5,
                        use_cache=True,
                        step=10,
                        return_format='grids'
                    )
                except Exception as e:
                    print(f"⚠️ Error calculating clay contours: {e}")
                    overlay_clay_contours = False
            else:
                clay_contour_data = clay_contour_results
        
        # 🆕 CLAY CONTOUR HELPER FUNCTION
        def _add_clay_contour_overlay(ax, z_center, clay_contour_results, contour_params):
            """Add clay atom contours (lines only, no fill) to existing water dipole plot"""
            if clay_contour_results is None or not clay_contour_results.get('z_slices'):
                return
            
            # Simply use the first available clay slice (they're all identical due to combine_mg_layers=True)
            if len(clay_contour_results['z_slices']) > 0:
                clay_slice = clay_contour_results['z_slices'][0]  # First slice
                
                # Extract Mg grid if available
                if contour_params.get('overlay_mg_contours', True) and 'mg_grid' in clay_slice:
                    mg_grid = clay_slice['mg_grid']
                    x_centers = clay_slice['x_centers']
                    y_centers = clay_slice['y_centers']
                    
                    if np.max(mg_grid) > 0:  # Only plot if there's data
                        X, Y = np.meshgrid(x_centers, y_centers)
                        
                        # Plot contour lines only (no fill)
                        ax.contour(X, Y, mg_grid, 
                                levels=contour_params.get('mg_contour_levels', 5),
                                colors=contour_params.get('mg_contour_color', 'white'),
                                alpha=contour_params.get('mg_contour_alpha', 0.6),
                                linewidths=contour_params.get('mg_contour_linewidth', 1.0))
        
        # ✅ DEFINE CLAY OVERLAY FUNCTIONS AT METHOD LEVEL (so they're available to both individual and combined)
        def add_vdw_mg_atoms_fixed(ax, mg_positions_all, z_center, mg_params):
            """Add VdW-scaled Mg atoms using direct atom positions with visual clipping"""
            if mg_positions_all is None or len(mg_positions_all) == 0:
                return
            
            mg_vdw_scaling = mg_params.get('mg_vdw_scaling', 2.0)
            mgo_color = mg_params.get('mgo_color', 'green')
            fade_alpha_min = mg_params.get('fade_alpha_min', 0.1)
            fade_alpha_max = mg_params.get('fade_alpha_max', 0.8)
            mgo_radial_fade = mg_params.get('mgo_radial_fade', True)
            clay_z_tolerance = mg_params.get('clay_z_tolerance', 5.0)
            
            # Filter Mg atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = mg_positions_all[:, 2] >= 0
            else:
                region_mask = mg_positions_all[:, 2] < 0
            # region_mask = np.ones(len(mg_positions_all), dtype=bool)  # Include ALL Mg atoms

            z_tolerance_mask = np.abs(mg_positions_all[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            mg_positions = mg_positions_all[final_mask]
            
            # Base VdW radius for Mg (Angstroms)
            base_mg_radius = 0.72
            scaled_radius = base_mg_radius * mg_vdw_scaling
            
            # ✅ GET AXIS LIMITS FOR CLIPPING
            x_min, x_max = ax.get_xlim()
            y_min, y_max = ax.get_ylim()
            
            for mg_pos in mg_positions:
                x, y = mg_pos[0], mg_pos[1]
                
                # Skip if center is completely outside bounds
                if (x + scaled_radius < x_min or x - scaled_radius > x_max or 
                    y + scaled_radius < y_min or y - scaled_radius > y_max):
                    continue
                
                if mgo_radial_fade:
                    # Create multiple concentric circles with varying alpha for texture
                    n_circles = 5
                    alphas = np.linspace(fade_alpha_max, fade_alpha_min, n_circles)
                    radii = np.linspace(0.3 * scaled_radius, scaled_radius, n_circles)
                    
                    for i, (radius, alpha) in enumerate(zip(radii, alphas)):
                        # Add some randomness for grainy texture
                        noise_factor = 0.1 * scaled_radius * (1 - i/n_circles)
                        final_radius = radius + np.random.normal(0, noise_factor)
                        actual_alpha = alpha + np.random.normal(0, 0.05)
                        actual_alpha = np.clip(actual_alpha, 0.05, 1.0)
                        
                        # ✅ CREATE CIRCLE WITH ORIGINAL SIZE
                        circle = plt.Circle((x, y), final_radius, 
                                        color=mgo_color, alpha=actual_alpha,
                                        zorder=5+i)
                        
                        # ✅ APPLY VISUAL CLIPPING
                        circle.set_clip_box(ax.bbox)
                        ax.add_patch(circle)
                else:
                    # Simple solid circle
                    circle = plt.Circle((x, y), scaled_radius, 
                                    color=mgo_color, alpha=fade_alpha_max,
                                    zorder=10)
                    
                    # ✅ APPLY VISUAL CLIPPING
                    circle.set_clip_box(ax.bbox)
                    ax.add_patch(circle)

        def add_si_network_fixed(ax, si_positions_all, z_center, si_params):
            """Add Si atoms connected by lines using direct atom positions with visual clipping"""
            if si_positions_all is None or len(si_positions_all) == 0:
                return
            
            si_color = si_params.get('si_color', 'orange')
            si_connection_threshold = si_params.get('si_connection_threshold', 5.0)
            si_connection_style = si_params.get('si_connection_style', 'lines')
            si_connection_alpha = si_params.get('si_connection_alpha', 0.6)
            si_connection_linewidth = si_params.get('si_connection_linewidth', 1.2)
            si_center_alpha = si_params.get('si_center_alpha', 0.8) 
            show_hexagonal_pattern = si_params.get('show_hexagonal_pattern', True)
            clay_z_tolerance = si_params.get('clay_z_tolerance', 5.0)
            
            # Filter Si atoms by z-position and region
            is_positive_slice = z_center >= 0
            
            if is_positive_slice:
                region_mask = si_positions_all[:, 2] >= 0
            else:
                region_mask = si_positions_all[:, 2] < 0
            
            z_tolerance_mask = np.abs(si_positions_all[:, 2] - z_center) <= clay_z_tolerance
            final_mask = region_mask & z_tolerance_mask
            
            if not np.any(final_mask):
                return
            
            si_positions = si_positions_all[final_mask]
            
            # ✅ GET AXIS LIMITS FOR CLIPPING
            x_min, x_max = ax.get_xlim()
            y_min, y_max = ax.get_ylim()
            
            si_array = si_positions[:, :2]  # Only XY coordinates
            
            # ✅ CLIP SI ATOM POSITIONS TO AXIS BOUNDS
            # Filter Si atoms that are within or near the plot boundaries
            si_visible_mask = (
                (si_array[:, 0] >= x_min - si_connection_threshold) & 
                (si_array[:, 0] <= x_max + si_connection_threshold) &
                (si_array[:, 1] >= y_min - si_connection_threshold) & 
                (si_array[:, 1] <= y_max + si_connection_threshold)
            )
            
            si_array_clipped = si_array[si_visible_mask]
            
            if len(si_array_clipped) == 0:
                return
            
            # Draw connections between nearby Si atoms (with clipping)
            for i in range(len(si_array_clipped)):
                for j in range(i+1, len(si_array_clipped)):
                    distance = np.linalg.norm(si_array_clipped[i] - si_array_clipped[j])
                    
                    if distance < si_connection_threshold:
                        x_coords = [si_array_clipped[i][0], si_array_clipped[j][0]]
                        y_coords = [si_array_clipped[i][1], si_array_clipped[j][1]]
                        
                        # ✅ CHECK IF CONNECTION LINE INTERSECTS WITH PLOT AREA
                        line_x_min, line_x_max = min(x_coords), max(x_coords)
                        line_y_min, line_y_max = min(y_coords), max(y_coords)
                        
                        # Check if line intersects with plot boundaries
                        line_in_bounds = (
                            line_x_max >= x_min and line_x_min <= x_max and
                            line_y_max >= y_min and line_y_min <= y_max
                        )
                        
                        if line_in_bounds:
                            # ✅ CREATE LINE WITH VISUAL CLIPPING
                            if si_connection_style == 'lines':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, zorder=3)[0]
                            elif si_connection_style == 'dashed':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle='--', zorder=3)[0]
                            elif si_connection_style == 'dotted':
                                line = ax.plot(x_coords, y_coords, 
                                    color=si_color, alpha=si_connection_alpha,
                                    linewidth=si_connection_linewidth, 
                                    linestyle=':', zorder=3)[0]
                            
                            # ✅ APPLY VISUAL CLIPPING TO LINE
                            line.set_clip_box(ax.bbox)
            
            # ✅ OPTIONALLY SHOW SI ATOM CENTERS WITH CLIPPING
            if show_hexagonal_pattern:
                # Filter Si centers to only those within plot bounds (with small margin for visibility)
                margin = 0.5  # Small margin to include atoms near edges
                centers_mask = (
                    (si_array_clipped[:, 0] >= x_min - margin) & 
                    (si_array_clipped[:, 0] <= x_max + margin) &
                    (si_array_clipped[:, 1] >= y_min - margin) & 
                    (si_array_clipped[:, 1] <= y_max + margin)
                )
                
                si_centers_visible = si_array_clipped[centers_mask]
                
                if len(si_centers_visible) > 0:
                    scatter = ax.scatter(si_centers_visible[:, 0], si_centers_visible[:, 1], 
                            s=20, c=si_color, alpha=si_center_alpha,
                            marker='o', edgecolors='black', linewidth=0.5,
                            zorder=4, )
                    
                    # ✅ APPLY VISUAL CLIPPING TO SCATTER POINTS
                    scatter.set_clip_box(ax.bbox)
        
        # 🆕 SAVE AND/OR SHOW INDIVIDUAL FIGURES
        if save_individual_figures or show_individual_figures:
            print(f"📄 Processing individual figures...")
            
            for idx, z_idx in enumerate(z_indices_to_plot):
                z_slice_data = z_slices[z_idx]
                z_center = z_slice_data['z_center']
                
                print(f"  Individual figure {idx + 1}/{len(z_indices_to_plot)}: z = {z_center:.2f}°")
                
                # Get dipole data
                if 'grid' not in z_slice_data:
                    print(f"    ⚠️ No dipole orientation grid for z-slice {z_idx}")
                    continue
                
                dipole_grid = z_slice_data['grid']
                x_centers = z_slice_data['x_centers']
                y_centers = z_slice_data['y_centers']
                
                # 🆕 GET REGION-SPECIFIC COLORBAR LIMITS
                vmin_actual, vmax_actual = get_colorbar_limits_for_z(z_center)
                
                # ✅ CREATE SINGLE FIGURE
                fig_single, ax_single = plt.subplots(figsize=individual_figsize, dpi=dpi)
                
                # Create extent for imshow
                x_extent = [x_centers[0], x_centers[-1]]
                y_extent = [y_centers[0], y_centers[-1]]
                
                # Create the dipole plot with region-specific limits
                im = ax_single.imshow(dipole_grid, cmap=cmap, vmin=vmin_actual, vmax=vmax_actual,
                            origin=origin, interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                
                # ✅ FIX: EXPLICITLY SET AXIS LIMITS BEFORE CLAY OVERLAY
                ax_single.set_xlim(x_extent[0], x_extent[1])
                ax_single.set_ylim(y_extent[0], y_extent[1])
                
                # ✅ FIXED: Add clay visualization using clipping functions (same as original)
                if show_clay_spatial and (si_positions is not None or mgo_positions is not None):
                    # Set default parameters if not provided
                    if clay_analysis_params is None:
                        clay_analysis_params = {
                            'mg_vdw_scaling': 2.0,
                            'mgo_color': 'darkgreen',
                            'fade_alpha_min': 0.1,
                            'fade_alpha_max': 0.8,
                            'mgo_radial_fade': True,
                            'si_color': 'orange',
                            'si_connection_threshold': 4,
                            'si_connection_style': 'lines',
                            'si_connection_alpha': 0.6,
                            'si_connection_linewidth': 1.2,
                            'show_hexagonal_pattern': True,
                            'clay_z_tolerance': 5.0
                        }
                    
                    # Use the clay overlay functions defined above
                    if mgo_positions is not None:
                        add_vdw_mg_atoms_fixed(ax_single, mgo_positions, z_center, clay_analysis_params)
                    
                    if si_positions is not None:
                        add_si_network_fixed(ax_single, si_positions, z_center, clay_analysis_params)
                
                # 🆕 NEW: Add clay contour overlay
                if overlay_clay_contours and clay_contour_data:
                    contour_params = {
                        'clay_contour_z_tolerance': clay_contour_z_tolerance,
                        'overlay_mg_contours': overlay_mg_contours,
                        'mg_contour_levels': mg_contour_levels,
                        'mg_contour_color': mg_contour_color,
                        'mg_contour_alpha': mg_contour_alpha,
                        'mg_contour_linewidth': mg_contour_linewidth
                    }
                    _add_clay_contour_overlay(ax_single, z_center, clay_contour_data, contour_params)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    if show_clay_spatial:
                        # title += ' (+ Clay)'
                        pass
                    ax_single.set_title(title, fontsize=title_fontsize)
                
                # Add labels
                ax_single.set_xlabel('x (Å)', fontsize=label_fontsize)
                ax_single.set_ylabel('y (Å)', fontsize=label_fontsize)
                
                # Tick formatting
                ax_single.tick_params(labelsize=tick_fontsize)
                
                # Add colorbar
                if show_colorbar:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax_single)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Dipole Angle (°)', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
                
                # Add grid
                if show_grid:
                    ax_single.grid(True, alpha=grid_alpha)
                
                # Add reference lines at origin for centered systems
                dipole_x_centered = (np.min(x_centers) < 0) and (np.max(x_centers) > 0)
                dipole_y_centered = (np.min(y_centers) < 0) and (np.max(y_centers) > 0)
                
                if dipole_x_centered and dipole_y_centered:
                    ax_single.axhline(y=0, color='white', linestyle='--', alpha=0.5, linewidth=1)
                    ax_single.axvline(x=0, color='white', linestyle='--', alpha=0.5, linewidth=1)
                
                # Add legend if clay atoms are shown
                if show_clay_spatial and (si_positions is not None or mgo_positions is not None):
                    handles, labels = ax_single.get_legend_handles_labels()
                    if handles:
                        ax_single.legend(loc='upper right', fontsize=legend_fontsize-2, framealpha=0.8)
                
                plt.tight_layout()
                
                # Save individual figure
                if save_individual_figures:
                    individual_filename = f'water_dipole_orientation_xy_z{z_center:.1f}A_individual.png'
                    plt.savefig(individual_filename, dpi=dpi, bbox_inches='tight')
                    print(f"    ✅ Saved: {individual_filename}")
                
                # Show individual figure
                if show_individual_figures:
                    plt.show()
                else:
                    plt.close(fig_single)  # Close to save memory
        
        # 🆕 CREATE COMBINED FIGURE (only if requested)
        if show_combined_figure:
            print(f"📊 Creating combined figure...")
            
            # Create figure (YOUR ORIGINAL CODE)
            n_plots = len(z_indices_to_plot)
            if n_plots == 1:
                fig, ax = plt.subplots(figsize=figsize, dpi=dpi)
                axes = [ax]
            else:
                ncols = min(3, n_plots)
                nrows = (n_plots - 1) // ncols + 1
                fig, axes = plt.subplots(nrows, ncols, figsize=(figsize[0]*ncols, figsize[1]*nrows), dpi=dpi)
                if n_plots > 1:
                    axes = axes.flatten() if hasattr(axes, 'flatten') else [axes]

            # Plot each z-slice (YOUR ORIGINAL CODE with the functions already defined above)
            for plot_idx, z_idx in enumerate(z_indices_to_plot):
                ax = axes[plot_idx]
                
                z_slice_data = z_slices[z_idx]
                z_center = z_slice_data['z_center']
                
                # Get dipole data
                if 'grid' not in z_slice_data:
                    print(f"⚠️ No dipole orientation grid for z-slice {z_idx} (z={z_center:.2f})")
                    ax.text(0.5, 0.5, f'No data for z={z_center:.2f}Å', 
                        ha='center', va='center', transform=ax.transAxes)
                    ax.set_title(f'z = {z_center:.2f} Å')
                    continue
                
                dipole_grid = z_slice_data['grid']
                x_centers = z_slice_data['x_centers']
                y_centers = z_slice_data['y_centers']
                
                # 🆕 GET REGION-SPECIFIC COLORBAR LIMITS
                vmin_actual, vmax_actual = get_colorbar_limits_for_z(z_center)
                
                # Create extent for imshow
                x_extent = [x_centers[0], x_centers[-1]]
                y_extent = [y_centers[0], y_centers[-1]]
                
                # Create the dipole plot (use region-specific vmin/vmax)
                im = ax.imshow(dipole_grid, cmap=cmap, vmin=vmin_actual, vmax=vmax_actual,
                            origin=origin, interpolation=interpolation, aspect=aspect,
                            extent=[x_extent[0], x_extent[1], y_extent[0], y_extent[1]])
                            
                # ✅ FIXED: Add clay visualization using clipping functions (YOUR ORIGINAL CODE)
                if show_clay_spatial and (si_positions is not None or mgo_positions is not None):
                    # Set default parameters if not provided
                    if clay_analysis_params is None:
                        clay_analysis_params = {
                            'mg_vdw_scaling': 2.0,
                            'mgo_color': 'darkgreen',  # Note: was 'green', using your logs
                            'fade_alpha_min': 0.1,
                            'fade_alpha_max': 0.8,
                            'mgo_radial_fade': True,
                            'si_color': 'orange',
                            'si_connection_threshold': 4.0,  # Note: using your value from logs
                            'si_connection_style': 'lines',
                            'si_connection_alpha': 0.6,
                            'si_connection_linewidth': 1.2,
                            'show_hexagonal_pattern': True,
                            'clay_z_tolerance': 5.0
                        }
                    
                    # ✅ SET EXPLICIT CLIPPING BOUNDARIES
                    # Option 1: Use a smaller region within the dipole extent for clipping
                    clip_margin = 0.0  # Margin from edges where clipping should occur
                    ax.set_xlim(x_extent[0] + clip_margin, x_extent[1] - clip_margin)
                    ax.set_ylim(y_extent[0] + clip_margin, y_extent[1] - clip_margin)
                    
                    # Now call the clipping functions with the new boundaries
                    if mgo_positions is not None:
                        add_vdw_mg_atoms_fixed(ax, mgo_positions, z_center, clay_analysis_params)
                    
                    if si_positions is not None:
                        add_si_network_fixed(ax, si_positions, z_center, clay_analysis_params)
                    
                    # ✅ RESTORE ORIGINAL EXTENT if you want to show the full dipole data
                    # (Comment out if you want to keep the clipped view)
                    ax.set_xlim(x_extent[0], x_extent[1])
                    ax.set_ylim(y_extent[0], y_extent[1])        
                
                # 🆕 NEW: Add clay contour overlay
                if overlay_clay_contours and clay_contour_data:
                    contour_params = {
                        'clay_contour_z_tolerance': clay_contour_z_tolerance,
                        'overlay_mg_contours': overlay_mg_contours,
                        'mg_contour_levels': mg_contour_levels,
                        'mg_contour_color': mg_contour_color,
                        'mg_contour_alpha': mg_contour_alpha,
                        'mg_contour_linewidth': mg_contour_linewidth
                    }
                    _add_clay_contour_overlay(ax, z_center, clay_contour_data, contour_params)
                
                # Add title
                if show_title:
                    title = f'z = {z_center:.2f} Å'
                    if show_clay_spatial:
                        # title += ' (+ Clay)'
                        pass
                    ax.set_title(title, fontsize=title_fontsize)
                
                # Add labels
                ax.set_xlabel('x (Å)', fontsize=label_fontsize)
                ax.set_ylabel('y (Å)', fontsize=label_fontsize)
                
                # Tick formatting
                ax.tick_params(labelsize=tick_fontsize)
                
                # Add colorbar
                if show_colorbar:
                    from mpl_toolkits.axes_grid1 import make_axes_locatable
                    divider = make_axes_locatable(ax)
                    cax = divider.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar = plt.colorbar(im, cax=cax)
                    cbar.set_label('Dipole Angle (°)', fontsize=colorbar_label_fontsize)
                    cbar.ax.tick_params(labelsize=tick_fontsize)
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha)
                
                # Add reference lines at origin for centered systems
                dipole_x_centered = (np.min(x_centers) < 0) and (np.max(x_centers) > 0)
                dipole_y_centered = (np.min(y_centers) < 0) and (np.max(y_centers) > 0)
                
                if dipole_x_centered and dipole_y_centered:
                    ax.axhline(y=0, color='white', linestyle='--', alpha=0.5, linewidth=1)
                    ax.axvline(x=0, color='white', linestyle='--', alpha=0.5, linewidth=1)
                
                # Add legend if clay atoms are shown
                if show_clay_spatial and (si_positions is not None or mgo_positions is not None):
                    handles, labels = ax.get_legend_handles_labels()
                    if handles:
                        # ax.legend(loc='upper right', fontsize=legend_fontsize-2, framealpha=0.8)
                        pass
            
            # Hide extra subplots
            if n_plots > 1:
                for i in range(n_plots, len(axes)):
                    axes[i].axis('off')
            
            plt.tight_layout()
            
            # 🆕 SAVE COMBINED FIGURE INDEPENDENTLY
            if save_combined_figure:
                combined_filename = f'water_dipole_orientation_xy_COMBINED.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved combined: {combined_filename}")
            
            plt.show()
        else:
            print("Skipping combined figure (show_combined_figure=False)")
            
        # Save if requested (DEPRECATED behavior)
        if save_plots and not save_individual_figures and not save_combined_figure:
            # Generate filename if not provided
            if filename is None:
                base_filename = 'water_dipole_orientation_xy'
                if show_clay_spatial:
                    base_filename += '_with_clay_FIXED'
            else:
                base_filename = filename.split('.')[0] if '.' in filename else filename
            
            filename_full = f"{base_filename}.png"
            
            # Only save if we created a combined figure
            if show_combined_figure:
                plt.savefig(filename_full, dpi=dpi, bbox_inches='tight')
                print(f"✅ Saved (deprecated): {filename_full}")
        
        return fig



