    def plot_clay_atoms_xy(self, clay_results=None, z_slice_centers=None, 
                        z_slice_width=2.0, mg_vdw_scaling=2.0, si_vdw_scaling=1.5,
                        mg_cmap='Reds', si_cmap='Blues', levels=20,
                        
                        # INDIVIDUAL FIGURE CONTROL
                        save_individual_figures=False,
                        show_individual_figures=False, 
                        save_combined_figure=False,
                        show_combined_figure=True,
                        individual_figsize=(8, 7),
                        
                        # PUBLICATION SETTINGS  
                        title_fontsize=16,
                        show_title=False,
                        label_fontsize=14,
                        tick_fontsize=12,
                        legend_fontsize=12,
                        show_legend=False,
                        show_grid=True,
                        grid_alpha=0.3,
                        
                        # INDEPENDENT COLORBAR CONTROL
                        colorbar_pad=0.02,
                        colorbar_width='4%', 
                        mg_vmin=None,      
                        mg_vmax=None,      
                        si_vmin=None,      
                        si_vmax=None,      
                        
                        # COLORBAR STRETCHING/COMPRESSION CONTROL
                        stretch_colorbar=True,
                        
                        # MG LAYER COMBINATION CONTROL
                        combine_mg_layers=True,     # NEW: Combine Mg atoms from both clay layers
                        
                        # NEW: CONTOUR LINE CONTROL
                        show_contour_lines=False,           # Enable/disable contour lines
                        show_contour_fill=True,             # Enable/disable filled contours
                        contour_line_color='white',         # Line color
                        contour_line_alpha=0.3,             # Line transparency
                        contour_line_width=0.5,             # Line thickness
                        contour_levels='auto',              # 'auto', integer, or list of specific levels
                        contour_line_style='-',             # Line style: '-', '--', ':', etc.
                        
                        # EXISTING PARAMETERS
                        figsize=(15, 10), dpi=300, save_plots=True,
                        filename_prefix='clay_atoms_xy', show_plots=True):
        """
        Create standalone clay atom plots with independent colorbar control for Mg and Si.
        
        NEW PARAMETER:
        stretch_colorbar : bool, default=True
            If True, applies intelligent colorbar mapping:
            - When data max < vmax: STRETCHES the colorbar (fills entire range)
            - When data max > vmax: COMPRESSES the colorbar (non-linear mapping for values above vmax)
            If False, uses original behavior (data range determines colorbar).
        
        combine_mg_layers : bool, default=True
            If True, combines Mg atoms from both upper and lower clay layers in all z-slices.
            If False, separates Mg atoms by layer (original behavior).
        
        NEW CONTOUR PARAMETERS:
        show_contour_lines : bool, default=False
            Enable/disable contour lines overlay
        show_contour_fill : bool, default=True
            Enable/disable filled contours (allows contour-only mode when False)
        contour_line_color : str, default='white'
            Color for contour lines
        contour_line_alpha : float, default=0.3
            Transparency for contour lines (0-1)
        contour_line_width : float, default=0.5
            Line thickness for contour lines
        contour_levels : 'auto', int, or list, default='auto'
            Number of contour levels or specific level values
        contour_line_style : str, default='-'
            Line style for contours: '-', '--', ':', '-.'
        """
        from mpl_toolkits.axes_grid1 import make_axes_locatable
        
        print(f"🎨 Creating clay atom plots with independent colorbar control...")
        
        # Set default z-slice centers if not provided
        if z_slice_centers is None:
            z_slice_centers = [-24, 0, 24]
        
        # Calculate clay spatial distribution if not provided
        if clay_results is None:
            print(f"  📊 Calculating clay spatial distribution...")
            clay_results = self.analysis.calculate_clay_spatial_distribution_xy(
                z_slice_centers=z_slice_centers,
                z_slice_width=z_slice_width,
                mg_vdw_scaling=mg_vdw_scaling,
                si_vdw_scaling=si_vdw_scaling,
                use_cache=True,
                step=10,
                return_format='grids',
                combine_mg_layers=combine_mg_layers  # Pass the new parameter
            )
            
            if not clay_results or not clay_results.get('z_slices'):
                print(f"  ❌ No clay data available for plotting")
                return {}
        
        # Use provided colorbar limits directly
        mg_vmin_calc = mg_vmin
        mg_vmax_calc = mg_vmax
        si_vmin_calc = si_vmin
        si_vmax_calc = si_vmax
        
        # COLORBAR STRETCHING/COMPRESSION HELPER FUNCTION
        def apply_compression_mapping(grid_data, vmin, vmax, element_name):
            """
            Apply intelligent colorbar mapping - handles BOTH compression AND stretching
            """
            if vmin is None or vmax is None:
                return grid_data
            
            data_min = np.nanmin(grid_data)
            data_max = np.nanmax(grid_data)
            
            print(f"    🎯 Processing {element_name}:")
            print(f"       Original range: {data_min:.3f} to {data_max:.3f}")
            print(f"       Target range: {vmin} to {vmax}")
            
            if data_max <= vmax:
                # STRETCHING case: data max < vmax, stretch to fill colorbar
                print(f"       Mode: STRETCHING (data max ≤ vmax)")
                grid_processed = grid_data.copy()
                
                # Force minimum and maximum values to exist in the data
                if np.min(grid_processed) > vmin:
                    grid_processed.flat[0] = vmin  # Set one pixel to minimum
                if np.max(grid_processed) < vmax:
                    grid_processed.flat[1] = vmax  # Set one pixel to maximum
                
                print(f"       Final range: {np.min(grid_processed):.3f} to {np.max(grid_processed):.3f}")
                print(f"       ✅ Final range matches target: [{vmin}, {vmax}]")
                return grid_processed
            
            else:
                # COMPRESSION case: data max > vmax, compress high values
                print(f"       Mode: COMPRESSION (data max > vmax)")
                
                # Use 80% of colorbar for linear range (vmin to vmax)
                # Use 20% of colorbar for compressed range (vmax to data_max)
                linear_fraction = 0.8
                
                # Calculate the boundary between linear and compressed regions IN FINAL SCALE
                linear_boundary = vmin + (vmax - vmin) * linear_fraction
                
                # Create output array
                compressed_data = np.full_like(grid_data, np.nan)
                
                # Linear mapping for values <= vmax (maps to vmin → linear_boundary)
                linear_mask = grid_data <= vmax
                if np.any(linear_mask):
                    linear_data = grid_data[linear_mask]
                    compressed_data[linear_mask] = vmin + (linear_data - data_min) / (vmax - data_min) * (linear_boundary - vmin)
                
                # Compressed mapping for values > vmax (maps to linear_boundary → vmax)
                compress_mask = grid_data > vmax
                if np.any(compress_mask):
                    excess_data = grid_data[compress_mask] - vmax
                    max_excess = data_max - vmax
                    
                    # Logarithmic compression: compress [0, max_excess] to [linear_boundary, vmax]
                    normalized_excess = np.log(1 + excess_data) / np.log(1 + max_excess)
                    compressed_data[compress_mask] = linear_boundary + normalized_excess * (vmax - linear_boundary)
                
                # CRITICAL: Ensure exact vmin and vmax values exist in the data
                if np.nanmin(compressed_data) > vmin:
                    compressed_data.flat[0] = vmin
                if np.nanmax(compressed_data) < vmax:
                    compressed_data.flat[1] = vmax
                
                print(f"       Final range: {np.nanmin(compressed_data):.3f} to {np.nanmax(compressed_data):.3f}")
                print(f"       Linear region: {vmin:.3f} to {linear_boundary:.3f} (maps data: {data_min:.3f} to {vmax:.3f})")
                print(f"       Compressed region: {linear_boundary:.3f} to {vmax:.3f} (maps data: {vmax:.3f} to {data_max:.3f})")
                print(f"       ✅ Final range matches target: [{vmin}, {vmax}]")
                
                return compressed_data
        
        # NEW: CONTOUR PLOTTING HELPER FUNCTION
        def plot_contours(ax, X, Y, grid_data, vmin_val, vmax_val, cmap_val, element_name):
            """
            Plot contours (filled and/or lines) based on settings
            """
            # Determine contour levels
            if contour_levels == 'auto':
                n_levels = levels  # Use the existing levels parameter
            elif isinstance(contour_levels, int):
                n_levels = contour_levels
            else:
                n_levels = contour_levels  # Assume it's a list of specific levels
            
            im = None
            
            # Plot filled contours if enabled
            if show_contour_fill:
                im = ax.contourf(X, Y, grid_data, levels=n_levels, cmap=cmap_val,
                            vmin=vmin_val, vmax=vmax_val)
            
            # Plot contour lines if enabled
            if show_contour_lines:
                cs = ax.contour(X, Y, grid_data, levels=n_levels, 
                            colors=contour_line_color, alpha=contour_line_alpha,
                            linewidths=contour_line_width, linestyles=contour_line_style)
            
            return im
        
        plot_info = {
            'n_slices': len(clay_results['z_slices']),
            'z_centers': z_slice_centers,
            'individual_filenames': {
                'mg': [],
                'si': []
            },
            'combined_filename': None,
            'mg_scale': (mg_vmin_calc, mg_vmax_calc),
            'si_scale': (si_vmin_calc, si_vmax_calc),
            'colorbar_stretching': stretch_colorbar,
            'mg_layers_combined': combine_mg_layers,  # Track if Mg layers are combined
            'contour_settings': {
                'show_lines': show_contour_lines,
                'show_fill': show_contour_fill,
                'line_color': contour_line_color,
                'line_alpha': contour_line_alpha
            }
        }
        
        print(f"  📈 Creating plots for {plot_info['n_slices']} z-slices...")
        if stretch_colorbar and (mg_vmin_calc is not None or mg_vmax_calc is not None or 
                                si_vmin_calc is not None or si_vmax_calc is not None):
            print(f"  🎯 Colorbar stretching/compression: ENABLED")
        else:
            print(f"  🎯 Colorbar stretching/compression: DISABLED")
        
        if combine_mg_layers:
            print(f"  🔗 Mg layer combination: ENABLED (showing Mg from both clay layers)")
        else:
            print(f"  🔗 Mg layer combination: DISABLED (separating Mg by layer)")
        
        # NEW: Print contour settings
        if show_contour_lines:
            print(f"  📏 Contour lines: ENABLED (color={contour_line_color}, α={contour_line_alpha})")
        if not show_contour_fill:
            print(f"  🔲 Contour fill: DISABLED (lines-only mode)")
        
        # INDIVIDUAL FIGURES PROCESSING WITH CONSISTENT SCALES
        if save_individual_figures or show_individual_figures:
            print(f"  📄 Processing individual figures with CONSISTENT colorbar scales...")
            
            for slice_idx, slice_data in enumerate(clay_results['z_slices']):
                z_center = slice_data['z_center']
                
                print(f"    Individual figures {slice_idx + 1}/{plot_info['n_slices']}: z = {z_center:.1f} Å")
                
                # Check if we have grid data
                if 'mg_grid' not in slice_data or 'si_grid' not in slice_data:
                    print(f"      ⚠️ No grid data available for z = {z_center:.1f} Å")
                    continue
                
                # Extract grid data
                mg_grid_original = slice_data['mg_grid']
                si_grid_original = slice_data['si_grid']
                x_centers = slice_data['x_centers']
                y_centers = slice_data['y_centers']
                
                # Apply colorbar stretching/compression (if enabled)
                if stretch_colorbar:
                    mg_grid = apply_compression_mapping(mg_grid_original, mg_vmin_calc, mg_vmax_calc, 'Mg')
                    si_grid = apply_compression_mapping(si_grid_original, si_vmin_calc, si_vmax_calc, 'Si')
                else:
                    mg_grid = mg_grid_original
                    si_grid = si_grid_original
                
                # Create meshgrid
                X, Y = np.meshgrid(x_centers, y_centers)
                
                # CREATE SEPARATE Mg FIGURE WITH CONSISTENT SCALE
                if np.max(mg_grid_original) > 0:  # Check original data for existence
                    fig_mg, ax_mg = plt.subplots(figsize=individual_figsize)
                    
                    # NEW: Use contour plotting function
                    im_mg = plot_contours(ax_mg, X, Y, mg_grid, mg_vmin_calc, mg_vmax_calc, mg_cmap, 'Mg')
                    
                    if show_title:
                        title_suffix = " (Combined)" if combine_mg_layers else ""
                        ax_mg.set_title(f'Mg Atoms (z = {z_center:.1f} Å){title_suffix}', 
                                    fontweight='bold', fontsize=title_fontsize)
                    ax_mg.set_xlabel('X (Å)', fontsize=label_fontsize)
                    ax_mg.set_ylabel('Y (Å)', fontsize=label_fontsize)
                    ax_mg.tick_params(labelsize=tick_fontsize)
                    ax_mg.set_aspect('equal')
                    
                    if show_grid:
                        ax_mg.grid(True, alpha=grid_alpha)
                    
                    # Add colorbar with consistent scale (only if filled contours are shown)
                    if show_contour_fill and im_mg is not None:
                        divider_mg = make_axes_locatable(ax_mg)
                        cax_mg = divider_mg.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar_mg = plt.colorbar(im_mg, cax=cax_mg)
                        cbar_mg.set_label('Mg Density', fontsize=label_fontsize)
                        cbar_mg.ax.tick_params(labelsize=tick_fontsize)
                    
                    plt.tight_layout()
                    
                    # Save individual Mg plot
                    if save_individual_figures:
                        layer_suffix = "_combined" if combine_mg_layers else ""
                        contour_suffix = "_lines" if show_contour_lines and not show_contour_fill else ""
                        mg_filename = f'{filename_prefix}_z{z_center:.1f}A_Mg{layer_suffix}{contour_suffix}_individual.png'
                        plt.savefig(mg_filename, dpi=dpi, bbox_inches='tight')
                        plot_info['individual_filenames']['mg'].append(mg_filename)
                        print(f"        ✅ Saved Mg: {mg_filename}")
                    
                    # Show individual Mg plot
                    if show_individual_figures:
                        plt.show()
                    else:
                        plt.close(fig_mg)
                
                # CREATE SEPARATE Si FIGURE WITH CONSISTENT SCALE
                if np.max(si_grid_original) > 0:  # Check original data for existence
                    fig_si, ax_si = plt.subplots(figsize=individual_figsize)
                    
                    # NEW: Use contour plotting function
                    im_si = plot_contours(ax_si, X, Y, si_grid, si_vmin_calc, si_vmax_calc, si_cmap, 'Si')
                    
                    if show_title:
                        ax_si.set_title(f'Si Atoms (z = {z_center:.1f} Å)', 
                                    fontweight='bold', fontsize=title_fontsize)
                    ax_si.set_xlabel('X (Å)', fontsize=label_fontsize)
                    ax_si.set_ylabel('Y (Å)', fontsize=label_fontsize)
                    ax_si.tick_params(labelsize=tick_fontsize)
                    ax_si.set_aspect('equal')
                    
                    if show_grid:
                        ax_si.grid(True, alpha=grid_alpha)
                    
                    # Add colorbar with consistent scale (only if filled contours are shown)
                    if show_contour_fill and im_si is not None:
                        divider_si = make_axes_locatable(ax_si)
                        cax_si = divider_si.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                        cbar_si = plt.colorbar(im_si, cax=cax_si)
                        cbar_si.set_label('Si Density', fontsize=label_fontsize)
                        cbar_si.ax.tick_params(labelsize=tick_fontsize)
                    
                    plt.tight_layout()
                    
                    # Save individual Si plot
                    if save_individual_figures:
                        contour_suffix = "_lines" if show_contour_lines and not show_contour_fill else ""
                        si_filename = f'{filename_prefix}_z{z_center:.1f}A_Si{contour_suffix}_individual.png'
                        plt.savefig(si_filename, dpi=dpi, bbox_inches='tight')
                        plot_info['individual_filenames']['si'].append(si_filename)
                        print(f"        ✅ Saved Si: {si_filename}")
                    
                    # Show individual Si plot
                    if show_individual_figures:
                        plt.show()
                    else:
                        plt.close(fig_si)
        
        # COMBINED FIGURE PROCESSING WITH CONSISTENT SCALES
        if show_combined_figure:
            print(f"  📊 Creating combined figure with consistent scales...")
            self._create_clay_summary_plot(clay_results, mg_cmap, si_cmap, levels,
                                        figsize, dpi, save_plots, filename_prefix,
                                        title_fontsize, label_fontsize, tick_fontsize,
                                        show_title, show_grid, grid_alpha, show_legend,
                                        colorbar_pad, colorbar_width, 
                                        mg_vmin_calc, mg_vmax_calc,    
                                        si_vmin_calc, si_vmax_calc,   
                                        stretch_colorbar,
                                        # NEW: Pass contour parameters
                                        show_contour_lines, show_contour_fill,
                                        contour_line_color, contour_line_alpha,
                                        contour_line_width, contour_levels, contour_line_style)              
            
            if save_combined_figure:
                layer_suffix = "_combined" if combine_mg_layers else ""
                contour_suffix = "_lines" if show_contour_lines and not show_contour_fill else ""
                combined_filename = f'{filename_prefix}{layer_suffix}{contour_suffix}_combined.png'
                plt.savefig(combined_filename, dpi=dpi, bbox_inches='tight')
                print(f"✓ Combined clay atoms plot saved as: {combined_filename}")
        
        print(f"  ✅ Clay atom plotting complete!")
        
        return plot_info

    def _create_clay_summary_plot(self, clay_results, mg_cmap, si_cmap, levels,
                                figsize, dpi, save_plots, filename_prefix,
                                title_fontsize, label_fontsize, tick_fontsize,
                                show_title, show_grid, grid_alpha, show_legend,
                                colorbar_pad, colorbar_width, 
                                mg_vmin, mg_vmax, si_vmin, si_vmax,
                                stretch_colorbar=True,
                                # NEW: Contour parameters
                                show_contour_lines=False, show_contour_fill=True,
                                contour_line_color='white', contour_line_alpha=0.3,
                                contour_line_width=0.5, contour_levels='auto', contour_line_style='-'):
        """
        Create a summary plot showing all z-slices with independent colorbar control for Mg and Si
        """
        import numpy as np
        import matplotlib.pyplot as plt
        from mpl_toolkits.axes_grid1 import make_axes_locatable
        
        # 🆕 SAME COLORBAR STRETCHING HELPER FUNCTION
        def apply_colorbar_stretching(grid, vmin, vmax, element_name):
            """Apply colorbar stretching fix to ensure full range utilization"""
            if not stretch_colorbar or vmin is None or vmax is None:
                return grid.copy()
            
            data_min = np.min(grid)
            data_max = np.max(grid)
            
            if data_min >= vmin and data_max >= vmax:
                return grid.copy()
            
            grid_stretched = grid.copy()
            
            if data_min > vmin:
                grid_stretched[0, 0] = vmin
            if data_max < vmax:
                grid_stretched[0, 1] = vmax
            
            return grid_stretched
        
        # NEW: CONTOUR PLOTTING HELPER FUNCTION
        def plot_contours(ax, X, Y, grid_data, vmin_val, vmax_val, cmap_val, element_name):
            """
            Plot contours (filled and/or lines) based on settings
            """
            # Determine contour levels
            if contour_levels == 'auto':
                n_levels = levels  # Use the existing levels parameter
            elif isinstance(contour_levels, int):
                n_levels = contour_levels
            else:
                n_levels = contour_levels  # Assume it's a list of specific levels
            
            im = None
            
            # Plot filled contours if enabled
            if show_contour_fill:
                im = ax.contourf(X, Y, grid_data, levels=n_levels, cmap=cmap_val,
                            vmin=vmin_val, vmax=vmax_val)
            
            # Plot contour lines if enabled
            if show_contour_lines:
                cs = ax.contour(X, Y, grid_data, levels=n_levels, 
                            colors=contour_line_color, alpha=contour_line_alpha,
                            linewidths=contour_line_width, linestyles=contour_line_style)
            
            return im
        
        n_slices = len(clay_results['z_slices'])
        
        # Create subplot grid - 2 rows (Mg top, Si bottom), n_slices columns
        if n_slices <= 3:
            fig, axes = plt.subplots(2, n_slices, figsize=figsize, dpi=dpi)
        else:
            # For more slices, create a larger grid but limit columns to avoid overcrowding
            n_cols = min(4, n_slices)  # Maximum 4 columns
            n_slice_rows = (n_slices + n_cols - 1) // n_cols  # How many rows of z-slices needed
            n_total_rows = 2 * n_slice_rows  # Each z-slice needs 2 rows (Mg + Si)
            
            # Adjust figure size for larger grids
            adjusted_figsize = (figsize[0] * n_cols / 3, figsize[1] * n_slice_rows / 1.5)
            fig, axes = plt.subplots(n_total_rows, n_cols, figsize=adjusted_figsize, dpi=dpi)
        
        # Ensure axes is 2D for consistent indexing
        if n_slices == 1:
            axes = axes.reshape(2, 1)
        elif axes.ndim == 1:
            axes = axes.reshape(-1, 1)
        
        # Process each z-slice
        for slice_idx, slice_data in enumerate(clay_results['z_slices']):
            if n_slices > 3:
                # For larger grids, calculate row and column differently
                n_cols = min(4, n_slices)
                slice_row = (slice_idx // n_cols) * 2  # Each slice occupies 2 rows
                slice_col = slice_idx % n_cols
                
                # Skip if we've exceeded available subplot positions
                if slice_row + 1 >= axes.shape[0] or slice_col >= axes.shape[1]:
                    continue
            else:
                # For 3 or fewer slices, use simple layout
                slice_row = 0
                slice_col = slice_idx
            
            z_center = slice_data['z_center']
            
            # Check for grid data
            if 'mg_grid' not in slice_data or 'si_grid' not in slice_data:
                # Add placeholder text for missing data
                if n_slices > 3:
                    axes[slice_row, slice_col].text(0.5, 0.5, 'No Mg data', 
                                                    ha='center', va='center', transform=axes[slice_row, slice_col].transAxes)
                    axes[slice_row + 1, slice_col].text(0.5, 0.5, 'No Si data', 
                                                        ha='center', va='center', transform=axes[slice_row + 1, slice_col].transAxes)
                else:
                    axes[0, slice_col].text(0.5, 0.5, 'No Mg data', 
                                            ha='center', va='center', transform=axes[0, slice_col].transAxes)
                    axes[1, slice_col].text(0.5, 0.5, 'No Si data', 
                                            ha='center', va='center', transform=axes[1, slice_col].transAxes)
                continue
            
            # Extract grid data
            mg_grid_original = slice_data['mg_grid']
            si_grid_original = slice_data['si_grid']
            x_centers = slice_data['x_centers']
            y_centers = slice_data['y_centers']
            
            # 🆕 APPLY COLORBAR STRETCHING (if enabled)
            mg_grid = apply_colorbar_stretching(mg_grid_original, mg_vmin, mg_vmax, 'Mg')
            si_grid = apply_colorbar_stretching(si_grid_original, si_vmin, si_vmax, 'Si')
            
            # Create meshgrid
            X, Y = np.meshgrid(x_centers, y_centers)
            
            # Determine axis indices based on grid layout
            if n_slices > 3:
                mg_ax = axes[slice_row, slice_col]
                si_ax = axes[slice_row + 1, slice_col]
            else:
                mg_ax = axes[0, slice_col]
                si_ax = axes[1, slice_col]
            
            # 🎯 PLOT MG (TOP ROW) WITH INDEPENDENT SCALE - FIXED
            if np.max(mg_grid_original) > 0:  # Check original data for existence
                # NEW: Use contour plotting function
                im1 = plot_contours(mg_ax, X, Y, mg_grid, mg_vmin, mg_vmax, mg_cmap, 'Mg')
                
                # Add colorbar for Mg with consistent scale (only if filled contours are shown)
                if show_contour_fill and im1 is not None:
                    divider1 = make_axes_locatable(mg_ax)
                    cax1 = divider1.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar1 = plt.colorbar(im1, cax=cax1)
                    cbar1.set_label('Mg Density', fontsize=max(6, label_fontsize - 2))
                    cbar1.ax.tick_params(labelsize=max(6, tick_fontsize - 2))
                
            else:
                mg_ax.text(0.5, 0.5, 'No Mg atoms', ha='center', va='center',
                        transform=mg_ax.transAxes, fontsize=max(8, label_fontsize - 2))
            
            # Format Mg subplot
            if show_title:
                mg_ax.set_title(f'Mg (z = {z_center:.1f} Å)', 
                            fontsize=max(8, title_fontsize - 4), fontweight='bold')
            
            mg_ax.set_aspect('equal')
            mg_ax.tick_params(labelsize=max(6, tick_fontsize - 2))
            
            # Only show axis labels on leftmost column
            if slice_col == 0:
                mg_ax.set_ylabel('Y (Å)', fontsize=max(8, label_fontsize - 2))
            else:
                mg_ax.set_ylabel('')
            
            if show_grid:
                mg_ax.grid(True, alpha=grid_alpha)
            
            # 🎯 PLOT SI (BOTTOM ROW) WITH INDEPENDENT SCALE - FIXED
            if np.max(si_grid_original) > 0:  # Check original data for existence
                # NEW: Use contour plotting function
                im2 = plot_contours(si_ax, X, Y, si_grid, si_vmin, si_vmax, si_cmap, 'Si')
                
                # Add colorbar for Si with consistent scale (only if filled contours are shown)
                if show_contour_fill and im2 is not None:
                    divider2 = make_axes_locatable(si_ax)
                    cax2 = divider2.append_axes("right", size=colorbar_width, pad=colorbar_pad)
                    cbar2 = plt.colorbar(im2, cax=cax2)
                    cbar2.set_label('Si Density', fontsize=max(6, label_fontsize - 2))
                    cbar2.ax.tick_params(labelsize=max(6, tick_fontsize - 2))
                
            else:
                si_ax.text(0.5, 0.5, 'No Si atoms', ha='center', va='center',
                        transform=si_ax.transAxes, fontsize=max(8, label_fontsize - 2))
            
            # Format Si subplot
            if show_title:
                si_ax.set_title(f'Si (z = {z_center:.1f} Å)', 
                            fontsize=max(8, title_fontsize - 4), fontweight='bold')
            
            si_ax.set_aspect('equal')
            si_ax.tick_params(labelsize=max(6, tick_fontsize - 2))
            
            # Add X-axis label to bottom row
            si_ax.set_xlabel('X (Å)', fontsize=max(8, label_fontsize - 2))
            
            # Only show Y-axis label on leftmost column
            if slice_col == 0:
                si_ax.set_ylabel('Y (Å)', fontsize=max(8, label_fontsize - 2))
            else:
                si_ax.set_ylabel('')
            
            if show_grid:
                si_ax.grid(True, alpha=grid_alpha)
        
        # Hide unused subplots for larger grids
        if n_slices > 3:
            n_cols = min(4, n_slices)
            total_slice_pairs_needed = n_slices
            
            # Hide unused subplot pairs
            for pair_idx in range(total_slice_pairs_needed, (axes.shape[0] // 2) * n_cols):
                row_start = (pair_idx // n_cols) * 2
                col = pair_idx % n_cols
                
                if row_start < axes.shape[0] and col < axes.shape[1]:
                    axes[row_start, col].set_visible(False)
                    if row_start + 1 < axes.shape[0]:
                        axes[row_start + 1, col].set_visible(False)
        else:
            # Hide unused subplots for simple layout
            for slice_idx in range(n_slices, axes.shape[1]):
                axes[0, slice_idx].set_visible(False)
                axes[1, slice_idx].set_visible(False)
        
        # Add overall figure title
        if show_title:
            title_text = f'Clay Atoms XY Distribution - {n_slices} Z-Slices'
            fig.suptitle(title_text, fontsize=max(10, title_fontsize - 2), 
                        fontweight='bold', y=0.98)
        
        plt.tight_layout(rect=[0, 0, 1, 0.95] if show_title else [0, 0, 1, 1])
        
        # Save the combined plot
        if save_plots:
            summary_filename = f'{filename_prefix}_combined.png'
            plt.savefig(summary_filename, dpi=dpi, bbox_inches='tight')
        
        plt.show()



    def debug_colorbar_clipping_step_by_step(self):
        """
        Debug method to identify exactly what's happening with colorbar clipping
        """
        import numpy as np
        import matplotlib.pyplot as plt
        from mpl_toolkits.axes_grid1 import make_axes_locatable
        
        print(f"\n{'='*80}")
        print(f"🔍 DEBUGGING COLORBAR CLIPPING STEP BY STEP")
        print(f"{'='*80}")
        
        # Get clay data for testing
        clay_results = self.analysis.calculate_clay_spatial_distribution_xy(
            z_slice_centers=[27.0, -27.0],
            z_slice_width=6.0,
            mg_vdw_scaling=2.0,
            si_vdw_scaling=1.5,
            use_cache=True,
            step=10,
            return_format='grids'
        )
        
        if not clay_results or not clay_results.get('z_slices'):
            print("❌ No clay data available")
            return
        
        slice_data = clay_results['z_slices'][0]
        si_grid_original = slice_data['si_grid']
        x_centers = slice_data['x_centers']
        y_centers = slice_data['y_centers']
        X, Y = np.meshgrid(x_centers, y_centers)
        
        # Test parameters
        si_vmin, si_vmax = 0, 36
        
        print(f"\n1️⃣ ORIGINAL DATA ANALYSIS:")
        print(f"   Si grid shape: {si_grid_original.shape}")
        print(f"   Si grid dtype: {si_grid_original.dtype}")
        print(f"   Si data range: {np.min(si_grid_original):.6f} to {np.max(si_grid_original):.6f}")
        print(f"   Target colorbar range: {si_vmin} to {si_vmax}")
        
        # Check if data exceeds target range
        exceeds_max = np.sum(si_grid_original > si_vmax)
        below_min = np.sum(si_grid_original < si_vmin)
        total_points = si_grid_original.size
        
        print(f"   Points above vmax ({si_vmax}): {exceeds_max} ({exceeds_max/total_points*100:.2f}%)")
        print(f"   Points below vmin ({si_vmin}): {below_min} ({below_min/total_points*100:.2f}%)")
        
        # Test different approaches
        approaches = [
            ("No processing", lambda data: data),
            ("Simple clipping", lambda data: np.clip(data, si_vmin, si_vmax)),
            ("Clipping + min extension", lambda data: _extend_min(np.clip(data, si_vmin, si_vmax), si_vmin)),
            ("Clipping + max extension", lambda data: _extend_max(np.clip(data, si_vmin, si_vmax), si_vmax)),
            ("Clipping + both extensions", lambda data: _extend_both(np.clip(data, si_vmin, si_vmax), si_vmin, si_vmax)),
        ]
        
        def _extend_min(data, vmin):
            data_copy = data.copy()
            if np.min(data_copy) > vmin:
                data_copy.flat[0] = vmin
            return data_copy
        
        def _extend_max(data, vmax):
            data_copy = data.copy()
            if np.max(data_copy) < vmax:
                data_copy.flat[1] = vmax
            return data_copy
        
        def _extend_both(data, vmin, vmax):
            data_copy = data.copy()
            if np.min(data_copy) > vmin:
                data_copy.flat[0] = vmin
            if np.max(data_copy) < vmax:
                data_copy.flat[1] = vmax
            return data_copy
        
        # Create figure for testing
        n_approaches = len(approaches)
        fig, axes = plt.subplots(2, 3, figsize=(18, 12))
        axes = axes.flatten()
        
        print(f"\n2️⃣ TESTING DIFFERENT APPROACHES:")
        
        for idx, (approach_name, process_func) in enumerate(approaches):
            if idx >= len(axes):
                break
                
            ax = axes[idx]
            
            print(f"\n   {approach_name.upper()}:")
            
            # Process data
            processed_data = process_func(si_grid_original)
            
            print(f"     Processed range: {np.min(processed_data):.6f} to {np.max(processed_data):.6f}")
            
            # Test with contourf (what we actually use)
            try:
                im = ax.contourf(X, Y, processed_data, levels=20, cmap='YlOrRd',
                            vmin=si_vmin, vmax=si_vmax)
                
                # Get actual colorbar limits
                actual_vmin, actual_vmax = im.get_clim()
                print(f"     Actual colorbar limits: {actual_vmin:.6f} to {actual_vmax:.6f}")
                print(f"     Target colorbar limits: {si_vmin} to {si_vmax}")
                
                # Check if they match
                vmin_match = abs(actual_vmin - si_vmin) < 1e-6
                vmax_match = abs(actual_vmax - si_vmax) < 1e-6
                
                if vmin_match and vmax_match:
                    print(f"     ✅ SUCCESS: Colorbar limits match target exactly!")
                else:
                    print(f"     ❌ MISMATCH: vmin_match={vmin_match}, vmax_match={vmax_match}")
                
                # Add colorbar
                divider = make_axes_locatable(ax)
                cax = divider.append_axes("right", size='4%', pad=0.1)
                cbar = plt.colorbar(im, cax=cax)
                
                # Set exact ticks to verify
                ticks = np.linspace(si_vmin, si_vmax, 7)
                cbar.set_ticks(ticks)
                cbar.set_ticklabels([f'{t:.0f}' for t in ticks])
                
            except Exception as e:
                print(f"     ❌ ERROR: {e}")
                ax.text(0.5, 0.5, f'ERROR\n{e}', ha='center', va='center', 
                    transform=ax.transAxes, fontsize=10, 
                    bbox=dict(boxstyle='round', facecolor='red', alpha=0.3))
            
            ax.set_title(f'{approach_name}\nRange: {np.min(processed_data):.3f} to {np.max(processed_data):.3f}')
            ax.set_aspect('equal')
        
        # Hide unused subplots
        for idx in range(len(approaches), len(axes)):
            axes[idx].axis('off')
        
        plt.tight_layout()
        plt.show()
        
        print(f"\n3️⃣ DETAILED CONTOURF ANALYSIS:")
        
        # Test what happens with contourf specifically
        test_data = np.clip(si_grid_original, si_vmin, si_vmax)
        test_data.flat[0] = si_vmin
        test_data.flat[1] = si_vmax
        
        fig, ax = plt.subplots(figsize=(8, 6))
        
        print(f"   Test data range: {np.min(test_data):.6f} to {np.max(test_data):.6f}")
        
        # Create contourf
        im = ax.contourf(X, Y, test_data, levels=20, cmap='YlOrRd',
                    vmin=si_vmin, vmax=si_vmax)
        
        print(f"   Contourf input vmin/vmax: {si_vmin}, {si_vmax}")
        print(f"   Contourf actual clim: {im.get_clim()}")
        print(f"   Contourf levels: {im.levels}")
        print(f"   Number of levels: {len(im.levels)}")
        
        # Check level distribution
        levels = im.levels
        level_range = levels[-1] - levels[0]
        expected_range = si_vmax - si_vmin
        
        print(f"   Level range: {level_range:.6f}")
        print(f"   Expected range: {expected_range}")
        print(f"   Range match: {abs(level_range - expected_range) < 1e-6}")
        
        # Add colorbar with explicit control
        divider = make_axes_locatable(ax)
        cax = divider.append_axes("right", size='4%', pad=0.1)
        cbar = plt.colorbar(im, cax=cax)
        
        # Force colorbar ticks
        manual_ticks = np.linspace(si_vmin, si_vmax, 7)
        cbar.set_ticks(manual_ticks)
        cbar.set_ticklabels([f'{t:.0f}' for t in manual_ticks])
        cbar.set_label('Si Density (Manual Ticks)')
        
        ax.set_title('Detailed Contourf Test')
        ax.set_aspect('equal')
        
        plt.tight_layout()
        plt.show()
        
        print(f"\n4️⃣ MATPLOTLIB VERSION & SETTINGS CHECK:")
        print(f"   Matplotlib version: {plt.matplotlib.__version__}")
        print(f"   Backend: {plt.get_backend()}")
        
        # Test with different parameters
        print(f"\n5️⃣ PARAMETER SENSITIVITY TEST:")
        
        for test_levels in [10, 20, 50]:
            for test_extend in ['neither', 'both', 'min', 'max']:
                try:
                    fig, ax = plt.subplots(figsize=(6, 4))
                    im = ax.contourf(X, Y, test_data, levels=test_levels, 
                                cmap='YlOrRd', vmin=si_vmin, vmax=si_vmax,
                                extend=test_extend)
                    actual_range = im.get_clim()
                    range_match = abs(actual_range[0] - si_vmin) < 1e-6 and abs(actual_range[1] - si_vmax) < 1e-6
                    
                    print(f"   levels={test_levels}, extend='{test_extend}': {actual_range} -> {'✅' if range_match else '❌'}")
                    plt.close(fig)
                    
                    if range_match:
                        print(f"     🎯 WORKING COMBINATION: levels={test_levels}, extend='{test_extend}'")
                        
                except Exception as e:
                    print(f"   levels={test_levels}, extend='{test_extend}': ERROR - {e}")
        
        print(f"\n{'='*80}")
        print(f"🔍 DEBUG COMPLETE")
        print(f"{'='*80}\n")



