    def plot_solvation_shells_vs_z(self, save_plots=True, figsize=None, filename=None):
        '''Plot solvation shell analysis results vs z-position'''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'solvation_shells_vs_z'):
            print("No solvation shell data available. Run calculate_solvation_shells_vs_z_detailed() first.")
            return
        
        solvation_data = self.analysis.results.solvation_shells_vs_z
        z_centers = solvation_data['z_centers']
        
        figsize = figsize or (16, 12)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        # Plot 1: First shell water coordination vs z
        ax1 = axes[0, 0]
        if 'first_shell' in solvation_data['shell_water_counts']:
            for ion_type, water_counts in solvation_data['shell_water_counts']['first_shell'].items():
                ax1.plot(z_centers, water_counts, linewidth=2, marker='o', markersize=4, label=ion_type)
        
        ax1.set_xlabel('z (Å)')
        ax1.set_ylabel('Waters in First Shell')
        ax1.set_title('First Solvation Shell Hydration vs Z', fontweight='bold')
        ax1.legend()
        ax1.grid(True, alpha=0.3)
        ax1.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 2: Second shell water coordination vs z
        ax2 = axes[0, 1]
        if 'second_shell' in solvation_data['shell_water_counts']:
            for ion_type, water_counts in solvation_data['shell_water_counts']['second_shell'].items():
                ax2.plot(z_centers, water_counts, linewidth=2, marker='s', markersize=4, label=ion_type)
        
        ax2.set_xlabel('z (Å)')
        ax2.set_ylabel('Waters in Second Shell')
        ax2.set_title('Second Solvation Shell Hydration vs Z', fontweight='bold')
        ax2.legend()
        ax2.grid(True, alpha=0.3)
        ax2.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 3: Total coordination numbers vs z
        ax3 = axes[1, 0]
        if 'coordination_numbers' in solvation_data:
            for ion_type, coord_nums in solvation_data['coordination_numbers'].items():
                ax3.plot(z_centers, coord_nums, linewidth=2, marker='^', markersize=4, label=ion_type)
        
        ax3.set_xlabel('z (Å)')
        ax3.set_ylabel('Coordination Number')
        ax3.set_title('Total Coordination Number vs Z', fontweight='bold')
        ax3.legend()
        ax3.grid(True, alpha=0.3)
        ax3.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        # Plot 4: Shell comparison for a selected ion type
        ax4 = axes[1, 1]
        
        # Choose first ion type for detailed shell comparison
        if solvation_data['shell_water_counts']:
            first_shell_name = list(solvation_data['shell_water_counts'].keys())[0]
            ion_types = list(solvation_data['shell_water_counts'][first_shell_name].keys())
            
            if ion_types:
                selected_ion = ion_types[0]
                
                for shell_name in solvation_data['shell_water_counts'].keys():
                    if selected_ion in solvation_data['shell_water_counts'][shell_name]:
                        water_counts = solvation_data['shell_water_counts'][shell_name][selected_ion]
                        ax4.plot(z_centers, water_counts, linewidth=2, marker='o', 
                                markersize=4, label=shell_name)
                
                ax4.set_xlabel('z (Å)')
                ax4.set_ylabel('Waters per Shell')
                ax4.set_title(f'Shell-by-Shell Hydration: {selected_ion}', fontweight='bold')
                ax4.legend()
                ax4.grid(True, alpha=0.3)
                ax4.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'solvation_shells_vs_z.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Solvation shell analysis plot saved as: {filename}")
        
        plt.show()
        
        # Print summary
        print(f"\nSolvation Shell Analysis Summary:")
        
        if 'coordination_numbers' in solvation_data:
            for ion_type, coord_nums in solvation_data['coordination_numbers'].items():
                avg_coord = np.mean(coord_nums[coord_nums > 0]) if np.any(coord_nums > 0) else 0
                print(f"  {ion_type}:")
                print(f"    Average coordination number: {avg_coord:.2f}")
        
        if 'shell_water_counts' in solvation_data:
            for shell_name, shell_data in solvation_data['shell_water_counts'].items():
                print(f"\n  {shell_name}:")
                for ion_type, water_counts in shell_data.items():
                    avg_waters = np.mean(water_counts[water_counts > 0]) if np.any(water_counts > 0) else 0
                    print(f"    {ion_type}: {avg_waters:.2f} waters")


    def plot_solvation_shell_comparison(self, ion_type=None, save_plots=True, 
                                    figsize=None, filename=None, symmetrize=False,
                                    symmetrize_method='average',
                                    # Publication settings
                                    dpi=300,
                                    title_fontsize=16,
                                    title_text=None,
                                    show_title=True,
                                    label_fontsize=14,
                                    tick_fontsize=12,
                                    legend_fontsize=12,
                                    show_legend=True,
                                    legend_location='best',
                                    legend_ncol=1,
                                    legend_frameon=False,
                                    legend_framealpha=0.8,
                                    # Publication figure control parameters
                                    save_individual_figures=False,
                                    individual_figsize=(8, 6),
                                    save_combined_figure=False,
                                    show_individual_figures=False,
                                    show_combined_figure=True,
                                    # Color customization for ions and shells
                                    ion_colors=None,
                                    shell_colors=None,
                                    total_color='black',
                                    # Line styling
                                    shell_linewidth=2,
                                    total_linewidth=3,
                                    shell_alpha=0.8,
                                    total_alpha=0.7,
                                    total_linestyle='--',
                                    # Marker styling
                                    show_markers=False,
                                    marker_size=4,
                                    shell_markers=None,
                                    # Fill options
                                    fill_shells=False,
                                    shell_fill_alpha=0.2,
                                    shell_fill_colors=None,
                                    fill_total=False,
                                    total_fill_alpha=0.15,
                                    total_fill_color=None,
                                    # Grid and reference lines
                                    show_grid=True,
                                    grid_alpha=0.3,
                                    grid_linestyle=':',
                                    show_zero_line=True,
                                    zero_line_color='black',
                                    zero_line_style='--',
                                    zero_line_alpha=0.5,
                                    zero_line_width=1.0,
                                    # Axis labels
                                    xlabel_text='z (Å)',
                                    ylabel_text='Water Count',
                                    # Symmetrization display
                                    show_symmetry_mirror=True,
                                    symmetry_mirror_alpha=0.3,
                                    symmetry_mirror_linestyle='--'):
        '''
        Plot detailed comparison of all solvation shells for specific ions
        
        Parameters
        ----------
        ion_type : str, list, or None
            Ion type(s) to plot. If None, plots all available ions
        save_plots : bool, default=True
            Whether to save the combined plot (legacy parameter)
        figsize : tuple, optional
            Figure size for combined plot (width, height) in inches. 
            If None, auto-calculated based on number of ions
        filename : str, optional
            Output filename for combined plot. If None, auto-generated
        symmetrize : bool, default=False
            Whether to symmetrize the solvation shell data around z=0
        symmetrize_method : str, default='average'
            Method for symmetrization: 'average', 'fold', 'mirror_positive', 'mirror_negative'
        
        Publication Settings:
        dpi : int, default=300
            Resolution for saved figures
        title_fontsize : int, default=16
            Font size for subplot titles
        title_text : str or dict, optional
            Custom title text. Can be a string (used for all ions) or dict mapping ion->title
        show_title : bool, default=True
            Whether to show subplot titles
        label_fontsize : int, default=14
            Font size for axis labels
        tick_fontsize : int, default=12
            Font size for axis tick labels
        legend_fontsize : int, default=12
            Font size for legend text
        show_legend : bool, default=True
            Whether to show legend
        legend_location : str, default='best'
            Legend location ('best', 'upper right', 'upper left', etc.)
        legend_ncol : int, default=1
            Number of columns in legend
        legend_frameon : bool, default=False
            Whether to show legend frame
        legend_framealpha : float, default=0.8
            Transparency of legend frame (0-1)
        
        Publication Figure Control:
        save_individual_figures : bool, default=False
            Save separate figure for each ion
        individual_figsize : tuple, default=(8, 6)
            Figure size for individual ion plots
        save_combined_figure : bool, default=False
            Save combined figure with all ions (overrides save_plots)
        show_individual_figures : bool, default=False
            Display individual figures (separate windows)
        show_combined_figure : bool, default=True
            Display combined figure
        
        Color Customization:
        ion_colors : dict, optional
            Dictionary mapping ion types to colors for subplot titles/accents
            Example: {'NA': 'blue', 'MG': 'green', 'CL': 'red'}
        shell_colors : list or dict, optional
            Colors for shell curves. Can be list (used for all ions) or 
            dict mapping shell names to colors
        total_color : str, default='black'
            Color for total coordination line
        
        Line Styling:
        shell_linewidth : float, default=2
            Line width for shell curves
        total_linewidth : float, default=3
            Line width for total coordination curve
        shell_alpha : float, default=0.8
            Transparency for shell lines (0-1)
        total_alpha : float, default=0.7
            Transparency for total line (0-1)
        total_linestyle : str, default='--'
            Line style for total coordination ('-', '--', '-.', ':')
        
        Marker Styling:
        show_markers : bool, default=False
            Whether to show markers on data points
        marker_size : float, default=4
            Size of markers
        shell_markers : list or dict, optional
            Markers for shells. Can be list (cycling) or dict mapping shell names to markers
            Default: ['o', 's', '^', 'd', 'v', '<', '>', 'p', '*', 'h']
        
        Fill Options:
        fill_shells : bool, default=False
            Fill area under shell curves
        shell_fill_alpha : float, default=0.2
            Transparency for shell fills (0-1)
        shell_fill_colors : list or dict, optional
            Fill colors for shells. If None, uses shell line colors
        fill_total : bool, default=False
            Fill area under total coordination curve
        total_fill_alpha : float, default=0.15
            Transparency for total fill (0-1)
        total_fill_color : str, optional
            Fill color for total. If None, uses total_color
        
        Grid and Reference Lines:
        show_grid : bool, default=True
            Show grid lines
        grid_alpha : float, default=0.3
            Transparency of grid lines (0-1)
        grid_linestyle : str, default=':'
            Grid line style
        show_zero_line : bool, default=True
            Show vertical line at z=0
        zero_line_color : str, default='black'
            Color of z=0 line
        zero_line_style : str, default='--'
            Line style for z=0 line
        zero_line_alpha : float, default=0.5
            Transparency of z=0 line (0-1)
        zero_line_width : float, default=1.0
            Width of z=0 line
        
        Axis Labels:
        xlabel_text : str, default='z (Å)'
            X-axis label text
        ylabel_text : str, default='Water Count'
            Y-axis label text
        
        Symmetrization Display:
        show_symmetry_mirror : bool, default=True
            When symmetrized, show mirrored curves on negative side
        symmetry_mirror_alpha : float, default=0.3
            Transparency for mirrored curves (0-1)
        symmetry_mirror_linestyle : str, default='--'
            Line style for mirrored curves
        '''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'solvation_shells_vs_z'):
            print("No solvation shell data available. Run calculate_solvation_shells_vs_z_detailed() first.")
            return
        
        solvation_data = self.analysis.results.solvation_shells_vs_z
        z_centers = solvation_data['z_centers']
        available_shells = list(solvation_data['shell_water_counts'].keys())
        
        # Get available ion types
        first_shell_data = solvation_data['shell_water_counts'][available_shells[0]]
        available_ions = list(first_shell_data.keys())
        
        # Select ion type(s) to plot
        if ion_type is None:
            ions_to_plot = available_ions
        elif isinstance(ion_type, str):
            ions_to_plot = [ion_type] if ion_type in available_ions else []
        else:
            ions_to_plot = [ion for ion in ion_type if ion in available_ions]
        
        if not ions_to_plot:
            print(f"No valid ion types found. Available: {available_ions}")
            return
        
        # Apply symmetrization if requested
        if symmetrize:
            print(f"Applying symmetrization method: {symmetrize_method}")
            z_centers_sym, solvation_data_sym = self._symmetrize_solvation_data(
                z_centers, solvation_data, method=symmetrize_method)
        else:
            z_centers_sym = z_centers
            solvation_data_sym = solvation_data
        
        # Setup default colors for ions if not provided
        default_ion_colors = {
            'NA': '#1f77b4',  # Blue
            'MG': '#ff7f0e',  # Orange
            'CA': '#2ca02c',  # Green
            'K': '#d62728',   # Red
            'LI': '#9467bd',  # Purple
            'RB': '#8c564b',  # Brown
            'SR': '#e377c2',  # Pink
            'CL': '#7f7f7f',  # Gray
            'BR': '#bcbd22',  # Olive
            'F': '#17becf'    # Cyan
        }
        
        if ion_colors is None:
            ion_colors = default_ion_colors
        
        # Setup default shell colors if not provided
        if shell_colors is None:
            shell_colors = self.default_colors if hasattr(self, 'default_colors') else \
                          ['#e74c3c', '#3498db', '#2ecc71', '#f39c12', '#9b59b6', '#1abc9c']
        
        # Setup shell markers if not provided
        if shell_markers is None:
            shell_markers = ['o', 's', '^', 'd', 'v', '<', '>', 'p', '*', 'h']
        
        # Helper function to get color for shell
        def get_shell_color(shell_name, shell_idx):
            if isinstance(shell_colors, dict) and shell_name in shell_colors:
                return shell_colors[shell_name]
            elif isinstance(shell_colors, list):
                return shell_colors[shell_idx % len(shell_colors)]
            else:
                return self.default_colors[shell_idx % len(self.default_colors)]
        
        # Helper function to get marker for shell
        def get_shell_marker(shell_name, shell_idx):
            if isinstance(shell_markers, dict) and shell_name in shell_markers:
                return shell_markers[shell_name]
            elif isinstance(shell_markers, list):
                return shell_markers[shell_idx % len(shell_markers)]
            else:
                return ['o', 's', '^', 'd', 'v'][shell_idx % 5]
        
        # Helper function to get fill color for shell
        def get_shell_fill_color(shell_name, shell_idx, line_color):
            if shell_fill_colors is not None:
                if isinstance(shell_fill_colors, dict) and shell_name in shell_fill_colors:
                    return shell_fill_colors[shell_name]
                elif isinstance(shell_fill_colors, list):
                    return shell_fill_colors[shell_idx % len(shell_fill_colors)]
            return line_color  # Use line color if no fill color specified
        
        # Create combined figure
        n_ions = len(ions_to_plot)
        figsize_combined = figsize or (8 * n_ions, 6)
        fig_combined, axes = plt.subplots(1, n_ions, figsize=figsize_combined)
        
        if n_ions == 1:
            axes = [axes]
        
        # Storage for individual figures
        individual_figures = []
        
        # Plot each ion
        for idx, ion in enumerate(ions_to_plot):
            # Create individual figure if needed
            if save_individual_figures or show_individual_figures:
                fig_individual = plt.figure(figsize=individual_figsize)
                ax_individual = fig_individual.add_subplot(111)
                individual_figures.append((ion, fig_individual, ax_individual))
            else:
                ax_individual = None
            
            # Get axis for combined plot
            ax_combined = axes[idx]
            
            # Plot on both axes (combined and individual if created)
            for ax in [ax_combined, ax_individual]:
                if ax is None:
                    continue
                
                # Plot each shell for this ion
                for shell_idx, shell_name in enumerate(available_shells):
                    if ion in solvation_data_sym['shell_water_counts'][shell_name]:
                        water_counts = solvation_data_sym['shell_water_counts'][shell_name][ion]
                        
                        # Get styling for this shell
                        color = get_shell_color(shell_name, shell_idx)
                        marker = get_shell_marker(shell_name, shell_idx) if show_markers else None
                        
                        # Plot main curve
                        ax.plot(z_centers_sym, water_counts, 
                               color=color, 
                               linewidth=shell_linewidth,
                               marker=marker, 
                               markersize=marker_size if show_markers else 0,
                               alpha=shell_alpha,
                               label=shell_name.replace('_', ' ').title())
                        
                        # Fill under curve if requested
                        if fill_shells:
                            fill_color = get_shell_fill_color(shell_name, shell_idx, color)
                            ax.fill_between(z_centers_sym, 0, water_counts, 
                                          color=fill_color, alpha=shell_fill_alpha)
                        
                        # Plot symmetry mirror if requested
                        if symmetrize and show_symmetry_mirror and symmetrize_method in ['average', 'fold']:
                            ax.plot(-z_centers_sym[::-1], water_counts[::-1], 
                                   color=color, 
                                   linewidth=shell_linewidth,
                                   alpha=symmetry_mirror_alpha,
                                   marker=marker if show_markers else None,
                                   markersize=marker_size if show_markers else 0,
                                   linestyle=symmetry_mirror_linestyle)
                
                # Add total coordination if available
                if 'coordination_numbers' in solvation_data_sym and ion in solvation_data_sym['coordination_numbers']:
                    total_coord = solvation_data_sym['coordination_numbers'][ion]
                    
                    # Plot total line
                    ax.plot(z_centers_sym, total_coord, 
                           color=total_color,
                           linewidth=total_linewidth, 
                           alpha=total_alpha,
                           label='Total', 
                           linestyle=total_linestyle)
                    
                    # Fill under total if requested
                    if fill_total:
                        fill_color_total = total_fill_color if total_fill_color else total_color
                        ax.fill_between(z_centers_sym, 0, total_coord,
                                      color=fill_color_total, alpha=total_fill_alpha)
                    
                    # Plot symmetry mirror for total
                    if symmetrize and show_symmetry_mirror and symmetrize_method in ['average', 'fold']:
                        ax.plot(-z_centers_sym[::-1], total_coord[::-1], 
                               color=total_color,
                               linewidth=total_linewidth, 
                               alpha=symmetry_mirror_alpha,
                               linestyle=symmetry_mirror_linestyle)
                
                # Configure axes
                ax.set_xlabel(xlabel_text, fontsize=label_fontsize)
                ax.set_ylabel(ylabel_text, fontsize=label_fontsize)
                ax.tick_params(labelsize=tick_fontsize)
                
                # Set title
                if show_title:
                    if isinstance(title_text, dict) and ion in title_text:
                        title = title_text[ion]
                    elif isinstance(title_text, str):
                        title = title_text
                    else:
                        title = f'{ion}: Shell-by-Shell Hydration'
                        if symmetrize:
                            title += f' (Symmetrized: {symmetrize_method})'
                    
                    # Use ion color for title if available
                    title_color = ion_colors.get(ion, 'black')
                    ax.set_title(title, fontsize=title_fontsize, fontweight='bold', color=title_color)
                
                # Add legend
                if show_legend:
                    ax.legend(fontsize=legend_fontsize, 
                            loc=legend_location,
                            ncol=legend_ncol,
                            frameon=legend_frameon,
                            framealpha=legend_framealpha)
                
                # Add grid
                if show_grid:
                    ax.grid(True, alpha=grid_alpha, linestyle=grid_linestyle)
                
                # Add zero line
                if show_zero_line:
                    ax.axvline(0, color=zero_line_color, linestyle=zero_line_style, 
                             alpha=zero_line_alpha, linewidth=zero_line_width)
            
            # After finishing plotting on individual figure, save and close immediately if only saving
            if ax_individual is not None and save_individual_figures and not show_individual_figures:
                fig_individual.tight_layout()
                suffix = f'_symmetrized_{symmetrize_method}' if symmetrize else ''
                filename_indiv = f'solvation_shell_comparison_{ion}{suffix}.png'
                fig_individual.savefig(filename_indiv, dpi=dpi, bbox_inches='tight', facecolor='white')
                print(f"✓ Individual plot saved: {filename_indiv}")
                plt.close(fig_individual)
        
        # Apply tight layout to combined figure
        plt.figure(fig_combined.number)
        plt.tight_layout()
        
        # Save and show combined figure
        if save_combined_figure or (save_plots and not save_individual_figures):
            suffix = f'_symmetrized_{symmetrize_method}' if symmetrize else ''
            filename_combined = filename or f'solvation_shell_comparison_{"_".join(ions_to_plot)}{suffix}.png'
            fig_combined.savefig(filename_combined, dpi=dpi, bbox_inches='tight', facecolor='white')
            print(f"✓ Combined plot saved: {filename_combined}")
        
        if show_combined_figure:
            plt.figure(fig_combined.number)
            plt.show()
        else:
            plt.close(fig_combined)
        
        # Handle individual figures - save and/or show those that weren't already processed
        if save_individual_figures or show_individual_figures:
            for ion, fig_indiv, ax_indiv in individual_figures:
                # Skip if figure was already closed (when save_individual_figures=True and show_individual_figures=False)
                if not plt.fignum_exists(fig_indiv.number):
                    continue
                    
                # Apply tight layout if not already done
                fig_indiv.tight_layout()
                
                if save_individual_figures:
                    suffix = f'_symmetrized_{symmetrize_method}' if symmetrize else ''
                    filename_indiv = f'solvation_shell_comparison_{ion}{suffix}.png'
                    fig_indiv.savefig(filename_indiv, dpi=dpi, bbox_inches='tight', facecolor='white')
                    print(f"✓ Individual plot saved: {filename_indiv}")
                
                # Show or close individual figure
                if show_individual_figures:
                    fig_indiv.show()
                else:
                    plt.close(fig_indiv)
        
        # Print shell radii info
        if hasattr(self.analysis, 'shell_radii'):
            print(f"\n{'='*60}")
            print(f"Shell Radii Used: {self.analysis.shell_radii}")
            for i, r in enumerate(self.analysis.shell_radii):
                r_prev = 0 if i == 0 else self.analysis.shell_radii[i-1]
                print(f"  Shell {i+1}: {r_prev:.1f} - {r:.1f} Å")
            print(f"{'='*60}")



    def _symmetrize_solvation_data(self, z_centers, solvation_data, method='average'):
        '''
        Helper function to symmetrize solvation shell data
        
        Parameters
        ----------
        z_centers : np.ndarray
            Z-position centers
        solvation_data : dict
            Original solvation shell data
        method : str
            Symmetrization method
        
        Returns
        -------
        z_centers_sym : np.ndarray
            Symmetrized z-centers (positive side only)
        solvation_data_sym : dict
            Symmetrized solvation data
        '''
        
        # Find center (z=0) index
        center_idx = np.argmin(np.abs(z_centers))
        
        # Split into positive side only (including center)
        positive_mask = z_centers >= 0
        z_positive = z_centers[positive_mask]
        
        # Create symmetrized data dictionary
        solvation_data_sym = {
            'z_centers': z_positive,
            'shell_water_counts': {},
            'coordination_numbers': {}
        }
        
        # Symmetrize shell water counts
        for shell_name, shell_data in solvation_data['shell_water_counts'].items():
            solvation_data_sym['shell_water_counts'][shell_name] = {}
            
            for ion_type, water_counts in shell_data.items():
                # Split into left and right
                left_side = water_counts[~positive_mask]
                right_side = water_counts[positive_mask]
                
                # Apply symmetrization
                if method == 'average':
                    # Average left (flipped) and right
                    left_flipped = np.flip(left_side)
                    min_len = min(len(left_flipped), len(right_side))
                    
                    symmetrized = np.zeros(len(right_side))
                    symmetrized[:min_len] = (left_flipped[:min_len] + right_side[:min_len]) / 2.0
                    
                    # Fill remaining with available data
                    if len(right_side) > min_len:
                        symmetrized[min_len:] = right_side[min_len:]
                
                elif method == 'fold':
                    # Fold left onto right
                    left_flipped = np.flip(left_side)
                    min_len = min(len(left_flipped), len(right_side))
                    
                    symmetrized = np.zeros(len(right_side))
                    symmetrized[:min_len] = left_flipped[:min_len]
                    
                    if len(right_side) > min_len:
                        symmetrized[min_len:] = right_side[min_len:]
                
                elif method == 'mirror_positive':
                    # Use only positive side
                    symmetrized = right_side.copy()
                
                elif method == 'mirror_negative':
                    # Use only negative side (flipped)
                    left_flipped = np.flip(left_side)
                    symmetrized = np.zeros(len(right_side))
                    min_len = min(len(left_flipped), len(right_side))
                    symmetrized[:min_len] = left_flipped[:min_len]
                
                else:
                    raise ValueError(f"Unknown symmetrization method: {method}")
                
                solvation_data_sym['shell_water_counts'][shell_name][ion_type] = symmetrized
        
        # Symmetrize coordination numbers if available
        if 'coordination_numbers' in solvation_data:
            for ion_type, coord_nums in solvation_data['coordination_numbers'].items():
                left_side = coord_nums[~positive_mask]
                right_side = coord_nums[positive_mask]
                
                if method == 'average':
                    left_flipped = np.flip(left_side)
                    min_len = min(len(left_flipped), len(right_side))
                    
                    symmetrized = np.zeros(len(right_side))
                    symmetrized[:min_len] = (left_flipped[:min_len] + right_side[:min_len]) / 2.0
                    
                    if len(right_side) > min_len:
                        symmetrized[min_len:] = right_side[min_len:]
                
                elif method == 'fold':
                    left_flipped = np.flip(left_side)
                    min_len = min(len(left_flipped), len(right_side))
                    
                    symmetrized = np.zeros(len(right_side))
                    symmetrized[:min_len] = left_flipped[:min_len]
                    
                    if len(right_side) > min_len:
                        symmetrized[min_len:] = right_side[min_len:]
                
                elif method == 'mirror_positive':
                    symmetrized = right_side.copy()
                
                elif method == 'mirror_negative':
                    left_flipped = np.flip(left_side)
                    symmetrized = np.zeros(len(right_side))
                    min_len = min(len(left_flipped), len(right_side))
                    symmetrized[:min_len] = left_flipped[:min_len]
                
                solvation_data_sym['coordination_numbers'][ion_type] = symmetrized
        
        return z_positive, solvation_data_sym


    def plot_symmetrized_profiles(self, save_plots=True, figsize=None, filename=None, 
                                show_ion_specific=True):
        '''Plot symmetrized profiles comparison with original - ION SPECIFIC'''
        
        self._validate_analysis()
        
        if not hasattr(self.analysis.results, 'symmetric_profiles'):
            print("No symmetrized profiles available. Run symmetrize_profiles() first.")
            return
        
        sym_data = self.analysis.results.symmetric_profiles
        
        # Plot ion-specific symmetrized densities
        if show_ion_specific and 'ion_densities' in sym_data:
            ion_types = list(sym_data['ion_densities'].keys())
            n_ions = len(ion_types)
            
            n_cols = 2
            n_rows = (n_ions + n_cols - 1) // n_cols
            
            figsize = figsize or (7 * n_cols, 5 * n_rows)
            fig, axes = plt.subplots(n_rows, n_cols, figsize=figsize, squeeze=False)
            
            for idx, ion_type in enumerate(ion_types):
                row = idx // n_cols
                col = idx % n_cols
                ax = axes[row, col]
                
                # Get original ion-specific density
                original_density = self.analysis.results.ion_densities_by_type[ion_type]
                
                # Plot original
                ax.plot(self.analysis.z_centers, original_density, 
                    'b-', alpha=0.5, linewidth=2, label='Original')
                
                # Plot symmetrized
                sym_density = sym_data['ion_densities'][ion_type]
                sym_z = sym_data['z_centers']
                ax.plot(sym_z, sym_density, 'r-', linewidth=2, label='Symmetrized')
                
                # Also plot mirrored symmetrized (for full profile)
                ax.plot(-sym_z[::-1], sym_density[::-1], 'r-', linewidth=2, alpha=0.5)
                
                ax.set_xlabel('z (Å)')
                ax.set_ylabel(f'{ion_type} Density (ions/Å³)')
                ax.set_title(f'{ion_type}: Original vs Symmetrized', fontweight='bold')
                ax.legend()
                ax.grid(True, alpha=0.3)
                ax.axvline(0, color='k', linestyle='--', alpha=0.5)
                
                # Calculate and display noise reduction
                bulk_mask = np.abs(self.analysis.z_centers) > 15.0
                if np.any(bulk_mask):
                    original_noise = np.std(original_density[bulk_mask])
                    
                    sym_bulk_mask = np.abs(sym_z) > 15.0
                    if np.any(sym_bulk_mask) and original_noise > 0:
                        symmetrized_noise = np.std(sym_density[sym_bulk_mask])
                        noise_reduction = (1 - symmetrized_noise / original_noise) * 100
                        
                        # Add text annotation
                        method = sym_data.get('method', 'unknown')
                        ax.text(0.02, 0.98, f'Method: {method}\nNoise ↓: {noise_reduction:.1f}%',
                            transform=ax.transAxes, fontsize=9,
                            verticalalignment='top',
                            bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.5))
            
            # Hide empty subplots
            total_subplots = n_rows * n_cols
            for idx in range(n_ions, total_subplots):
                row = idx // n_cols
                col = idx % n_cols
                axes[row, col].axis('off')
            
            plt.tight_layout()
            
            if save_plots:
                filename = filename or 'symmetrized_profiles_ion_specific.png'
                plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
                print(f"Ion-specific symmetrized profiles plot saved as: {filename}")
            
            plt.show()
        
        else:
            print("No ion-specific symmetrized data available.")
            print(f"Available keys in symmetric_profiles: {list(sym_data.keys())}")


    def plot_symmetrization_comparison(self, methods=None, profile_type='water_density',
                                    save_plots=True, figsize=None, filename=None):
        '''Plot comparison of different symmetrization methods'''
        
        self._validate_analysis()
        
        if methods is None:
            methods = ['average', 'fold', 'mirror_positive', 'mirror_negative']
        
        # Get original profile
        if profile_type == 'water_density':
            original_profile = self.analysis.results.water_density
            ylabel = 'Water Density (molecules/Å³)'
            title = 'Water Density'
        elif profile_type == 'cation_density':
            original_profile = self.analysis.results.cation_density
            ylabel = 'Cation Density (ions/Å³)'
            title = 'Cation Density'
        elif profile_type == 'anion_density':
            original_profile = self.analysis.results.anion_density
            ylabel = 'Anion Density (ions/Å³)'
            title = 'Anion Density'
        else:
            print(f"Unknown profile type: {profile_type}")
            return
        
        figsize = figsize or (15, 10)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        axes = axes.flatten()
        
        # Plot each method
        for idx, method in enumerate(methods):
            if idx >= 4:  # Only 4 subplots
                break
            
            ax = axes[idx]
            
            # Plot original
            ax.plot(self.analysis.z_centers, original_profile, 
                'b-', alpha=0.4, linewidth=2, label='Original')
            
            # Apply symmetrization method
            try:
                sym_results = self.analysis.symmetrize_profiles(method=method)
                
                # FIX: Access directly from sym_results, not under 'profiles' key
                if profile_type in sym_results:
                    sym_profile = sym_results[profile_type]
                    sym_z = sym_results['z_centers']
                    
                    ax.plot(sym_z, sym_profile, 'r-', linewidth=2, 
                        label=f'Symmetrized ({method})')
                    
                    # Calculate asymmetry metric
                    left_side = original_profile[self.analysis.z_centers < 0]
                    right_side = original_profile[self.analysis.z_centers > 0]
                    right_flipped = np.flip(right_side)
                    
                    min_len = min(len(left_side), len(right_flipped))
                    if min_len > 0:
                        left_compare = left_side[-min_len:]
                        right_compare = right_flipped[:min_len]
                        asymmetry = np.mean(np.abs(left_compare - right_compare) / 
                                        (left_compare + right_compare + 1e-10)) * 100
                        
                        ax.text(0.02, 0.98, f'Asymmetry: {asymmetry:.2f}%', 
                            transform=ax.transAxes, fontsize=9,
                            verticalalignment='top',
                            bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.5))
                else:
                    print(f"  Warning: {profile_type} not found in symmetrized results for method '{method}'")
                    print(f"  Available keys: {list(sym_results.keys())}")
            
            except Exception as e:
                print(f"Error with method '{method}': {e}")
                ax.text(0.5, 0.5, f'Method: {method}\nError occurred', 
                    ha='center', va='center', transform=ax.transAxes)
            
            ax.set_xlabel('z (Å)')
            ax.set_ylabel(ylabel)
            ax.set_title(f'{title} - Method: {method}', fontweight='bold')
            ax.legend()
            ax.grid(True, alpha=0.3)
            ax.axvline(0, color='k', linestyle='--', alpha=0.5)
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or f'symmetrization_comparison_{profile_type}.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Symmetrization comparison plot saved as: {filename}")
        
        plt.show()



    def plot_asymmetry_analysis(self, save_plots=True, figsize=None, filename=None):
        '''Plot detailed asymmetry analysis between left and right sides'''
        
        self._validate_analysis()
        
        figsize = figsize or (15, 12)
        fig, axes = plt.subplots(2, 2, figsize=figsize)
        
        profiles_to_analyze = {
            'water_density': ('Water Density', 'molecules/Å³', self.analysis.results.water_density),
            'cation_density': ('Cation Density', 'ions/Å³', self.analysis.results.cation_density),
            'anion_density': ('Anion Density', 'ions/Å³', self.analysis.results.anion_density)
        }
        
        plot_idx = 0
        for profile_name, (title, units, profile) in profiles_to_analyze.items():
            if plot_idx >= 3:
                break
            
            row = plot_idx // 2
            col = plot_idx % 2
            ax = axes[row, col]
            
            # Split into left and right sides
            left_mask = self.analysis.z_centers < 0
            right_mask = self.analysis.z_centers > 0
            
            left_z = self.analysis.z_centers[left_mask]
            left_profile = profile[left_mask]
            
            right_z = self.analysis.z_centers[right_mask]
            right_profile = profile[right_mask]
            
            # Plot both sides
            ax.plot(left_z, left_profile, 'b-', linewidth=2, label='Left side (z < 0)')
            ax.plot(right_z, right_profile, 'r-', linewidth=2, label='Right side (z > 0)')
            
            # Plot flipped right side for comparison
            ax.plot(-right_z[::-1], right_profile[::-1], 'r--', linewidth=1, 
                alpha=0.5, label='Right side (flipped)')
            
            ax.set_xlabel('z (Å)')
            ax.set_ylabel(f'{title} ({units})')
            ax.set_title(f'{title} - Left vs Right', fontweight='bold')
            ax.legend()
            ax.grid(True, alpha=0.3)
            ax.axvline(0, color='k', linestyle='--', alpha=0.5)
            
            # Calculate asymmetry
            right_flipped = np.flip(right_profile)
            min_len = min(len(left_profile), len(right_flipped))
            
            if min_len > 0:
                left_compare = left_profile[-min_len:]
                right_compare = right_flipped[:min_len]
                asymmetry = np.mean(np.abs(left_compare - right_compare) / 
                                (left_compare + right_compare + 1e-10)) * 100
                
                ax.text(0.02, 0.98, f'Mean asymmetry: {asymmetry:.2f}%', 
                    transform=ax.transAxes, fontsize=10,
                    verticalalignment='top',
                    bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.7))
            
            plot_idx += 1
        
        # Fourth plot: Combined asymmetry comparison
        ax = axes[1, 1]
        
        asymmetries = {}
        for profile_name, (title, units, profile) in profiles_to_analyze.items():
            left_side = profile[self.analysis.z_centers < 0]
            right_side = profile[self.analysis.z_centers > 0]
            right_flipped = np.flip(right_side)
            
            min_len = min(len(left_side), len(right_flipped))
            if min_len > 0:
                left_compare = left_side[-min_len:]
                right_compare = right_flipped[:min_len]
                asymmetry = np.mean(np.abs(left_compare - right_compare) / 
                                (left_compare + right_compare + 1e-10)) * 100
                asymmetries[title] = asymmetry
        
        # Bar plot
        names = list(asymmetries.keys())
        values = list(asymmetries.values())
        colors = ['blue', 'red', 'green']
        
        bars = ax.bar(names, values, color=colors, alpha=0.7, edgecolor='black')
        ax.set_ylabel('Mean Asymmetry (%)')
        ax.set_title('Overall Asymmetry Comparison', fontweight='bold')
        ax.grid(True, alpha=0.3, axis='y')
        
        # Add value labels on bars
        for bar, value in zip(bars, values):
            height = bar.get_height()
            ax.text(bar.get_x() + bar.get_width()/2., height,
                f'{value:.2f}%', ha='center', va='bottom', fontweight='bold')
        
        # Add reference lines
        ax.axhline(5, color='orange', linestyle='--', alpha=0.5, label='Good (<5%)')
        ax.axhline(10, color='red', linestyle='--', alpha=0.5, label='Acceptable (<10%)')
        ax.legend()
        
        plt.tight_layout()
        
        if save_plots:
            filename = filename or 'asymmetry_analysis.png'
            plt.savefig(filename, dpi=self.default_dpi, bbox_inches='tight')
            print(f"Asymmetry analysis plot saved as: {filename}")
        
        plt.show()
        
        # Print summary
        print(f"\nAsymmetry Analysis Summary:")
        for name, value in asymmetries.items():
            status = "✓ Good" if value < 5 else ("⚠ Acceptable" if value < 10 else "✗ High")
            print(f"  {name}: {value:.2f}% - {status}")

    def quick_export_manuscript(self, plot_method_name, base_filename=None, **plot_kwargs):
        '''
        Quick export a plot in manuscript formats (Word + Journal)
        
        Parameters
        ----------
        plot_method_name : str
            Name of the plotting method to call (e.g., 'plot_density_profiles')
        base_filename : str, optional
            Base filename. If None, uses method name.
        **plot_kwargs : dict
            Arguments to pass to the plotting method
            
        Examples
        --------
        >>> plotter.quick_export_manuscript('plot_density_profiles', 
        ...                                  ion_types=['NA', 'CL'])
        '''
        
        if not hasattr(self, plot_method_name):
            print(f"Error: Method '{plot_method_name}' not found")
            return
        
        # Get the plotting method
        plot_method = getattr(self, plot_method_name)
        
        # Set save_plots to False to prevent double-saving
        plot_kwargs['save_plots'] = False
        
        # Call the plotting method
        print(f"\nCreating plot: {plot_method_name}...")
        plot_method(**plot_kwargs)
        
        # Export current figure
        filename = base_filename or plot_method_name.replace('plot_', '')
        self.export_current_figure(filename, export_formats=['word', 'journal'])
    
    
    def quick_export_all_formats(self, plot_method_name, base_filename=None, **plot_kwargs):
        '''
        Quick export a plot in all formats
        
        Parameters
        ----------
        plot_method_name : str
            Name of the plotting method to call
        base_filename : str, optional
            Base filename. If None, uses method name.
        **plot_kwargs : dict
            Arguments to pass to the plotting method
        '''
        
        if not hasattr(self, plot_method_name):
            print(f"Error: Method '{plot_method_name}' not found")
            return
        
        plot_method = getattr(self, plot_method_name)
        plot_kwargs['save_plots'] = False
        
        print(f"\nCreating plot: {plot_method_name}...")
        plot_method(**plot_kwargs)
        
        filename = base_filename or plot_method_name.replace('plot_', '')
        self.export_current_figure(filename, 
                                   export_formats=['word', 'presentation', 'journal', 
                                                  'supplementary'])
    
    
    def export_multiple_plots(self, plot_configs, export_formats=None):
        '''
        Export multiple plots in batch
        
        Parameters
        ----------
        plot_configs : list of dict
            List of plot configurations. Each dict should have:
            - 'method': plotting method name
            - 'filename': base filename
            - 'kwargs': dict of plotting arguments (optional)
        export_formats : list, optional
            Formats to export for all plots
            
        Examples
        --------
        >>> configs = [
        ...     {'method': 'plot_density_profiles', 
        ...      'filename': 'figure_1_density',
        ...      'kwargs': {'ion_types': ['NA']}},
        ...     {'method': 'plot_clay_interface_boundaries',
        ...      'filename': 'figure_2_clay'}
        ... ]
        >>> plotter.export_multiple_plots(configs, export_formats=['word', 'journal'])
        '''
        
        export_formats = export_formats or ['word', 'journal']
        
        print(f"\n{'='*70}")
        print(f"BATCH EXPORT: {len(plot_configs)} plots")
        print(f"{'='*70}\n")
        
        for i, config in enumerate(plot_configs, 1):
            method_name = config['method']
            filename = config.get('filename', method_name.replace('plot_', ''))
            kwargs = config.get('kwargs', {})
            
            print(f"\n[{i}/{len(plot_configs)}] Processing: {method_name}")
            print(f"            Filename: {filename}")
            
            if not hasattr(self, method_name):
                print(f"   ✗ Error: Method '{method_name}' not found. Skipping...")
                continue
            
            try:
                # Get method and call it
                plot_method = getattr(self, method_name)
                kwargs['save_plots'] = False
                
                plot_method(**kwargs)
                
                # Export
                self.export_current_figure(filename, export_formats=export_formats)
                
                # Close figure to free memory
                plt.close()
                
            except Exception as e:
                print(f"   ✗ Error processing {method_name}: {e}")
                plt.close()
        
        print(f"\n{'='*70}")
        print(f"BATCH EXPORT COMPLETE")
        print(f"{'='*70}\n")



